module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 저작권 보호기간 만료 공공저작물."},"kids":{"label":"쉬운말","note":"쉬운말 — 어린이용 의역"},"greek":{"label":"헬라어","note":"SBLGNT (SBL Greek New Testament), © Society of Biblical Literature, CC BY 4.0. 사용 범위: 마태복음 1~5장 (점진적 확장 예정). 각 절 아래 단어 풀이(greekWords)는 본 앱이 직접 작성한 학습용 의역이며, 발음·격·뜻이 불확실한 부분은 단어 뒤 `(?)` 로 표시한다."}},"chapters":[{"chapter":1,"title":"예수님의 족보와 탄생","verses":{"krv":[{"n":1,"t":"아브라함과 다윗의 자손 예수 그리스도의 세계라"},{"n":2,"t":"아브라함이 이삭을 낳고 이삭은 야곱을 낳고 야곱은 유다와 그의 형제를 낳고"},{"n":3,"t":"유다는 다말에게서 베레스와 세라를 낳고 베레스는 헤스론을 낳고 헤스론은 람을 낳고"},{"n":4,"t":"람은 아미나답을 낳고 아미나답은 나손을 낳고 나손은 살몬을 낳고"},{"n":5,"t":"살몬은 라합에게서 보아스를 낳고 보아스는 룻에게서 오벳을 낳고 오벳은 이새를 낳고"},{"n":6,"t":"이새는 다윗왕을 낳으니라 다윗은 우리야의 아내에게서 솔로몬을 낳고"},{"n":7,"t":"솔로몬은 르호보암을 낳고 르호보암은 아비야를 낳고 아비야는 아사를 낳고"},{"n":8,"t":"아사는 여호사밧을 낳고 여호사밧은 요람을 낳고 요람은 웃시야를 낳고"},{"n":9,"t":"웃시야는 요담을 낳고 요담은 아하스를 낳고 아하스는 히스기야를 낳고"},{"n":10,"t":"히스기야는 므낫세를 낳고 므낫세는 아몬을 낳고 아몬은 요시야를 낳고"},{"n":11,"t":"바벨론으로 이거할 때에 요시야는 여고냐와 그의 형제를 낳으니라"},{"n":12,"t":"바벨론으로 이거한 후에 여고냐는 스알디엘을 낳고 스알디엘은 스룹바벨을 낳고"},{"n":13,"t":"스룹바벨은 아비훗을 낳고 아비훗은 엘리아김을 낳고 엘리아김은 아소르를 낳고"},{"n":14,"t":"아소르는 사독을 낳고 사독은 아킴를 낳고 아킴은 엘리웃을 낳고"},{"n":15,"t":"엘리웃은 엘르아살을 낳고 엘르아살은 맛단을 낳고 맛단은 야곱을 낳고"},{"n":16,"t":"야곱은 마리아의 남편 요셉을 낳았으니 마리아에게서 그리스도라 칭하는 예수가 나시니라"},{"n":17,"t":"그런즉 모든 대 수가 아브라함부터 다윗까지 열 네 대요 다윗 부터 바벨론으로 이거할 때까지 열 네 대요 바벨론으로 이거 한후부터 그리스도까지 열 네 대러라"},{"n":18,"t":"예수 그리스도의 나심은 이러하니라 그 모친 마리아가 요셉과 정혼하고 동거하기 전에 성령으로 잉태된 것이 나타났더니"},{"n":19,"t":"그 남편 요셉은 의로운 사람이라 저를 드러내지 아니하고 가만히 끊고자하여"},{"n":20,"t":"이 일을 생각할 때에 주의 사자가 현몽하여 가로되 다윗의 자손 요셉아 네 아내 마리아 데려오기를 무서워 말라 저에게 잉태된 자는 성령으로 된 것이라"},{"n":21,"t":"아들을 낳으리니 이름을 예수라 하라 이는 그가 자기 백성을 저희 죄에서 구원할 자이심이라 하니라"},{"n":22,"t":"이 모든 일의 된 것은 주께서 선지자로 하신 말씀을 이루려 하심이니 가라사대"},{"n":23,"t":"보라 처녀가 잉태하여 아들을 낳을 것이요 그 이름은 임마누엘이라 하리라 하셨으니 이를 번역한즉 하나님이 우리와 함께 계시다 함이라"},{"n":24,"t":"요셉이 잠을 깨어 일어나서 주의 사자의 분부대로 행하여 그 아내를 데려 왔으나"},{"n":25,"t":"아들을 낳기까지 동침치 아니하더니 낳으매 이름을 예수라 하니라"}],"kids":[{"n":1,"t":"이 글은 아브라함의 자손이고 다윗의 자손이신 예수 그리스도의 족보예요."},{"n":2,"t":"아브라함이 이삭을 낳고, 이삭이 야곱을 낳고, 야곱이 유다와 그의 형제들을 낳았어요."},{"n":3,"t":"유다는 다말에게서 베레스와 세라를 낳고, 베레스가 헤스론을, 헤스론이 람을 낳았어요."},{"n":4,"t":"람이 아미나답을, 아미나답이 나손을, 나손이 살몬을 낳았어요."},{"n":5,"t":"살몬은 라합에게서 보아스를, 보아스는 룻에게서 오벳을, 오벳은 이새를 낳았어요."},{"n":6,"t":"이새는 다윗 왕을 낳았어요. 다윗은 우리야의 아내였던 여인에게서 솔로몬을 낳았어요."},{"n":7,"t":"솔로몬이 르호보암을, 르호보암이 아비야를, 아비야가 아사를 낳았어요."},{"n":8,"t":"아사가 여호사밧을, 여호사밧이 요람을, 요람이 웃시야를 낳았어요."},{"n":9,"t":"웃시야가 요담을, 요담이 아하스를, 아하스가 히스기야를 낳았어요."},{"n":10,"t":"히스기야가 므낫세를, 므낫세가 아몬을, 아몬이 요시야를 낳았어요."},{"n":11,"t":"요시야는 바벨론으로 잡혀가던 때에 여고냐와 그의 형제들을 낳았어요."},{"n":12,"t":"바벨론으로 끌려간 뒤 여고냐는 스알디엘을, 스알디엘은 스룹바벨을 낳았어요."},{"n":13,"t":"스룹바벨이 아비훗을, 아비훗이 엘리아김을, 엘리아김이 아소르를 낳았어요."},{"n":14,"t":"아소르가 사독을, 사독이 아킴을, 아킴이 엘리웃을 낳았어요."},{"n":15,"t":"엘리웃이 엘르아살을, 엘르아살이 맛단을, 맛단이 야곱을 낳았어요."},{"n":16,"t":"야곱은 마리아의 남편 요셉을 낳았고, 그 마리아에게서 그리스도라 불리는 예수님이 태어나셨어요."},{"n":17,"t":"그래서 아브라함부터 다윗까지가 열네 대, 다윗부터 바벨론에 끌려갈 때까지가 열네 대, 바벨론에 끌려간 뒤부터 그리스도까지가 열네 대예요."},{"n":18,"t":"예수 그리스도께서 태어나신 이야기예요. 어머니 마리아는 요셉과 약혼한 사이였는데, 함께 살기 전에 성령으로 아기를 가진 것이 드러났어요."},{"n":19,"t":"마리아의 남편 요셉은 의로운 사람이라 마리아를 부끄럽게 하고 싶지 않아서, 조용히 파혼하려고 마음먹었어요."},{"n":20,"t":"그런데 요셉이 그 일을 깊이 생각하고 있을 때, 주의 천사가 꿈에 나타나 말했어요. \\"다윗의 자손 요셉아, 마리아를 아내로 맞이하는 것을 두려워하지 마라. 그 아기는 성령으로 잉태되었단다.\\""},{"n":21,"t":"\\"마리아가 아들을 낳을 거야. 그 이름을 예수라고 지어라. 예수님이 자기 백성을 죄에서 구원하실 것이기 때문이야.\\""},{"n":22,"t":"이 모든 일은 주께서 예언자를 통해 하신 말씀이 이루어지려고 일어난 거예요."},{"n":23,"t":"\\"보아라, 처녀가 잉태하여 아들을 낳을 것이며, 그 이름을 임마누엘이라 부를 거야.\\" 임마누엘은 \'하나님이 우리와 함께 계시다\'라는 뜻이에요."},{"n":24,"t":"잠에서 깬 요셉은 주의 천사가 시킨 대로 마리아를 아내로 맞이했어요."},{"n":25,"t":"그러나 마리아가 아들을 낳을 때까지 부부 관계를 갖지 않았고, 그 아기의 이름을 예수라고 지었어요."}]}},{"chapter":2,"title":"동방박사와 애굽으로 피난","verses":{"krv":[{"n":1,"t":"헤롯왕 때에 예수께서 유대 베들레헴에서 나시매 동방으로부터 박사들이 예루살렘에 이르러 말하되"},{"n":2,"t":"유대인의 왕으로 나신 이가 어디 계시뇨 우리가 동방에서 그의 별을 보고 그에게 경배하러 왔노라 하니"},{"n":3,"t":"헤롯왕과 온 예루살렘이 듣고 소동한지라"},{"n":4,"t":"왕이 모든 대제사장과 백성의 서기관들을 모아 그리스도가 어디서 나겠느뇨 물으니"},{"n":5,"t":"가로되 유대 베들레헴이오니 이는 선지자로 이렇게 기록된바"},{"n":6,"t":"또 유대 땅 베들레헴아 너는 유대 고을 중에 가장 작지 아니하도다 네게서 한 다스리는 자가 나와서 내 백성 이스라엘의 목자가 되리라 하였음이니이다"},{"n":7,"t":"이에 헤롯이 가만히 박사들을 불러 별이 나타난 때를 자세히 묻고"},{"n":8,"t":"베들레헴으로 보내며 이르되 가서 아기에 대하여 자세히 알아보고 찾거든 내게 고하여 나도 가서 그에게 경배하게 하라"},{"n":9,"t":"박사들이 왕의 말을 듣고 갈쌔 동방에서 보던 그 별이 문득 앞서 인도하여 가다가 아기 있는 곳 위에 머물러 섰는지라"},{"n":10,"t":"저희가 별을 보고 가장 크게 기뻐하고 기뻐하더라"},{"n":11,"t":"집에 들어가 아기와 그 모친 마리아의 함께 있는 것을 보고 엎드려 아기께 경배하고 보배합을 열어 황금과 유향과 몰약을 예물로 드리니라"},{"n":12,"t":"꿈에 헤롯에게로 돌아가지 말라 지시하심을 받아 다른 길로 고국에 돌아가니라"},{"n":13,"t":"저희가 떠난 후에 주의 사자가 요셉에게 현몽하여 가로되 헤롯이 아기를 찾아 죽이려하니 일어나 아기와 그의 모친을 데리고 애굽으로 피하여 내가 네게 이르기까지 거기 있으라 하시니"},{"n":14,"t":"요셉이 일어나서 밤에 아기와 그의 모친을 데리고 애굽으로 떠나가"},{"n":15,"t":"헤롯이 죽기까지 거기 있었으니 이는 주께서 선지자로 말씀하신바 애굽에서 내 아들을 불렀다 함을 이루려 하심이니라"},{"n":16,"t":"이에 헤롯이 박사들에게 속은 줄을 알고 심히 노하여 사람을 보내어 베들레헴과 그 모든 지경 안에 있는 사내아이를 박사들에게 자세히 알아 본 그 때를 표준하여 두 살부터 그 아래로 다 죽이니"},{"n":17,"t":"이에 선지자 예레미야로 말씀하신바"},{"n":18,"t":"라마에서 슬퍼하며 크게 통곡하는 소리가 들리니 라헬이 그 자식을 위하여 애곡하는 것이라 그가 자식이 없으므로 위로 받기를 거절하였도다 함이 이루어졌느니라"},{"n":19,"t":"헤롯이 죽은 후에 주의 사자가 애굽에서 요셉에게 현몽하여 가로되"},{"n":20,"t":"일어나 아기와 그 모친을 데리고 이스라엘 땅으로 가라 아기의 목숨을 찾던 자들이 죽었느니라 하시니"},{"n":21,"t":"요셉이 일어나 아기와 그 모친을 데리고 이스라엘 땅으로 들어오니라"},{"n":22,"t":"그러나 아켈라오가 그 부친 헤롯을 이어 유대의 임금 됨을 듣고 거기로 가기를 무서워하더니 꿈에 지시하심을 받아 갈릴리 지방으로 떠나가"},{"n":23,"t":"나사렛이란 동리에 와서 사니 이는 선지자로 하신 말씀에 나사렛 사람이라 칭하리라 하심을 이루려 함이러라"}],"kids":[{"n":1,"t":"헤롯 왕 때 예수님이 유대 베들레헴에서 태어나셨어요. 그때 동방에서 박사들이 예루살렘에 찾아왔어요."},{"n":2,"t":"\\"유대인의 왕으로 태어나신 분이 어디 계시지요? 우리는 동방에서 그분의 별을 보고 그분께 경배하러 왔어요.\\""},{"n":3,"t":"이 말을 들은 헤롯 왕은 깜짝 놀라고 예루살렘 사람들도 함께 술렁였어요."},{"n":4,"t":"헤롯은 모든 대제사장과 율법 학자들을 모아 그리스도가 어디에서 태어나야 하는지 물었어요."},{"n":5,"t":"그들이 대답했어요. \\"유대 베들레헴이에요. 예언자가 이렇게 적었거든요.\\""},{"n":6,"t":"\\"유대 땅 베들레헴아, 너는 유대 땅의 통치자들 가운데 결코 가장 작지 않다. 너에게서 한 다스리는 자가 나와 내 백성 이스라엘의 목자가 될 것이다.\\""},{"n":7,"t":"그러자 헤롯은 박사들을 몰래 불러 별이 언제 나타났는지 자세히 물었어요."},{"n":8,"t":"그리고 그들을 베들레헴으로 보내며 말했어요. \\"가서 아기를 잘 찾아보고, 만나거든 나에게도 알려 주세요. 나도 가서 경배할게요.\\""},{"n":9,"t":"박사들은 왕의 말을 듣고 길을 떠났어요. 그러자 동방에서 본 그 별이 다시 나타나 아기 계신 곳 위에 멈춰 섰어요."},{"n":10,"t":"별을 본 박사들은 너무나 기뻐서 어쩔 줄을 몰랐어요."},{"n":11,"t":"집에 들어가 보니 아기와 어머니 마리아가 있었어요. 박사들은 엎드려 아기께 경배하고, 상자를 열어 황금과 유향과 몰약을 선물로 드렸어요."},{"n":12,"t":"그리고 꿈에 \'헤롯에게 돌아가지 말라\'는 말씀을 들었기 때문에, 다른 길로 자기 나라로 돌아갔어요."},{"n":13,"t":"박사들이 떠난 뒤, 주의 천사가 요셉의 꿈에 나타나 말했어요. \\"일어나 아기와 그 어머니를 데리고 애굽으로 피해라. 헤롯이 아기를 죽이려고 찾고 있다. 내가 다시 말할 때까지 거기 있어라.\\""},{"n":14,"t":"요셉은 그날 밤에 일어나 아기와 어머니를 데리고 애굽으로 떠났어요."},{"n":15,"t":"그리고 헤롯이 죽을 때까지 거기에 있었어요. 이는 주께서 예언자를 통해 \\"애굽에서 내 아들을 불러냈다\\"라고 하신 말씀이 이루어진 거예요."},{"n":16,"t":"헤롯은 박사들에게 속은 것을 알고 몹시 화가 나서, 베들레헴과 그 근처의 두 살 아래 사내아이들을 다 죽이라고 명령했어요. 박사들에게서 들은 시간을 따져서요."},{"n":17,"t":"이렇게 해서 예레미야 예언자의 말이 이루어졌어요."},{"n":18,"t":"\\"라마에서 슬픈 울음소리가 들렸다. 라헬이 자기 자식을 위해 울며 위로를 받지 못했으니, 자식들이 없기 때문이다.\\""},{"n":19,"t":"헤롯이 죽은 뒤에, 주의 천사가 애굽에 있는 요셉의 꿈에 나타나 말했어요."},{"n":20,"t":"\\"일어나 아기와 어머니를 데리고 이스라엘 땅으로 가거라. 아기의 목숨을 노리던 사람들이 다 죽었단다.\\""},{"n":21,"t":"요셉은 일어나 아기와 어머니를 데리고 이스라엘 땅으로 돌아왔어요."},{"n":22,"t":"하지만 아켈라오가 아버지 헤롯을 이어 유대 왕이 된 것을 듣고 그곳으로 가기를 두려워했어요. 그래서 꿈에 받은 말씀대로 갈릴리 지역으로 갔어요."},{"n":23,"t":"그리고 나사렛이라는 동네에 가서 살았어요. 이는 예언자들이 \\"그가 나사렛 사람이라 불릴 거야\\"라고 한 말이 이루어진 거예요."}]}},{"chapter":3,"title":"세례 요한과 예수님의 세례","verses":{"krv":[{"n":1,"t":"그 때에 세례 요한이 이르러 유대 광야에서 전파하여 가로되"},{"n":2,"t":"회개하라 천국이 가까왔느니라 하였으니"},{"n":3,"t":"저는 선지자 이사야로 말씀하신 자라 일렀으되 광야에 외치는 자의 소리가 있어 가로되 너희는 주의 길을 예비하라 그의 첩경을 평탄케 하라 하였느니라"},{"n":4,"t":"이 요한은 약대 털옷을 입고 허리에 가죽띠를 띠고 음식은 메뚜기와 석청이었더라"},{"n":5,"t":"이 때에 예루살렘과 온 유대와 요단강 사방에서 다 그에게 나아와"},{"n":6,"t":"자기들의 죄를 자복하고 요단강에서 그에게 세례를 받더니"},{"n":7,"t":"요한이 많은 바리새인과 사두개인이 세례 베푸는데 오는 것을 보고 이르되 독사의 자식들아 누가 너희를 가르쳐 임박한 진노를 피하라 하더냐"},{"n":8,"t":"그러므로 회개에 합당한 열매를 맺고"},{"n":9,"t":"속으로 아브라함이 우리 조상이라고 생각지 말라 내가 너희에게 이르노니 하나님이 능히 이 돌들로도 아브라함의 자손이 되게 하시리라"},{"n":10,"t":"이미 도끼가 나무 뿌리에 놓였으니 좋은 열매 맺지 아니하는 나무마다 찍혀 불에 던지우리라"},{"n":11,"t":"나는 너희로 회개케 하기 위하여 물로 세례를 주거니와 내 뒤에 오시는 이는 나보다 능력이 많으시니 나는 그의 신을 들기도 감당치 못하겠노라 그는 성령과 불로 너희에게 세례를 주실 것이요"},{"n":12,"t":"손에 키를 들고 자기의 타작 마당을 정하게 하사 알곡은 모아 곡간에 들이고 쭉정이는 꺼지지 않는 불에 태우시리라"},{"n":13,"t":"이 때에 예수께서 갈릴리로서 요단강에 이르러 요한에게 세례를 받으려 하신대"},{"n":14,"t":"요한이 말려 가로되 내가 당신에게 세례를 받아야 할 터인데 당신이 내게로 오시나이까"},{"n":15,"t":"예수께서 대답하여 가라사대 이제 허락하라 우리가 이와 같이 하여 모든 의를 이루는 것이 합당하니라 하신대 이에 요한이 허락하는지라"},{"n":16,"t":"예수께서 세례를 받으시고 곧 물에서 올라오실새 하늘이 열리고 하나님의 성령이 비둘기 같이 내려 자기 위에 임하심을 보시더니"},{"n":17,"t":"하늘로서 소리가 있어 말씀하시되 이는 내 사랑하는 아들이요 내 기뻐하는 자라 하시니라"}],"kids":[{"n":1,"t":"그 무렵 세례 요한이 유대 광야에 나타나서 외쳤어요."},{"n":2,"t":"\\"회개해요! 천국이 가까이 왔어요.\\""},{"n":3,"t":"이 사람은 예언자 이사야가 말한 그 사람이에요. \\"광야에서 외치는 자의 소리가 있어 \'주의 길을 예비하라, 그 길을 곧게 하라\' 하더라.\\""},{"n":4,"t":"요한은 낙타털로 만든 옷을 입고 허리에 가죽 띠를 두르고, 메뚜기와 들꿀을 먹으며 살았어요."},{"n":5,"t":"그때 예루살렘과 유대 전 지역, 요단강 둘레의 모든 사람들이 그에게로 나아왔어요."},{"n":6,"t":"사람들은 자기 죄를 고백하고 요단강에서 그에게 세례를 받았어요."},{"n":7,"t":"요한은 바리새인과 사두개인들이 자기에게 세례 받으러 오는 것을 보고 말했어요. \\"독사의 자식들아, 누가 너희에게 다가올 진노를 피하라고 알려 주었느냐?\\""},{"n":8,"t":"\\"그러니 회개한 사람답게 행동으로 열매를 맺어라.\\""},{"n":9,"t":"\\"속으로 \'우리에게는 조상 아브라함이 있다\'고 자랑하지 마라. 내가 너희에게 말한다. 하나님은 이 돌들로도 아브라함의 자손을 만드실 수 있어.\\""},{"n":10,"t":"\\"이미 도끼가 나무뿌리에 놓여 있어. 좋은 열매를 맺지 못하는 나무는 다 찍혀 불에 던져질 거야.\\""},{"n":11,"t":"\\"나는 회개의 표시로 너희에게 물로 세례를 줄 뿐이야. 하지만 내 뒤에 오시는 분은 나보다 능력이 크셔서, 나는 그분의 신발을 들고 다닐 자격도 없어. 그분은 너희에게 성령과 불로 세례를 주실 거야.\\""},{"n":12,"t":"\\"그분의 손에는 곡식을 까부르는 도구가 들려 있고, 곡식 떠는 마당을 깨끗이 하셔서 좋은 알맹이는 창고에 모으시지만 빈 껍질은 꺼지지 않는 불에 태우실 거야.\\""},{"n":13,"t":"그때 예수님이 세례를 받으시려고 갈릴리에서 요단강에 있는 요한에게 오셨어요."},{"n":14,"t":"요한은 예수님을 말리며 말했어요. \\"제가 오히려 주님께 세례를 받아야 하는데, 주님이 저에게 오시다니요?\\""},{"n":15,"t":"예수님이 대답하셨어요. \\"지금은 그렇게 하게 해 주세요. 우리가 이렇게 해서 모든 의를 이루는 것이 옳습니다.\\" 그러자 요한이 허락했어요."},{"n":16,"t":"예수님은 세례를 받으시고 곧바로 물에서 올라오셨어요. 그때 하늘이 열리고 하나님의 영이 비둘기처럼 내려와 예수님 위에 머무셨어요."},{"n":17,"t":"그리고 하늘에서 소리가 들렸어요. \\"이는 내 사랑하는 아들이다. 내가 그를 매우 기뻐한다.\\""}]}},{"chapter":4,"title":"광야의 시험과 첫 제자들","verses":{"krv":[{"n":1,"t":"그 때에 예수께서 성령에게 이끌리어 마귀에게 시험을 받으러 광야로 가사"},{"n":2,"t":"사십 일을 밤낮으로 금식하신 후에 주리신지라"},{"n":3,"t":"시험하는 자가 예수께 나아와서 가로되 네가 만일 하나님의 아들이어든 명하여 이 돌들이 떡덩이가 되게 하라"},{"n":4,"t":"예수께서 대답하여 가라사대 기록되었으되 사람이 떡으로만 살것이 아니요 하나님의 입으로 나오는 모든 말씀으로 살 것이라 하였느니라 하시니"},{"n":5,"t":"이에 마귀가 예수를 거룩한 성으로 데려다가 성전 꼭대기에 세우고"},{"n":6,"t":"가로되 네가 만일 하나님의 아들이어든 뛰어내리라 기록하였으되 저가 너를 위하여 그 사자들을 명하시리니 저희가 손으로 너를 받들어 발이 돌에 부딪히지 않게 하리로다 하였느니라"},{"n":7,"t":"예수께서 이르시되 또 기록되었으되 주 너의 하나님을 시험치 말라 하였느니라 하신대"},{"n":8,"t":"마귀가 또 그를 데리고 지극히 높은 산으로 가서 천하 만국과 그 영광을 보여"},{"n":9,"t":"가로되 만일 내게 엎드려 경배하면 이 모든 것을 네게 주리라"},{"n":10,"t":"이에 예수께서 말씀하시되 사단아 물러가라 기록되었으되 주 너의 하나님께 경배하고 다만 그를 섬기라 하였느니라"},{"n":11,"t":"이에 마귀는 예수를 떠나고 천사들이 나아와서 수종드니라"},{"n":12,"t":"예수께서 요한의 잡힘을 들으시고 갈릴리로 물러 가셨다가"},{"n":13,"t":"나사렛을 떠나 스불론과 납달리 지경 해변에 있는 가버나움에 가서 사시니"},{"n":14,"t":"이는 선지자 이사야로 하신 말씀을 이루려 하심이라 일렀으되"},{"n":15,"t":"스불론 땅과 납달리 땅과 요단강 저편 해변 길과 이방의 갈릴리여"},{"n":16,"t":"흑암에 앉은 백성이 큰 빛을 보았고 사망의 땅과 그늘에 앉은 자들에게 빛이 비취었도다 하였느니라"},{"n":17,"t":"이 때부터 예수께서 비로소 전파하여 가라사대 회개하라 천국이 가까왔느니라 하시더라"},{"n":18,"t":"갈릴리 해변에 다니시다가 두 형제 곧 베드로라 하는 시몬과 그 형제 안드레가 바다에 그물 던지는 것을 보시니 저희는 어부 라"},{"n":19,"t":"말씀하시되 나를 따라 오너라 내가 너희로 사람을 낚는 어부가 되게 하리라 하시니"},{"n":20,"t":"저희가 곧 그물을 버려 두고 예수를 좇으니라"},{"n":21,"t":"거기서 더 가시다가 다른 두 형제 곧 세베대의 아들 야고보와 그 형제 요한이 그 부친 세베대와 한가지로 배에서 그물 깁는 것을 보시고 부르시니"},{"n":22,"t":"저희가 곧 배와 부친을 버려두고 예수를 좇으니라"},{"n":23,"t":"예수께서 온 갈릴리에 두루 다니사 저희 회당에서 가르치시며 천국 복음을 전파하시며 백성 중에 모든 병과 모든 약한 것을 고치시니"},{"n":24,"t":"그의 소문이 온 수리아에 퍼진지라 사람들이 모든 앓는 자 곧 각색병과 고통에 걸린 자 귀신 들린 자 간질하는 자 중풍병자들을 데려오니 저희를 고치시더라"},{"n":25,"t":"갈릴리와 데가볼리와 예루살렘과 유대와 요단강 건너편에서 허다한 무리가 좇으니라"}],"kids":[{"n":1,"t":"그 후 예수님은 성령에 이끌려 광야로 가셨어요. 마귀에게 시험받으시려고요."},{"n":2,"t":"예수님은 사십 일 동안 밤낮 금식하셨고, 그 후에 몹시 배가 고프셨어요."},{"n":3,"t":"시험하는 자가 예수님께 와서 말했어요. \\"네가 정말 하나님의 아들이거든, 이 돌들에게 명령해서 빵이 되게 해 봐.\\""},{"n":4,"t":"예수님이 대답하셨어요. \\"성경에 기록되어 있다. \'사람은 빵으로만 사는 게 아니라 하나님의 입에서 나오는 모든 말씀으로 산다.\'\\""},{"n":5,"t":"그러자 마귀가 예수님을 거룩한 성으로 데리고 가서 성전 꼭대기에 세웠어요."},{"n":6,"t":"\\"네가 정말 하나님의 아들이거든, 여기서 뛰어내려 봐. 성경에 \'하나님이 너를 위해 천사들에게 명령하실 것이고, 그들이 손으로 너를 받아 발이 돌에 부딪히지 않게 할 것이다\'라고 적혀 있잖아.\\""},{"n":7,"t":"예수님이 말씀하셨어요. \\"성경에 \'주 너의 하나님을 시험하지 말라\'고 또한 기록되어 있다.\\""},{"n":8,"t":"또 마귀가 예수님을 아주 높은 산으로 데리고 가서 세상의 모든 나라와 그 영광을 보여 주었어요."},{"n":9,"t":"\\"네가 엎드려 내게 절하면 이 모든 것을 너에게 줄게.\\""},{"n":10,"t":"예수님이 말씀하셨어요. \\"사탄아, 물러가라! 성경에 \'주 너의 하나님께 경배하고 오직 그분만을 섬기라\'고 기록되어 있다.\\""},{"n":11,"t":"그러자 마귀는 떠나갔고, 천사들이 와서 예수님을 도왔어요."},{"n":12,"t":"예수님은 요한이 잡혔다는 소식을 들으시고 갈릴리로 가셨어요."},{"n":13,"t":"나사렛을 떠나 스불론과 납달리 지역에 있는 바닷가 마을 가버나움에 가서 사셨어요."},{"n":14,"t":"이는 예언자 이사야의 말이 이루어진 거예요."},{"n":15,"t":"\\"스불론 땅과 납달리 땅, 요단강 건너편 바닷길, 이방인의 갈릴리여.\\""},{"n":16,"t":"\\"어둠 속에 앉아 있던 백성이 큰 빛을 보았고, 죽음의 그늘진 땅에 앉아 있던 사람들 위에 빛이 비쳤다.\\""},{"n":17,"t":"그때부터 예수님은 \\"회개해요! 천국이 가까이 왔어요\\" 하고 가르치기 시작하셨어요."},{"n":18,"t":"예수님이 갈릴리 호숫가를 걸으시다가 두 형제를 보셨어요. 베드로라는 시몬과 그의 동생 안드레였어요. 그들은 어부였는데 그물을 던지고 있었어요."},{"n":19,"t":"예수님이 말씀하셨어요. \\"나를 따라오너라. 너희를 사람을 낚는 어부가 되게 해 줄게.\\""},{"n":20,"t":"두 사람은 곧 그물을 버리고 예수님을 따랐어요."},{"n":21,"t":"조금 더 가시다가 또 다른 두 형제, 세베대의 아들 야고보와 그의 동생 요한을 보셨어요. 그들은 아버지와 함께 배에서 그물을 손질하고 있었어요. 예수님이 그들도 부르셨어요."},{"n":22,"t":"두 사람도 곧 배와 아버지를 두고 예수님을 따랐어요."},{"n":23,"t":"예수님은 갈릴리 곳곳을 다니시며 회당에서 가르치시고, 천국 복음을 전하시며, 사람들의 모든 병과 약함을 고쳐 주셨어요."},{"n":24,"t":"예수님의 소문이 시리아 전 지역에 퍼져 나갔어요. 사람들이 온갖 병에 걸리고 고통받는 사람들, 귀신 들린 사람들, 간질을 앓는 사람들, 중풍에 걸린 사람들을 데리고 왔는데 예수님이 다 고쳐 주셨어요."},{"n":25,"t":"갈릴리와 데가볼리, 예루살렘과 유대, 요단강 건너편에서 큰 무리가 예수님을 따라다녔어요."}]}},{"chapter":5,"title":"산상수훈: 팔복과 율법의 완성","verses":{"krv":[{"n":1,"t":"예수께서 무리를 보시고 산에 올라가 앉으시니 제자들이 나아온지라"},{"n":2,"t":"입을 열어 가르쳐 가라사대"},{"n":3,"t":"심령이 가난한 자는 복이 있나니 천국이 저희 것임이요"},{"n":4,"t":"애통하는 자는 복이 있나니 저희가 위로를 받을 것임이요"},{"n":5,"t":"온유한 자는 복이 있나니 저희가 땅을 기업으로 받을 것임이요"},{"n":6,"t":"의에 주리고 목마른 자는 복이 있나니 저희가 배부를 것임이요"},{"n":7,"t":"긍휼히 여기는 자는 복이 있나니 저희가 긍휼히 여김을 받을 것임이요"},{"n":8,"t":"마음이 청결한 자는 복이 있나니 저희가 하나님을 볼 것임이요"},{"n":9,"t":"화평케 하는 자는 복이 있나니 저희가 하나님의 아들이라 일컬음을 받을 것임이요"},{"n":10,"t":"의를 위하여 핍박을 받은 자는 복이 있나니 천국이 저희 것임이라"},{"n":11,"t":"나를 인하여 너희를 욕하고 핍박하고 거짓으로 너희를 거스려 모든 악한 말을 할 때에는 너희에게 복이 있나니"},{"n":12,"t":"기뻐하고 즐거워하라 하늘에서 너희의 상이 큼이라 너희 전에 있던 선지자들을 이같이 핍박하였느니라"},{"n":13,"t":"너희는 세상의 소금이니 소금이 만일 그 맛을 잃으면 무엇으로 짜게 하리요 후에는 아무 쓸데 없어 다만 밖에 버리워 사람에게 밟힐 뿐이니라"},{"n":14,"t":"너희는 세상의 빛이라 산위에 있는 동네가 숨기우지 못할 것이요"},{"n":15,"t":"사람이 등불을 켜서 말 아래 두지 아니하고 등경 위에 두나니 이러므로 집안 모든 사람에게 비취느니라"},{"n":16,"t":"이같이 너희 빛을 사람 앞에 비취게 하여 저희로 너희 착한 행실을 보고 하늘에 계신 너희 아버지께 영광을 돌리게 하라"},{"n":17,"t":"내가 율법이나 선지자나 폐하러 온 줄로 생각지 말라 폐하러 온 것이 아니요 완전케 하려 함이로다"},{"n":18,"t":"진실로 너희에게 이르노니 천지가 없어지기 전에는 율법의 일점 일획이라도 반드시 없어지지 아니하고 다 이루리라"},{"n":19,"t":"그러므로 누구든지 이 계명 중에 지극히 작은 것 하나라도 버리고 또 그같이 사람을 가르치는 자는 천국에서 지극히 작다 일컬음을 받을 것이요 누구든지 이를 행하며 가르치는 자는 천국에서 크다 일컬음을 받으리라"},{"n":20,"t":"내가 너희에게 이르노니 너희 의가 서기관과 바리새인보다 더 낫지 못하면 결단코 천국에 들어가지 못하리라"},{"n":21,"t":"옛 사람에게 말한바 살인치 말라 누구든지 살인하면 심판을 받게 되리라 하였다는 것을 너희가 들었으나"},{"n":22,"t":"나는 너희에게 이르노니 형제에게 노하는 자마다 심판을 받게 되고 형제를 대하여 라가라 하는 자는 공회에 잡히게 되고 미련한 놈이라 하는 자는 지옥 불에 들어가게 되리라"},{"n":23,"t":"그러므로 예물을 제단에 드리다가 거기서 네 형제에게 원망 들을만한 일이 있는줄 생각나거든"},{"n":24,"t":"예물을 제단 앞에 두고 먼저 가서 형제와 화목하고 그 후에 와서 예물을 드리라"},{"n":25,"t":"너를 송사하는 자와 함께 길에 있을 때에 급히 사화하라 그 송사하는 자가 너를 재판관에게 내어주고 재판관이 관예에게 내어주어 옥에 가둘까 염려하라"},{"n":26,"t":"진실로 네게 이르노니 네가 호리라도 남김이 없이 다 갚기 전에는 결단코 거기서 나오지 못하리라"},{"n":27,"t":"또 간음치 말라 하였다는 것을 너희가 들었으나"},{"n":28,"t":"나는 너희에게 이르노니 여자를 보고 음욕을 품는 자마다 마음에 이미 간음하였느니라"},{"n":29,"t":"만일 네 오른눈이 너로 실족케 하거든 빼어 내버리라 네 백체 중 하나가 없어지고 온 몸이 지옥에 던지우지 않는 것이 유익하며"},{"n":30,"t":"또한 만일 네 오른손이 너로 실족케 하거든 찍어 내버리라 네 백체중 하나가 없어지고 온 몸이 지옥에 던지우지 않는 것이 유익하니라"},{"n":31,"t":"또 일렀으되 누구든지 아내를 버리거든 이혼 증서를 줄 것이라 하였으나"},{"n":32,"t":"나는 너희에게 이르노니 누구든지 음행한 연고 없이 아내를 버리면 이는 저로 간음하게 함이요 또 누구든지 버린 여자에게 장가드는 자도 간음함이니라"},{"n":33,"t":"또 옛 사람에게 말한 바 헛 맹세를 하지 말고 네 맹세한 것을 주께 지키라 하였다는 것을 너희가 들었으나"},{"n":34,"t":"나는 너희에게 이르노니 도무지 맹세하지 말찌니 하늘로도 말라 이는 하나님의 보좌임이요"},{"n":35,"t":"땅으로도 말라 이는 하나님의 발등상임이요 예루살렘으로도 말라 이는 큰 임금의 성임이요"},{"n":36,"t":"네 머리로도 말라 이는 네가 한 터럭도 희고 검게 할 수 없음이라"},{"n":37,"t":"오직 너희 말은 옳다 옳다, 아니라 아니라 하라 이에서 지나는 것은 악으로 좇아 나느니라"},{"n":38,"t":"또 눈은 눈으로, 이는 이로 갚으라 하였다는 것을 너희가 들었으나"},{"n":39,"t":"나는 너희에게 이르노니 악한 자를 대적지 말라 누구든지 네 오른편 뺨을 치거든 왼편도 돌려 대며"},{"n":40,"t":"또 너를 송사하여 속옷을 가지고자 하는 자에게 겉옷까지도 가지게 하며"},{"n":41,"t":"또 누구든지 너로 억지로 오리를 가게 하거든 그 사람과 십리를 동행하고"},{"n":42,"t":"네게 구하는 자에게 주며 네게 꾸고자 하는 자에게 거절하지말라"},{"n":43,"t":"또 네 이웃을 사랑하고 네 원수를 미워하라 하였다는 것을 너희가 들었으나"},{"n":44,"t":"나는 너희에게 이르노니 너희 원수를 사랑하며 너희를 핍박하는 자를 위하여 기도하라"},{"n":45,"t":"이같이 한즉 하늘에 계신 너희 아버지의 아들이 되리니 이는 하나님이 그 해를 악인과 선인에게 비취게 하시며 비를 의로운 자와 불의한 자에게 내리우심이니라"},{"n":46,"t":"너희가 너희를 사랑하는 자를 사랑하면 무슨 상이 있으리요 세리도 이같이 아니하느냐"},{"n":47,"t":"또 너희가 너희 형제에게만 문안하면 남보다 더 하는 것이 무엇이냐 이방인들도 이같이 아니하느냐"},{"n":48,"t":"그러므로 하늘에 계신 너희 아버지의 온전하심과 같이 너희도 온전하라"}],"kids":[{"n":1,"t":"예수님은 사람들의 무리를 보시고 산에 올라가 앉으셨어요. 제자들이 곁으로 모였어요."},{"n":2,"t":"예수님은 입을 여시고 그들을 가르치기 시작하셨어요."},{"n":3,"t":"\\"마음이 가난한 사람은 복이 있어요. 천국이 그들의 것이니까요.\\""},{"n":4,"t":"\\"슬퍼하는 사람은 복이 있어요. 그들이 위로를 받을 거니까요.\\""},{"n":5,"t":"\\"온유한 사람은 복이 있어요. 그들이 땅을 물려받을 거니까요.\\""},{"n":6,"t":"\\"의에 주리고 목마른 사람은 복이 있어요. 그들이 배부르게 될 거니까요.\\""},{"n":7,"t":"\\"긍휼히 여기는 사람은 복이 있어요. 그들도 긍휼히 여김을 받을 거니까요.\\""},{"n":8,"t":"\\"마음이 깨끗한 사람은 복이 있어요. 그들이 하나님을 볼 거니까요.\\""},{"n":9,"t":"\\"화평하게 하는 사람은 복이 있어요. 그들이 하나님의 자녀라 불릴 거니까요.\\""},{"n":10,"t":"\\"의 때문에 박해받는 사람은 복이 있어요. 천국이 그들의 것이니까요.\\""},{"n":11,"t":"\\"나 때문에 사람들이 너희를 욕하고 박해하며 거짓으로 온갖 나쁜 말을 할 때 너희는 복이 있어요.\\""},{"n":12,"t":"\\"기뻐하고 즐거워해요. 하늘에서 받을 상이 크기 때문이에요. 옛 예언자들도 그렇게 박해를 받았어요.\\""},{"n":13,"t":"\\"여러분은 세상의 소금이에요. 소금이 짠맛을 잃으면 무엇으로 짜게 만들겠어요? 아무 데도 쓸 데가 없어서 밖에 버려져 사람들 발에 밟힐 뿐이에요.\\""},{"n":14,"t":"\\"여러분은 세상의 빛이에요. 산 위에 있는 동네는 숨길 수 없어요.\\""},{"n":15,"t":"\\"사람들이 등불을 켜서 그릇으로 덮어 두지 않고 등잔대 위에 놓아 집 안 모든 사람을 비추게 하지요.\\""},{"n":16,"t":"\\"그렇게 여러분의 빛을 사람들 앞에 비추세요. 그래서 그들이 여러분의 착한 행실을 보고 하늘에 계신 여러분의 아버지께 영광을 돌리게 해요.\\""},{"n":17,"t":"\\"내가 율법이나 예언자들의 말씀을 없애러 왔다고 생각하지 마라. 없애려는 게 아니라 완전하게 이루려고 왔어.\\""},{"n":18,"t":"\\"진정으로 말한다. 하늘과 땅이 사라지기까지 율법의 한 점, 한 획도 사라지지 않을 거야. 모든 것이 다 이루어지기까지.\\""},{"n":19,"t":"\\"그래서 이 계명 중에 가장 작은 것 하나라도 어기고 다른 사람에게 그렇게 가르치는 사람은 천국에서 가장 작다고 불릴 거야. 그러나 계명을 지키고 가르치는 사람은 천국에서 크다고 불릴 거야.\\""},{"n":20,"t":"\\"내가 말한다. 너희의 의가 율법 학자와 바리새인들의 의보다 더 낫지 않으면 결코 천국에 들어가지 못한다.\\""},{"n":21,"t":"\\"옛 사람들에게 \'살인하지 말라. 살인하는 사람은 심판을 받을 거야\'라고 한 말을 너희가 들었지요.\\""},{"n":22,"t":"\\"그러나 나는 말한다. 형제에게 화내는 사람마다 심판을 받게 될 거야. 형제에게 \'바보야\'라고 하는 사람은 공회 앞에 서게 되고, \'미친놈아\'라고 하는 사람은 지옥 불에 들어갈 거야.\\""},{"n":23,"t":"\\"그러므로 제단에 예물을 가져왔다가 거기서 형제가 너에게 원망할 일이 있는 게 생각나면,\\""},{"n":24,"t":"\\"예물을 제단 앞에 두고 먼저 가서 형제와 화해해. 그러고 나서 와서 예물을 드려라.\\""},{"n":25,"t":"\\"너를 고소하는 사람과 함께 길에 있을 때 빨리 화해해. 그렇지 않으면 그가 너를 재판관에게 넘기고, 재판관이 다시 너를 간수에게 넘겨 감옥에 갇히게 될지도 몰라.\\""},{"n":26,"t":"\\"진정으로 말한다. 너는 마지막 한 푼까지 다 갚기 전에는 거기서 결코 나오지 못할 거야.\\""},{"n":27,"t":"\\"\'간음하지 말라\'고 한 말을 들었지요.\\""},{"n":28,"t":"\\"그러나 나는 말한다. 여자를 보고 음란한 마음을 품는 사람은 이미 마음으로 그 여자와 간음한 거예요.\\""},{"n":29,"t":"\\"오른 눈이 너를 죄짓게 하거든 빼서 던져 버려. 몸의 한 부분을 잃는 것이 온몸이 지옥에 던져지는 것보다 나아.\\""},{"n":30,"t":"\\"오른손이 너를 죄짓게 하거든 잘라서 던져 버려. 한 손을 잃는 게 온몸이 지옥에 던져지는 것보다 나아.\\""},{"n":31,"t":"\\"또 \'아내를 버리려는 사람은 이혼증서를 써 주라\'고 했지요.\\""},{"n":32,"t":"\\"그러나 나는 말한다. 음란한 일 때문이 아니라면 자기 아내를 버리는 사람은 그 아내가 간음하게 만드는 거고, 버려진 여자와 결혼하는 사람도 간음하는 거야.\\""},{"n":33,"t":"\\"또 옛 사람들에게 \'거짓 맹세를 하지 말고 네가 한 맹세는 주님께 지키라\'고 한 말을 들었지요.\\""},{"n":34,"t":"\\"그러나 나는 말한다. 절대로 맹세하지 마라. 하늘을 두고도 하지 마. 하늘은 하나님의 보좌이기 때문이야.\\""},{"n":35,"t":"\\"땅을 두고도 하지 마. 땅은 하나님의 발판이기 때문이야. 예루살렘을 두고도 하지 마. 그곳은 큰 왕의 도시이기 때문이야.\\""},{"n":36,"t":"\\"너의 머리를 두고도 맹세하지 마. 너는 머리카락 한 올도 희게 하거나 검게 할 수 없잖아.\\""},{"n":37,"t":"\\"너희 말은 \'예\' 할 것은 \'예\' 하고, \'아니오\' 할 것은 \'아니오\' 하면 돼. 그 이상은 악에서 나오는 거야.\\""},{"n":38,"t":"\\"\'눈에는 눈, 이에는 이\'라고 한 말을 들었지요.\\""},{"n":39,"t":"\\"그러나 나는 말한다. 악한 사람에게 맞서지 마. 누구든 네 오른뺨을 때리면 왼뺨도 돌려 대.\\""},{"n":40,"t":"\\"너를 고소해서 속옷을 가지려는 사람에게는 겉옷까지 가지게 해.\\""},{"n":41,"t":"\\"누구든 너에게 오 리를 가자고 하면 십 리를 함께 가 줘.\\""},{"n":42,"t":"\\"달라는 사람에게는 주고, 빌리려는 사람을 거절하지 마.\\""},{"n":43,"t":"\\"\'네 이웃을 사랑하고 네 원수를 미워하라\'고 한 말을 들었지요.\\""},{"n":44,"t":"\\"그러나 나는 말한다. 너희 원수를 사랑하고 너희를 박해하는 사람들을 위해 기도해.\\""},{"n":45,"t":"\\"그래야 너희가 하늘에 계신 너희 아버지의 자녀가 돼. 아버지께서는 악한 사람과 선한 사람 모두에게 해를 떠오르게 하시고, 의로운 사람과 불의한 사람 모두에게 비를 내려 주시거든.\\""},{"n":46,"t":"\\"너희가 너희를 사랑하는 사람만 사랑한다면 무슨 상이 있겠니? 세리들도 그렇게 하잖아.\\""},{"n":47,"t":"\\"너희가 너희 형제들에게만 인사한다면 다른 사람보다 더 잘하는 게 무엇이야? 이방인들도 그렇게 하잖아.\\""},{"n":48,"t":"\\"그러므로 하늘에 계신 너희 아버지께서 온전하신 것처럼 너희도 온전해라.\\""}]}},{"chapter":6,"title":"주기도문과 참된 보물","verses":{"krv":[{"n":1,"t":"사람에게 보이려고 그들 앞에서 너희 의를 행치 않도록 주의하라 그렇지 아니하면 하늘에 계신 너희 아버지께 상을 얻지 못하느니라"},{"n":2,"t":"그러므로 구제할 때에 외식하는 자가 사람에게 영광을 얻으려고 회당과 거리에서 하는것 같이 너희 앞에 나팔을 불지 말라 진실로 너희에게 이르노니 저희는 자기 상을 이미 받았느니라"},{"n":3,"t":"너는 구제할 때에 오른손의 하는 것을 왼손이 모르게 하여"},{"n":4,"t":"네 구제함이 은밀하게 하라 은밀한 중에 보시는 너의 아버지가 갚으시리라"},{"n":5,"t":"또 너희가 기도할 때에 외식하는 자와 같이 되지 말라 저희는 사람에게 보이려고 회당과 큰 거리 어귀에 서서 기도하기를 좋아하느니라 내가 진실로 너희에게 이르노니 저희는 자기 상을 이미 받았느니라"},{"n":6,"t":"너는 기도할 때에 네 골방에 들어가 문을 닫고 은밀한 중에 계신 네 아버지께 기도하라 은밀한 중에 보시는 네 아버지께서 갚으시리라"},{"n":7,"t":"또 기도할 때에 이방인과 같이 중언부언하지 말라 저희는 말을 많이 하여야 들으실줄 생각하느니라"},{"n":8,"t":"그러므로 저희를 본받지 말라 구하기 전에 너희에게 있어야 할 것을 하나님 너희 아버지께서 아시느니라"},{"n":9,"t":"그러므로 너희는 이렇게 기도하라 하늘에 계신 우리 아버지여 이름이 거룩히 여김을 받으시오며"},{"n":10,"t":"나라이 임하옵시며 뜻이 하늘에서 이룬 것같이 땅에서도 이루어지이다"},{"n":11,"t":"오늘날 우리에게 일용할 양식을 주옵시고"},{"n":12,"t":"우리가 우리에게 죄 지은 자를 사하여 준것 같이 우리 죄를 사하여 주옵시고"},{"n":13,"t":"우리를 시험에 들게 하지 마옵시고 다만 악에서 구하옵소서 (나라와 권세와 영광이 아버지께 영원히 있사옵나이다 아멘)"},{"n":14,"t":"너희가 사람의 과실을 용서하면 너희 천부께서도 너희 과실을 용서하시려니와"},{"n":15,"t":"너희가 사람의 과실을 용서하지 아니하면 너희 아버지께서도 너희 과실을 용서하지 아니하시리라"},{"n":16,"t":"금식할 때에 너희는 외식하는 자들과 같이 슬픈 기색을 내지 말라 저희는 금식하는 것을 사람에게 보이려고 얼굴을 흉하게 하느니라 내가 진실로 너희에게 이르노니 저희는 자기 상을 이미 받았느니라"},{"n":17,"t":"너는 금식할 때에 머리에 기름을 바르고 얼굴을 씻으라"},{"n":18,"t":"이는 금식하는 자로 사람에게 보이지 않고 오직 은밀한 중에 계신 네 아버지께 보이게 하려 함이라 은밀한 중에 보시는 네 아버지께서 갚으시리라"},{"n":19,"t":"너희를 위하여 보물을 땅에 쌓아 두지 말라 거기는 좀과 동록이 해하며 도적이 구멍을 뚫고 도적질하느니라"},{"n":20,"t":"오직 너희를 위하여 보물을 하늘에 쌓아 두라 거기는 좀이나 동록이 해하지 못하며 도적이 구멍을 뚫지도 못하고 도적질도 못하느니라"},{"n":21,"t":"네 보물 있는 그 곳에는 네 마음도 있느니라"},{"n":22,"t":"눈은 몸의 등불이니 그러므로 네 눈이 성하면 온 몸이 밝을 것이요"},{"n":23,"t":"눈이 나쁘면 온 몸이 어두울 것이니 그러므로 네게 있는 빛이 어두우면 그 어두움이 얼마나 하겠느뇨"},{"n":24,"t":"한 사람이 두 주인을 섬기지 못할 것이니 혹 이를 미워하며 저를 사랑하거나 혹 이를 중히 여기며 저를 경히 여김이라 너희가 하나님과 재물을 겸하여 섬기지 못하느니라"},{"n":25,"t":"그러므로 내가 너희에게 이르노니 목숨을 위하여 무엇을 먹을까 무엇을 마실까 몸을 위하여 무엇을 입을까 염려하지 말라 목숨이 음식보다 중하지 아니하며 몸이 의복보다 중하지 아니하냐"},{"n":26,"t":"공중의 새를 보라 심지도 않고 거두지도 않고 창고에 모아 들이지도 아니하되 너희 천부께서 기르시나니 너희는 이것들보다 귀하지 아니하냐"},{"n":27,"t":"너희 중에 누가 염려함으로 그 키를 한 자나 더할 수 있느냐"},{"n":28,"t":"또 너희가 어찌 의복을 위하여 염려하느냐 들의 백합화가 어떻게 자라는가 생각하여 보라 수고도 아니하고 길쌈도 아니하느니라"},{"n":29,"t":"그러나 내가 너희에게 말하노니 솔로몬의 모든 영광으로도 입은 것이 이 꽃 하나만 같지 못하였느니라"},{"n":30,"t":"오늘 있다가 내일 아궁이에 던지우는 들풀도 하나님이 이렇게 입히시거든 하물며 너희일까보냐 믿음이 적은 자들아"},{"n":31,"t":"그러므로 염려하여 이르기를 무엇을 먹을까 무엇을 마실까 무엇을 입을까 하지 말라"},{"n":32,"t":"이는 다 이방인들이 구하는 것이라 너희 천부께서 이 모든 것이 너희에게 있어야 할 줄을 아시느니라"},{"n":33,"t":"너희는 먼저 그의 나라와 그의 의를 구하라 그리하면 이 모든 것을 너희에게 더하시리라"},{"n":34,"t":"그러므로 내일 일을 위하여 염려하지 말라 내일 일은 내일 염려할 것이요 한 날 괴로움은 그 날에 족하니라"}],"kids":[{"n":1,"t":"\\"사람들에게 보이려고 그들 앞에서 의를 행하지 않도록 조심해. 그러면 하늘에 계신 너희 아버지께 받을 상이 없게 돼.\\""},{"n":2,"t":"\\"가난한 사람에게 도움을 줄 때 위선자들처럼 회당과 거리에서 나팔을 불지 마. 그들은 사람들에게 칭찬받으려고 그래. 진정으로 말한다. 그들은 이미 자기 상을 다 받았어.\\""},{"n":3,"t":"\\"너는 도움을 줄 때 오른손이 하는 일을 왼손이 모르게 해.\\""},{"n":4,"t":"\\"그래야 너의 도움이 숨겨지고, 숨은 일을 보시는 아버지께서 너에게 갚아 주실 거야.\\""},{"n":5,"t":"\\"기도할 때도 위선자들처럼 하지 마. 그들은 회당과 길모퉁이에 서서 사람들에게 보이려고 기도하기를 좋아해. 진정으로 말한다. 그들은 이미 자기 상을 다 받았어.\\""},{"n":6,"t":"\\"너는 기도할 때 네 방에 들어가 문을 닫고 보이지 않는 아버지께 기도해. 숨은 일을 보시는 아버지께서 너에게 갚아 주실 거야.\\""},{"n":7,"t":"\\"기도할 때 이방인들처럼 같은 말을 자꾸 되풀이하지 마. 그들은 말을 많이 해야 들어주신다고 생각하거든.\\""},{"n":8,"t":"\\"그들을 본받지 마. 너희가 구하기 전에 너희 아버지께서 너희에게 무엇이 필요한지 다 아셔.\\""},{"n":9,"t":"\\"그러니까 너희는 이렇게 기도해. \'하늘에 계신 우리 아버지, 아버지의 이름이 거룩히 여김을 받으시고,\\""},{"n":10,"t":"\\"아버지의 나라가 오시고, 아버지의 뜻이 하늘에서 이루어진 것 같이 땅에서도 이루어지기를 원해요.\\""},{"n":11,"t":"\\"오늘 우리에게 일용할 양식을 주시고,\\""},{"n":12,"t":"\\"우리에게 죄지은 사람을 우리가 용서한 것 같이 우리 죄도 용서해 주세요.\\""},{"n":13,"t":"\\"우리를 시험에 들지 않게 하시고 악에서 우리를 건져 주세요. 나라와 권세와 영광이 영원히 아버지의 것이에요. 아멘.\'\\""},{"n":14,"t":"\\"너희가 다른 사람의 잘못을 용서하면 하늘에 계신 너희 아버지께서도 너희를 용서해 주실 거야.\\""},{"n":15,"t":"\\"그러나 너희가 다른 사람을 용서하지 않으면 너희 아버지께서도 너희 잘못을 용서하지 않으셔.\\""},{"n":16,"t":"\\"금식할 때 위선자들처럼 슬픈 얼굴을 짓지 마. 그들은 사람들에게 보이려고 얼굴을 일부러 흉하게 만들어. 진정으로 말한다. 그들은 이미 자기 상을 다 받았어.\\""},{"n":17,"t":"\\"너는 금식할 때 머리에 기름을 바르고 얼굴을 씻어.\\""},{"n":18,"t":"\\"사람들에게 금식하는 모습을 보이지 않고 보이지 않는 아버지께만 보여 드려. 숨은 일을 보시는 아버지께서 너에게 갚아 주실 거야.\\""},{"n":19,"t":"\\"보물을 땅에 쌓아 두지 마. 거기는 좀과 녹이 망가뜨리고 도둑이 들어와 훔쳐 가.\\""},{"n":20,"t":"\\"오직 보물을 하늘에 쌓아 둬. 거기는 좀이나 녹이 망가뜨릴 수 없고 도둑이 들어와 훔치지도 못해.\\""},{"n":21,"t":"\\"너의 보물이 있는 곳에 너의 마음도 있어.\\""},{"n":22,"t":"\\"몸의 등불은 눈이야. 그래서 네 눈이 성하면 온몸이 밝을 거야.\\""},{"n":23,"t":"\\"그러나 네 눈이 나쁘면 온몸이 어두울 거야. 네 안에 있는 빛이 어두우면 그 어둠이 얼마나 더 깊겠니!\\""},{"n":24,"t":"\\"아무도 두 주인을 함께 섬길 수 없어. 한쪽을 미워하고 다른 쪽을 사랑하거나, 한쪽을 받들고 다른 쪽을 무시하게 돼. 너희는 하나님과 돈을 함께 섬길 수 없어.\\""},{"n":25,"t":"\\"그래서 너희에게 말한다. 무엇을 먹을지, 무엇을 마실지, 몸을 위해 무엇을 입을지 걱정하지 마. 목숨이 음식보다 더 소중하고 몸이 옷보다 더 소중하지 않니?\\""},{"n":26,"t":"\\"하늘의 새들을 봐. 씨를 뿌리지도 거두지도, 창고에 모아 두지도 않지만 너희 하늘 아버지께서 먹여 주셔. 너희는 새들보다 훨씬 소중하잖아!\\""},{"n":27,"t":"\\"너희 중에 누가 걱정한다고 자기 목숨을 한 시간이라도 늘릴 수 있겠어?\\""},{"n":28,"t":"\\"왜 옷 걱정을 하니? 들에 핀 백합화가 어떻게 자라는지 살펴봐. 일도 하지 않고 옷감도 짜지 않아.\\""},{"n":29,"t":"\\"내가 말한다. 솔로몬이 누렸던 모든 영광 속에서도 이 꽃 하나만큼 옷을 입지 못했어.\\""},{"n":30,"t":"\\"오늘 있다가 내일 화덕에 던져질 들의 풀도 하나님이 그렇게 꾸며 주시는데, 하물며 너희에게는 더 잘해 주시지 않겠니? 믿음이 적은 사람들아!\\""},{"n":31,"t":"\\"그러니까 \'무엇을 먹지? 무엇을 마시지? 무엇을 입지?\' 하면서 걱정하지 마.\\""},{"n":32,"t":"\\"이것들은 다 이방인들이 구하는 거야. 너희 하늘 아버지께서 너희에게 이 모든 것이 필요한 줄 아셔.\\""},{"n":33,"t":"\\"그러니까 너희는 먼저 하나님의 나라와 그분의 의를 구해. 그러면 이 모든 것이 너희에게 더해질 거야.\\""},{"n":34,"t":"\\"내일 일을 걱정하지 마. 내일 일은 내일이 걱정할 거야. 그날의 어려움은 그날로 충분해.\\""}]}},{"chapter":7,"title":"좁은 문과 반석 위의 집","verses":{"krv":[{"n":1,"t":"비판을 받지 아니하려거든 비판하지 말라"},{"n":2,"t":"너희의 비판하는 그 비판으로 너희가 비판을 받을 것이요 너희의 헤아리는 그 헤아림으로 너희가 헤아림을 받을 것이니라"},{"n":3,"t":"어찌하여 형제의 눈속에 있는 티는 보고 네 눈속에 있는 들보는 깨닫지 못하느냐"},{"n":4,"t":"보라 네 눈속에 들보가 있는데 어찌하여 형제에게 말하기를 나로 네 눈속에 있는 티를 빼게 하라 하겠느냐"},{"n":5,"t":"외식하는 자여 먼저 네 눈속에서 들보를 빼어라 그 후에야 밝히보고 형제의 눈속에서 티를 빼리라"},{"n":6,"t":"거룩한 것을 개에게 주지 말며 너희 진주를 돼지 앞에 던지지 말라 저희가 그것을 발로 밟고 돌이켜 너희를 찢어 상할까 염려하라"},{"n":7,"t":"구하라 그러면 너희에게 주실 것이요 찾으라 그러면 찾을 것이요 문을 두드리라 그러면 너희에게 열릴 것이니"},{"n":8,"t":"구하는 이마다 얻을 것이요 찾는 이가 찾을 것이요 두드리는 이에게 열릴 것이니라"},{"n":9,"t":"너희 중에 누가 아들이 떡을 달라 하면 돌을 주며"},{"n":10,"t":"생선을 달라 하면 뱀을 줄 사람이 있겠느냐"},{"n":11,"t":"너희가 악한 자라도 좋은 것으로 자식에게 줄줄 알거든 하물며 하늘에 계신 너희 아버지께서 구하는 자에게 좋은 것으로 주시지 않겠느냐"},{"n":12,"t":"그러므로 무엇이든지 남에게 대접을 받고자 하는대로 너희도 남을 대접하라 이것이 율법이요 선지자니라"},{"n":13,"t":"좁은 문으로 들어가라 멸망으로 인도하는 문은 크고 그 길이 넓어 그리로 들어가는 자가 많고"},{"n":14,"t":"생명으로 인도하는 문은 좁고 길이 협착하여 찾는 이가 적음이니라"},{"n":15,"t":"거짓 선지자들을 삼가라 양의 옷을 입고 너희에게 나아오나 속에는 노략질하는 이리라"},{"n":16,"t":"그의 열매로 그들을 알찌니 가시나무에서 포도를, 또는 엉겅퀴에서 무화과를 따겠느냐"},{"n":17,"t":"이와 같이 좋은 나무마다 아름다운 열매를 맺고 못된 나무가 나쁜 열매를 맺나니"},{"n":18,"t":"좋은 나무가 나쁜 열매를 맺을 수 없고 못된 나무가 아름다운 열매를 맺을 수 없느니라"},{"n":19,"t":"아름다운 열매를 맺지 아니하는 나무마다 찍혀 불에 던지우니라"},{"n":20,"t":"이러므로 그의 열매로 그들을 알리라"},{"n":21,"t":"나더러 주여 주여 하는 자마다 천국에 다 들어갈 것이 아니요 다만 하늘에 계신 내 아버지의 뜻대로 행하는 자라야 들어가리라"},{"n":22,"t":"그 날에 많은 사람이 나더러 이르되 주여 주여 우리가 주의 이름으로 선지자 노릇하며 주의 이름으로 귀신을 쫓아 내며 주의 이름으로 많은 권능을 행치 아니하였나이까 하리니"},{"n":23,"t":"그 때에 내가 저희에게 밝히 말하되 내가 너희를 도무지 알지 못하니 불법을 행하는 자들아 내게서 떠나가라 하리라"},{"n":24,"t":"그러므로 누구든지 나의 이 말을 듣고 행하는 자는 그 집을 반석 위에 지은 지혜로운 사람 같으리니"},{"n":25,"t":"비가 내리고 창수가 나고 바람이 불어 그 집에 부딪히되 무너지지 아니하나니 이는 주초를 반석 위에 놓은 연고요"},{"n":26,"t":"나의 이 말을 듣고 행치 아니하는 자는 그 집을 모래 위에 지은 어리석은 사람 같으리니"},{"n":27,"t":"비가 내리고 창수가 나고 바람이 불어 그 집에 부딪히매 무너져 그 무너짐이 심하니라"},{"n":28,"t":"예수께서 이 말씀을 마치시매 무리들이 그 가르치심에 놀래니"},{"n":29,"t":"이는 그 가르치시는 것이 권세 있는 자와 같고 저희 서기관들과 같지 아니함일러라"}],"kids":[{"n":1,"t":"\\"남을 판단하지 마. 그래야 너희도 판단받지 않아.\\""},{"n":2,"t":"\\"너희가 판단하는 그 기준으로 너희도 판단받을 거야. 너희가 사용하는 그 잣대로 너희도 재게 될 거야.\\""},{"n":3,"t":"\\"어떻게 너는 형제의 눈 속에 있는 작은 티끌은 보면서 자기 눈 속에 있는 들보는 보지 못하니?\\""},{"n":4,"t":"\\"네 눈 속에 들보가 있는데 어떻게 형제에게 \'내가 네 눈에서 티끌을 빼 줄게\'라고 말할 수 있어?\\""},{"n":5,"t":"\\"위선자야! 먼저 네 눈 속의 들보를 빼 봐. 그래야 네가 똑똑히 보고 형제 눈의 티끌도 빼 줄 수 있어.\\""},{"n":6,"t":"\\"거룩한 것을 개에게 주지 말고 진주를 돼지에게 던지지 마. 그것들이 발로 짓밟고 돌이켜 너희를 물어뜯을지도 몰라.\\""},{"n":7,"t":"\\"구해. 그러면 받을 거야. 찾아. 그러면 만날 거야. 두드려. 그러면 열릴 거야.\\""},{"n":8,"t":"\\"구하는 사람마다 받고, 찾는 사람은 만나고, 두드리는 사람에게는 열려.\\""},{"n":9,"t":"\\"너희 중에 누가 자기 아들이 빵을 달라는데 돌을 줄 사람이 있겠니?\\""},{"n":10,"t":"\\"생선을 달라는데 뱀을 줄 사람이 있겠어?\\""},{"n":11,"t":"\\"너희가 악할지라도 자녀에게 좋은 선물을 줄 줄 아는데, 하물며 하늘에 계신 너희 아버지께서 구하는 사람에게 좋은 것을 주시지 않겠니!\\""},{"n":12,"t":"\\"그러니까 무엇이든지 남에게 대접받고자 하는 대로 너희도 그렇게 남을 대접해. 이게 율법과 예언자들의 가르침이야.\\""},{"n":13,"t":"\\"좁은 문으로 들어가. 멸망으로 가는 문은 크고 길도 넓어서 그리로 들어가는 사람이 많아.\\""},{"n":14,"t":"\\"하지만 생명으로 가는 문은 좁고 길도 좁아서 그것을 찾는 사람이 적어.\\""},{"n":15,"t":"\\"거짓 예언자들을 조심해. 그들은 양의 옷을 입고 너희에게 오지만 속에는 사나운 늑대야.\\""},{"n":16,"t":"\\"열매를 보고 그들을 알 수 있어. 가시나무에서 포도를, 엉겅퀴에서 무화과를 딸 수는 없잖아.\\""},{"n":17,"t":"\\"이처럼 좋은 나무는 좋은 열매를 맺고 못된 나무는 나쁜 열매를 맺어.\\""},{"n":18,"t":"\\"좋은 나무가 나쁜 열매를 맺을 수 없고 못된 나무가 좋은 열매를 맺을 수 없어.\\""},{"n":19,"t":"\\"좋은 열매를 맺지 못하는 나무는 다 찍혀서 불에 던져져.\\""},{"n":20,"t":"\\"그러므로 너희는 그들의 열매로 그들을 알 수 있어.\\""},{"n":21,"t":"\\"나에게 \'주님, 주님\' 하는 사람마다 다 천국에 들어가는 게 아니야. 하늘에 계신 내 아버지의 뜻대로 행하는 사람만 들어가.\\""},{"n":22,"t":"\\"그날에 많은 사람이 내게 말할 거야. \'주님, 주님, 우리가 주님의 이름으로 예언하지 않았나요? 주님의 이름으로 귀신을 쫓고 많은 능력을 행하지 않았나요?\'\\""},{"n":23,"t":"\\"그때 나는 분명히 말할 거야. \'나는 너희를 전혀 알지 못한다. 불법을 행하던 사람들아, 내게서 떠나라.\'\\""},{"n":24,"t":"\\"그러므로 내 말을 듣고 그대로 행하는 사람은 반석 위에 집을 지은 슬기로운 사람과 같아.\\""},{"n":25,"t":"\\"비가 내리고 홍수가 나고 바람이 불어 그 집에 부딪쳤지만, 무너지지 않았어. 반석 위에 세웠기 때문이야.\\""},{"n":26,"t":"\\"그러나 내 말을 듣고 행하지 않는 사람은 모래 위에 집을 지은 어리석은 사람과 같아.\\""},{"n":27,"t":"\\"비가 내리고 홍수가 나고 바람이 불어 그 집에 부딪치니 무너지고 말았어. 그 무너짐이 정말 컸어.\\""},{"n":28,"t":"\\"예수님이 이 말씀을 마치셨을 때 무리는 그분의 가르침에 깜짝 놀랐어요.\\""},{"n":29,"t":"\\"예수님은 율법 학자들과는 달리 권세 있는 분처럼 가르치셨거든요.\\""}]}},{"chapter":8,"title":"병을 고치시고 풍랑을 잠재우심","verses":{"krv":[{"n":1,"t":"예수께서 산에서 내려오시니 허다한 무리가 좇으니라"},{"n":2,"t":"한 문둥병자가 나아와 절하고 가로되 주여 원하시면 저를 깨끗케 하실수 있나이다 하거늘"},{"n":3,"t":"예수께서 손을 내밀어 저에게 대시며 가라사대 내가 원하노니 깨끗함을 받으라 하신대 즉시 그의 문둥병이 깨끗하여진지라"},{"n":4,"t":"예수께서 이르시되 삼가 아무에게도 이르지 말고 다만 가서 제사장에게 네 몸을 보이고 모세의 명한 예물을 드려 저희에게 증거하라 하시니라"},{"n":5,"t":"예수께서 가버나움에 들어가시니 한 백부장이 나아와 간구하여"},{"n":6,"t":"가로되 주여 내 하인이 중풍병으로 집에 누워 몹시 괴로와하나이다"},{"n":7,"t":"가라사대 내가 가서 고쳐 주리라"},{"n":8,"t":"백부장이 대답하여 가로되 주여 내 집에 들어오심을 나는 감당치 못하겠사오니 다만 말씀으로만 하옵소서 그러면 내 하인이 낫겠삽나이다"},{"n":9,"t":"나도 남의 수하에 있는 사람이요 내 아래도 군사가 있으니 이더러 가라 하면 가고 저더러 오라 하면 오고 내 종더러 이것을 하라 하면 하나이다"},{"n":10,"t":"예수께서 들으시고 기이히 여겨 좇는 자들에게 이르시되 내가 진실로 너희에게 이르노니 이스라엘 중 아무에게서도 이만한 믿음을 만나보지 못하였노라"},{"n":11,"t":"또 너희에게 이르노니 동서로부터 많은 사람이 이르러 아브라함과 이삭과 야곱과 함께 천국에 앉으려니와"},{"n":12,"t":"나라의 본 자손들은 바깥 어두운 데 쫓겨나 거기서 울며 이를 갊이 있으리라"},{"n":13,"t":"예수께서 백부장에게 이르시되 가라 네 믿은대로 될지어다 하시니 그 시로 하인이 나으니라"},{"n":14,"t":"예수께서 베드로의 집에 들어가사 그의 장모가 열병으로 앓아 누운 것을 보시고"},{"n":15,"t":"그의 손을 만지시니 열병이 떠나가고 여인이 일어나서 예수께 수종들더라"},{"n":16,"t":"저물매 사람들이 귀신 들린 자를 많이 데리고 예수께 오거늘 예수께서 말씀으로 귀신들을 쫓아 내시고 병든 자를 다 고치시니"},{"n":17,"t":"이는 선지자 이사야로 하신 말씀에 우리 연약한 것을 친히 담당하시고 병을 짊어지셨도다 함을 이루려 하심이더라"},{"n":18,"t":"예수께서 무리가 자기를 에워쌈을 보시고 저편으로 건너가기를 명하시니라"},{"n":19,"t":"한 서기관이 나아와 예수께 말씀하되 선생님이여 어디로 가시든지 저는 좇으리이다"},{"n":20,"t":"예수께서 이르시되 여우도 굴이 있고 공중의 새도 거처가 있으되 오직 인자는 머리 둘 곳이 없다 하시더라"},{"n":21,"t":"제자 중에 또 하나가 가로되 주여 나로 먼저 가서 내 부친을 장사하게 허락하옵소서"},{"n":22,"t":"예수께서 가라사대 죽은 자들로 저희 죽은 자를 장사하게 하고 너는 나를 좇으라 하시니라"},{"n":23,"t":"배에 오르시매 제자들이 좇았더니"},{"n":24,"t":"바다에 큰 놀이 일어나 물결이 배에 덮이게 되었으되 예수는 주무시는지라"},{"n":25,"t":"그 제자들이 나아와 깨우며 가로되 주여 구원하소서 우리가 죽겠나이다"},{"n":26,"t":"예수께서 이르시되 어찌하여 무서워하느냐 믿음이 적은 자들아 하시고 곧 일어나사 바람과 바다를 꾸짖으신대 아주 잔잔하게 되거늘"},{"n":27,"t":"그 사람들이 기이히 여겨 가로되 이 어떠한 사람이기에 바람과 바다도 순종하는고 하더라"},{"n":28,"t":"또 예수께서 건너편 가다라 지방에 가시매 귀신 들린 자 둘이 무덤 사이에서 나와 예수를 만나니 저희는 심히 사나와 아무도 그 길로 지나갈 수 없을만하더라"},{"n":29,"t":"이에 저희가 소리질러 가로되 하나님의 아들이여 우리와 당신과 무슨 상관이 있나이까 때가 이르기 전에 우리를 괴롭게 하려고 여기 오셨나이까 하더니"},{"n":30,"t":"마침 멀리서 많은 돼지 떼가 먹고 있는지라"},{"n":31,"t":"귀신들이 예수께 간구하여 가로되 만일 우리를 쫓아 내실진대 돼지 떼에 들여 보내소서 한대"},{"n":32,"t":"저희더러 가라 하시니 귀신들이 나와서 돼지에게로 들어가는지라 온 떼가 비탈로 내리달아 바다에 들어가서 물에서 몰사하거늘"},{"n":33,"t":"치던 자들이 달아나 시내에 들어가 이 모든 일과 귀신들린 자의 일을 고하니"},{"n":34,"t":"온 시내가 예수를 만나려고 나가서 보고 그 지방에서 떠나시기를 간구하더라"}],"kids":[{"n":1,"t":"예수님이 산에서 내려오시자 큰 무리가 그분을 따라왔어요."},{"n":2,"t":"그런데 나병 환자 한 사람이 다가와 예수님께 절하며 말했어요. \\"주님, 원하시면 저를 깨끗하게 하실 수 있어요.\\""},{"n":3,"t":"예수님이 손을 내밀어 그를 만지며 말씀하셨어요. \\"원해. 깨끗해져라.\\" 그러자 그 사람의 나병이 곧 깨끗해졌어요."},{"n":4,"t":"예수님이 말씀하셨어요. \\"아무에게도 말하지 마. 가서 제사장에게 네 몸을 보이고 모세가 명령한 예물을 드려, 사람들 앞에 증거가 되게 해.\\""},{"n":5,"t":"예수님이 가버나움에 들어가셨을 때 한 백부장이 와서 부탁했어요."},{"n":6,"t":"\\"주님, 제 종이 중풍으로 몹시 괴로워하며 집에 누워 있어요.\\""},{"n":7,"t":"예수님이 말씀하셨어요. \\"내가 가서 그를 고쳐 줄게.\\""},{"n":8,"t":"백부장이 대답했어요. \\"주님, 저는 주님을 제 집에 모실 자격이 없어요. 그저 말씀만 해 주세요. 그러면 제 종이 나을 거예요.\\""},{"n":9,"t":"\\"저도 다른 사람의 명령을 받는 사람이고 제 아래에도 군인들이 있어요. 한 사람에게 \'가라\' 하면 가고 다른 사람에게 \'오라\' 하면 오고, 종에게 \'이것을 하라\' 하면 합니다.\\""},{"n":10,"t":"예수님이 듣고 놀라시며 따르는 사람들에게 말씀하셨어요. \\"진정으로 말한다. 이스라엘에서도 이런 큰 믿음은 본 적이 없다.\\""},{"n":11,"t":"\\"내가 너희에게 말한다. 동쪽과 서쪽에서 많은 사람들이 와서 천국에서 아브라함, 이삭, 야곱과 함께 잔치에 앉을 거야.\\""},{"n":12,"t":"\\"그러나 본래 천국의 자녀가 될 사람들은 바깥 어둠으로 쫓겨나서 거기서 울며 이를 갈게 될 거야.\\""},{"n":13,"t":"그러고 나서 예수님이 백부장에게 말씀하셨어요. \\"가라. 네가 믿은 대로 될 거야.\\" 바로 그 시간에 종이 나았어요."},{"n":14,"t":"예수님이 베드로의 집에 들어가셔서 그의 장모가 열병으로 누워 있는 것을 보셨어요."},{"n":15,"t":"예수님이 그녀의 손을 만지시자 열이 떠나갔고, 그녀는 일어나서 예수님을 섬겼어요."},{"n":16,"t":"날이 저물 때, 사람들이 귀신 들린 많은 사람을 예수님께 데려왔어요. 예수님은 말씀으로 귀신들을 쫓아내시고 병자들을 다 고쳐 주셨어요."},{"n":17,"t":"이는 예언자 이사야의 말이 이루어진 거예요. \\"그가 우리의 약한 것을 친히 담당하시고 병을 짊어지셨다.\\""},{"n":18,"t":"예수님은 자기 둘레에 큰 무리가 모인 것을 보시고 호수 건너편으로 가라고 분부하셨어요."},{"n":19,"t":"한 율법 학자가 와서 말했어요. \\"선생님, 어디로 가시든지 따라가겠어요.\\""},{"n":20,"t":"예수님이 말씀하셨어요. \\"여우도 굴이 있고 새도 둥지가 있지만, 사람의 아들은 머리 둘 곳도 없다.\\""},{"n":21,"t":"제자 중 한 사람이 말했어요. \\"주님, 먼저 가서 제 아버지를 묻게 해 주세요.\\""},{"n":22,"t":"예수님이 말씀하셨어요. \\"나를 따라라. 죽은 사람들은 그들의 죽은 사람들이 묻게 두어라.\\""},{"n":23,"t":"예수님이 배에 오르시자 제자들이 따라 올랐어요."},{"n":24,"t":"갑자기 바다에 큰 풍랑이 일어 배가 파도에 덮였어요. 그런데 예수님은 주무시고 계셨어요."},{"n":25,"t":"제자들이 와서 깨우며 말했어요. \\"주님, 살려 주세요! 우리가 죽게 됐어요!\\""},{"n":26,"t":"예수님이 말씀하셨어요. \\"왜 그렇게 무서워하니, 믿음이 적은 자들아?\\" 그러고 일어나 바람과 바다를 꾸짖으시자 아주 잔잔해졌어요."},{"n":27,"t":"사람들이 놀라며 말했어요. \\"이분은 도대체 어떤 분이시기에 바람과 바다도 그분의 말을 듣는 거야?\\""},{"n":28,"t":"예수님이 건너편 가다라 지방에 이르셨을 때, 무덤가에서 사는 귀신 들린 두 사람이 나와 예수님께 다가왔어요. 그들이 너무 사나워서 아무도 그 길로 다닐 수 없었어요."},{"n":29,"t":"그들이 소리쳤어요. \\"하나님의 아들이여, 우리와 무슨 상관이에요? 때가 되기도 전에 우리를 괴롭히려고 오셨어요?\\""},{"n":30,"t":"멀지 않은 곳에서 큰 돼지 떼가 풀을 뜯고 있었어요."},{"n":31,"t":"귀신들이 예수님께 간청했어요. \\"만약 우리를 쫓아내시려거든 저 돼지 떼 속으로 들어가게 해 주세요.\\""},{"n":32,"t":"예수님이 \\"가라\\" 하시자 귀신들이 나와 돼지 떼 속으로 들어갔어요. 그러자 돼지 떼가 비탈을 내달려 바다로 뛰어들어 다 빠져 죽었어요."},{"n":33,"t":"돼지를 치던 사람들이 도망쳐 마을로 들어가 모든 일과 귀신 들렸던 사람들에게 일어난 일을 다 전했어요."},{"n":34,"t":"온 마을 사람들이 예수님을 만나러 나왔어요. 그들은 예수님을 보고 자기들의 지역을 떠나 달라고 부탁했어요."}]}},{"chapter":9,"title":"죄 사하시고 죽은 자를 살리심","verses":{"krv":[{"n":1,"t":"예수께서 배에 오르사 건너가 본 동네에 이르시니"},{"n":2,"t":"침상에 누운 중풍병자를 사람들이 데리고 오거늘 예수께서 저희의 믿음을 보시고 중풍병자에게 이르시되 소자야 안심하라 네 죄 사함을 받았느니라"},{"n":3,"t":"어떤 서기관들이 속으로 이르되 이 사람이 참람하도다"},{"n":4,"t":"예수께서 그 생각을 아시고 가라사대 너희가 어찌하여 마음에 악한 생각을 하느냐"},{"n":5,"t":"네 죄 사함을 받았느니라 하는 말과 일어나 걸어가라 하는 말이 어느 것이 쉽겠느냐"},{"n":6,"t":"그러나 인자가 세상에서 죄를 사하는 권세가 있는 줄을 너희로 알게 하려 하노라 하시고 중풍병자에게 말씀하시되 일어나 네 침상을 가지고 집으로 가라 하시니"},{"n":7,"t":"그가 일어나 집으로 돌아가거늘"},{"n":8,"t":"무리가 보고 두려워하며 이런 권세를 사람에게 주신 하나님께 영광을 돌리니라"},{"n":9,"t":"예수께서 거기서 떠나 지나가시다가 마태라 하는 사람이 세관에 앉은 것을 보시고 이르시되 나를 좇으라 하시니 일어나 좇으니라"},{"n":10,"t":"예수께서 마태의 집에서 앉아 음식을 잡수실 때에 많은 세리와 죄인들이 와서 예수와 그 제자들과 함께 앉았더니"},{"n":11,"t":"바리새인들이 보고 그 제자들에게 이르되 어찌하여 너희 선생은 세리와 죄인들과 함께 잡수시느냐"},{"n":12,"t":"예수께서 들으시고 이르시되 건강한 자에게는 의원이 쓸데 없고 병든 자에게라야 쓸데 있느니라"},{"n":13,"t":"너희는 가서 내가 긍휼을 원하고 제사를 원치 아니하노라 하신 뜻이 무엇인지 배우라 내가 의인을 부르러 온 것이 아니요 죄인을 부르러 왔노라 하시니라"},{"n":14,"t":"그 때에 요한의 제자들이 예수께 나아와 가로되 우리와 바리새인들은 금식하는데 어찌하여 당신의 제자들은 금식하지 아니하나이까"},{"n":15,"t":"예수께서 저희에게 이르시되 혼인집 손님들이 신랑과 함께 있을 동안에 슬퍼할 수 있느뇨 그러나 신랑을 빼앗길 날이 이르리니 그 때에는 금식할 것이니라"},{"n":16,"t":"생베 조각을 낡은 옷에 붙이는 자가 없나니 이는 기운 것이 그 옷을 당기어 해어짐이 더하게 됨이요"},{"n":17,"t":"새 포도주를 낡은 가죽 부대에 넣지 아니하나니 그렇게 하면 부대가 터져 포도주도 쏟아지고 부대도 버리게 됨이라 새 포도주는 새 부대에 넣어야 둘이 다 보전되느니라"},{"n":18,"t":"예수께서 이 말씀을 하실 때에 한 직원이 와서 절하고 가로되 내 딸이 방장 죽었사 오나 오셔서 그 몸에 손을 얹으소서 그러면 살겠나이다 하니"},{"n":19,"t":"예수께서 일어나 따라 가시매 제자들도 가더니"},{"n":20,"t":"열 두 해를 혈루증으로 앓는 여자가 예수의 뒤로 와서 그 겉옷 가를 만지니"},{"n":21,"t":"이는 제 마음에 그 겉옷만 만져도 구원을 받겠다 함이라"},{"n":22,"t":"예수께서 돌이켜 그를 보시며 가라사대 딸아 안심하라 네 믿음이 너를 구원하였다 하시니 여자가 그 시로 구원을 받으니라"},{"n":23,"t":"예수께서 그 직원의 집에 가사 피리 부는 자들과 훤화하는 무리를 보시고"},{"n":24,"t":"가라사대 물러가라 이 소녀가 죽은 것이 아니라 잔다 하시니 저들이 비웃더라"},{"n":25,"t":"무리를 내어 보낸 후에 예수께서 들어가사 소녀의 손을 잡으시매 일어나는지라"},{"n":26,"t":"그 소문이 그 온 땅에 퍼지더라"},{"n":27,"t":"예수께서 거기서 떠나 가실쌔 두 소경이 따라 오며 소리질러 가로되 다윗의 자손이여 우리를 불쌍히 여기소서 하더니"},{"n":28,"t":"예수께서 집에 들어가시매 소경들이 나아오거늘 예수께서 이르시되 내가 능히 이 일 할 줄을 믿느냐 대답하되 주여 그러하오이다 하니"},{"n":29,"t":"이에 예수께서 저희 눈을 만지시며 가라사대 너희 믿음대로 되라 하신대"},{"n":30,"t":"그 눈들이 밝아진지라 예수께서 엄히 경계하시되 삼가 아무에게도 알게 하지 말라 하셨으나"},{"n":31,"t":"저희가 나가서 예수의 소문을 그 온 땅에 전파하니라"},{"n":32,"t":"저희가 나갈 때에 귀신 들려 벙어리 된 자를 예수께 데려오니"},{"n":33,"t":"귀신이 쫓겨나고 벙어리가 말하거늘 무리가 기이히 여겨 가로되 이스라엘 가운데서 이런 일을 본 때가 없다 하되"},{"n":34,"t":"바리새인들은 가로되 저가 귀신의 왕을 빙자하여 귀신을 쫓아낸다 하더라"},{"n":35,"t":"예수께서 모든 성과 촌에 두루 다니사 저희 회당에서 가르치시며 천국복음을 전파하시며 모든 병과 모든 약한 것을 고치시니라"},{"n":36,"t":"무리를 보시고 민망히 여기시니 이는 저희가 목자 없는 양과 같이 고생하며 유리함이라"},{"n":37,"t":"이에 제자들에게 이르시되 추수할 것은 많되 일군은 적으니"},{"n":38,"t":"그러므로 추수하는 주인에게 청하여 추수할 일군들을 보내어 주소서 하라 하시니라"}],"kids":[{"n":1,"t":"예수님이 배를 타고 호수를 건너 자기 동네로 돌아오셨어요."},{"n":2,"t":"그때 사람들이 침대에 누운 중풍 환자를 데리고 왔어요. 예수님은 그들의 믿음을 보시고 중풍 환자에게 말씀하셨어요. \\"얘야, 안심해라. 네 죄가 용서받았다.\\""},{"n":3,"t":"그러자 율법 학자 몇몇이 속으로 \'이 사람이 하나님을 모독하는구나\' 하고 생각했어요."},{"n":4,"t":"예수님이 그들의 생각을 아시고 말씀하셨어요. \\"왜 너희 마음에 악한 생각을 품니?\\""},{"n":5,"t":"\\"\'네 죄가 용서받았다\' 하는 것과 \'일어나서 걸어가라\' 하는 것 중에 어느 것이 더 쉽니?\\""},{"n":6,"t":"\\"하지만 너희가 사람의 아들이 땅에서 죄를 용서할 권세가 있는 줄을 알게 하겠다.\\" 그러고 중풍 환자에게 말씀하셨어요. \\"일어나 네 침대를 들고 집으로 가라.\\""},{"n":7,"t":"그 사람은 일어나 집으로 갔어요."},{"n":8,"t":"무리가 보고 두려워하며 사람에게 이런 권세를 주신 하나님께 영광을 돌렸어요."},{"n":9,"t":"예수님이 그곳을 지나가시다가 마태라는 사람이 세관에 앉아 있는 것을 보시고 \\"나를 따르라\\" 하셨어요. 마태가 일어나 예수님을 따랐어요."},{"n":10,"t":"예수님이 마태의 집에서 식사하실 때, 많은 세리와 죄인들이 와서 예수님과 제자들과 함께 앉았어요."},{"n":11,"t":"바리새인들이 그것을 보고 제자들에게 물었어요. \\"왜 너희 선생님은 세리와 죄인들과 함께 식사하니?\\""},{"n":12,"t":"예수님이 듣고 말씀하셨어요. \\"건강한 사람에게는 의사가 필요 없고 병든 사람에게 필요해.\\""},{"n":13,"t":"\\"가서 \'나는 자비를 원하고 제사는 원하지 않는다\'라는 말씀이 무슨 뜻인지 배워. 나는 의인을 부르러 온 게 아니라 죄인을 부르러 왔어.\\""},{"n":14,"t":"그때 요한의 제자들이 와서 물었어요. \\"우리와 바리새인들은 자주 금식하는데, 왜 주님의 제자들은 금식하지 않아요?\\""},{"n":15,"t":"예수님이 대답하셨어요. \\"신랑이 함께 있을 때 친구들이 슬퍼할 수 있겠니? 그러나 신랑을 빼앗길 날이 올 거야. 그때는 그들도 금식할 거야.\\""},{"n":16,"t":"\\"낡은 옷에 새 천 조각을 대고 깁는 사람은 없어. 새 천이 옷에서 떨어져 나가 찢어진 곳이 더 커져.\\""},{"n":17,"t":"\\"새 포도주를 낡은 가죽 주머니에 넣지도 않아. 그러면 주머니가 터져 포도주는 흘러 나오고 주머니도 못 쓰게 돼. 새 포도주는 새 주머니에 넣어. 그래야 둘 다 보존돼.\\""},{"n":18,"t":"예수님이 이런 말씀을 하고 계실 때, 한 회당장이 와서 절하며 말했어요. \\"제 딸이 방금 죽었어요. 하지만 주님이 와서 손을 얹어 주시면 살아날 거예요.\\""},{"n":19,"t":"예수님은 일어나 제자들과 함께 그 사람을 따라가셨어요."},{"n":20,"t":"그때 십이 년 동안 피를 흘리는 병으로 고생하던 한 여자가 예수님 뒤로 다가와 옷자락을 만졌어요."},{"n":21,"t":"그녀는 \'내가 그분의 옷자락만 만져도 나을 거야\' 하고 생각했거든요."},{"n":22,"t":"예수님이 돌아보고 그녀를 보시며 말씀하셨어요. \\"딸아, 안심해라. 네 믿음이 너를 구원했다.\\" 바로 그 시간에 그 여자가 나았어요."},{"n":23,"t":"예수님이 회당장의 집에 이르러 피리 부는 사람들과 시끄럽게 우는 사람들을 보시고,"},{"n":24,"t":"\\"물러가요. 아이가 죽은 게 아니라 자는 거예요\\" 하고 말씀하셨어요. 사람들이 비웃었어요."},{"n":25,"t":"무리를 내보내신 뒤에 들어가 아이의 손을 잡으시자, 아이가 일어났어요."},{"n":26,"t":"이 소문이 그 지역 전체에 퍼졌어요."},{"n":27,"t":"예수님이 거기서 가시는데 두 맹인이 따라오며 외쳤어요. \\"다윗의 아들이여, 우리를 불쌍히 여겨 주세요!\\""},{"n":28,"t":"예수님이 집에 들어가시자 그 맹인들이 와서 예수님 앞에 섰어요. 예수님이 물으셨어요. \\"내가 너희를 고칠 수 있다고 믿니?\\" 그들이 \\"예, 주님\\" 하고 대답했어요."},{"n":29,"t":"예수님이 그들의 눈을 만지며 말씀하셨어요. \\"너희 믿음대로 되어라.\\""},{"n":30,"t":"그러자 그들의 눈이 열렸어요. 예수님이 엄히 말씀하셨어요. \\"이 일을 아무에게도 알리지 마라.\\""},{"n":31,"t":"그런데 그들이 나가서 그 소문을 그 지역 곳곳에 퍼뜨렸어요."},{"n":32,"t":"그들이 나갈 때 사람들이 귀신 들려 말 못 하는 사람을 예수님께 데리고 왔어요."},{"n":33,"t":"귀신이 쫓겨나자 그가 말을 하게 됐어요. 무리가 놀라며 \\"이스라엘에서 이런 일은 본 적이 없다\\" 하고 말했어요."},{"n":34,"t":"그러나 바리새인들은 \\"그가 귀신의 우두머리를 통해 귀신을 쫓아낸다\\" 하고 비방했어요."},{"n":35,"t":"예수님은 모든 도시와 마을을 두루 다니시며 회당에서 가르치고 천국 복음을 전하시며 모든 병과 약함을 고쳐 주셨어요."},{"n":36,"t":"무리를 보시고 불쌍히 여기셨어요. 그들이 목자 없는 양처럼 지쳐 있었거든요."},{"n":37,"t":"예수님이 제자들에게 말씀하셨어요. \\"추수할 것은 많은데 일꾼이 적구나.\\""},{"n":38,"t":"\\"그러니까 추수의 주인께 일꾼을 보내 달라고 기도해.\\""}]}},{"chapter":10,"title":"열두 제자를 보내심","verses":{"krv":[{"n":1,"t":"예수께서 그 열 두 제자를 부르사 더러운 귀신을 쫓아내며 모든 병과 모든 약한 것을 고치는 권능을 주시니라"},{"n":2,"t":"열 두 사도의 이름은 이러하니 베드로라 하는 시몬을 비롯하여 그의 형제 안드레와 세베대의 아들 야고보와 그의 형제 요한,"},{"n":3,"t":"빌립과 바돌로매, 도마와 세리 마태, 알패오의 아들 야고보와 다대오,"},{"n":4,"t":"가나안인 시몬과 및 가룟 유다 곧 예수를 판 자라"},{"n":5,"t":"예수께서 이 열 둘을 내어 보내시며 명하여 가라사대 이방인의 길로도 가지 말고 사마리아인의 고을에도 들어가지 말고"},{"n":6,"t":"차라리 이스라엘 집의 잃어버린 양에게로 가라"},{"n":7,"t":"가면서 전파하여 말하되 천국이 가까왔다 하고"},{"n":8,"t":"병든 자를 고치며 죽은 자를 살리며 문둥이를 깨끗하게 하며 귀신을 쫓아내되 너희가 거저 받았으니 거저 주어라"},{"n":9,"t":"너희 전대에 금이나 은이나 동이나 가지지 말고"},{"n":10,"t":"여행을 위하여 주머니나 두 벌 옷이나 신이나 지팡이를 가지지 말라 이는 일군이 저 먹을것 받는 것이 마땅함이니라"},{"n":11,"t":"아무 성이나 촌에 들어가든지 그 중에 합당한 자를 찾아내어 너희 떠나기까지 거기서 머물라"},{"n":12,"t":"또 그 집에 들어가면서 평안하기를 빌라"},{"n":13,"t":"그 집이 이에 합당하면 너희 빈 평안이 거기 임할 것이요 만일 합당치 아니하면 그 평안이 너희에게 돌아올 것이니라"},{"n":14,"t":"누구든지 너희를 영접도 아니하고 너희 말을 듣지도 아니하거든 그 집이나 성에서 나가 너희 발의 먼지를 떨어 버리라"},{"n":15,"t":"내가 진실로 너희에게 이르노니 심판 날에 소돔과 고모라 땅이 그 성보다 견디기 쉬우리라"},{"n":16,"t":"보라 내가 너희를 보냄이 양을 이리 가운데 보냄과 같도다 그러므로 너희는 뱀 같이 지혜롭고 비둘기 같이 순결하라"},{"n":17,"t":"사람들을 삼가라 저희가 너희를 공회에 넘겨 주겠고 저희 회당에서 채찍질하리라"},{"n":18,"t":"또 너희가 나를 인하여 총독들과 임금들 앞에 끌려 가리니 이는 저희와 이방인들에게 증거가 되게 하려 하심이라"},{"n":19,"t":"너희를 넘겨줄 때에 어떻게 또는 무엇을 말할까 염려치 말라 그 때에 무슨 말할 것을 주시리니"},{"n":20,"t":"말하는 이는 너희가 아니라 너희 속에서 말씀하시는 자 곧 너희 아버지의 성령이시니라"},{"n":21,"t":"장차 형제가 형제를, 아비가 자식을 죽는데 내어주며 자식들이 부모를 대적하여 죽게 하리라"},{"n":22,"t":"또 너희가 내 이름을 인하여 모든 사람에게 미움을 받을 것이나 나중까지 견디는 자는 구원을 얻으리라"},{"n":23,"t":"이 동네에서 너희를 핍박하거든 저 동네로 피하라 내가 진실로 너희에게 이르노니 이스라엘의 모든 동네를 다 다니지 못하여서 인자가 오리라"},{"n":24,"t":"제자가 그 선생보다, 또는 종이 그 상전보다 높지 못하나니"},{"n":25,"t":"제자가 그 선생 같고 종이 그 상전 같으면 족하도다 집 주인을 바알세불이라 하였거든 하물며 그 집 사람들이랴"},{"n":26,"t":"그런즉 저희를 두려워하지 말라 감추인 것이 드러나지 않을 것이 없고 숨은 것이 알려지지 않을 것이 없느니라"},{"n":27,"t":"내가 너희에게 어두운데서 이르는 것을 광명한데서 말하며 너희가 귓속으로 듣는 것을 집 위에서 전파하라"},{"n":28,"t":"몸은 죽여도 영혼은 능히 죽이지 못하는 자들을 두려워하지 말고 오직 몸과 영혼을 능히 지옥에 멸하시는 자를 두려워하라"},{"n":29,"t":"참새 두 마리가 한 앗사리온에 팔리는 것이 아니냐 그러나 너희 아버지께서 허락지 아니하시면 그 하나라도 땅에 떨어지지 아니하리라"},{"n":30,"t":"너희에게는 머리털까지 다 세신바 되었나니"},{"n":31,"t":"두려워하지 말라 너희는 많은 참새보다 귀하니라"},{"n":32,"t":"누구든지 사람 앞에서 나를 시인하면 나도 하늘에 계신 내 아버지 앞에서 저를 시인할 것이요"},{"n":33,"t":"누구든지 사람 앞에서 나를 부인하면 나도 하늘에 계신 내 아버지 앞에서 저를 부인하리라"},{"n":34,"t":"내가 세상에 화평을 주러 온 줄로 생각지 말라 화평이 아니요 검을 주러 왔노라"},{"n":35,"t":"내가 온 것은 사람이 그 아비와, 딸이 어미와, 며느리가 시어미와 불화하게 하려 함이니"},{"n":36,"t":"사람의 원수가 자기 집안 식구리라"},{"n":37,"t":"아비나 어미를 나보다 더 사랑하는 자는 내게 합당치 아니하고 아들이나 딸을 나보다 더 사랑하는 자도 내게 합당치 아니하고"},{"n":38,"t":"또 자기 십자가를 지고 나를 좇지 않는 자도 내게 합당치 아니하니라"},{"n":39,"t":"자기 목숨을 얻는 자는 잃을 것이요 나를 위하여 자기 목숨을 잃는 자는 얻으리라"},{"n":40,"t":"너희를 영접하는 자는 나를 영접하는 것이요 나를 영접하는 자는 나 보내신 이를 영접하는 것이니라"},{"n":41,"t":"선지자의 이름으로 선지자를 영접하는 자는 선지자의 상을 받을 것이요 의인의 이름으로 의인을 영접하는 자는 의인의 상을 받을 것이요"},{"n":42,"t":"또 누구든지 제자의 이름으로 이 소자 중 하나에게 냉수 한 그릇이라도 주는 자는 내가 진실로 너희에게 이르노니 그 사람이 결단코 상을 잃지 아니하리라 하시니라"}],"kids":[{"n":1,"t":"예수님은 열두 제자를 부르시고 더러운 영을 쫓아내며 모든 병과 약함을 고치는 권능을 주셨어요."},{"n":2,"t":"열두 사도의 이름은 이래요. 첫째로 베드로라 하는 시몬과 그의 동생 안드레, 세베대의 아들 야고보와 그의 동생 요한,"},{"n":3,"t":"빌립과 바돌로매, 도마와 세리 마태, 알패오의 아들 야고보와 다대오,"},{"n":4,"t":"가나안 사람 시몬, 그리고 예수님을 배신한 가룟 유다예요."},{"n":5,"t":"예수님은 이 열둘을 내보내며 명령하셨어요. \\"이방인의 길로 가지 말고 사마리아 마을에도 들어가지 마라.\\""},{"n":6,"t":"\\"오히려 이스라엘 집의 잃어버린 양에게로 가라.\\""},{"n":7,"t":"\\"가면서 \'천국이 가까이 왔다\'고 전해.\\""},{"n":8,"t":"\\"병든 사람을 고치고 죽은 사람을 살리고 나병 환자를 깨끗이 하고 귀신을 쫓아내. 너희가 거저 받았으니 거저 줘.\\""},{"n":9,"t":"\\"돈주머니에 금이나 은이나 구리 돈도 가져가지 마.\\""},{"n":10,"t":"\\"여행 가방도, 옷 두 벌도, 신발도, 지팡이도 챙기지 마. 일꾼은 자기 양식을 받을 자격이 있어.\\""},{"n":11,"t":"\\"어느 동네나 마을에 들어가든 거기서 누가 받아 주는지 알아내서 떠날 때까지 그 집에 머물러.\\""},{"n":12,"t":"\\"그 집에 들어갈 때 평안을 빌어 줘.\\""},{"n":13,"t":"\\"그 집이 받을 만하면 평안이 그 집에 임하고, 받을 만하지 않으면 평안이 너희에게 돌아올 거야.\\""},{"n":14,"t":"\\"누구든 너희를 받지 않고 너희 말을 듣지 않거든 그 집이나 동네를 떠나면서 발의 먼지를 떨어 버려.\\""},{"n":15,"t":"\\"진정으로 말한다. 심판 날에 그 동네보다 소돔과 고모라가 더 견디기 쉬울 거야.\\""},{"n":16,"t":"\\"보라, 내가 너희를 양으로 늑대 가운데 보내. 그러니 뱀처럼 슬기롭고 비둘기처럼 순결해라.\\""},{"n":17,"t":"\\"사람들을 조심해. 그들이 너희를 공회에 넘기고 회당에서 채찍질할 거야.\\""},{"n":18,"t":"\\"또 나 때문에 총독들과 왕들 앞에 끌려가서 그들과 이방인들에게 증언하게 될 거야.\\""},{"n":19,"t":"\\"잡혀갈 때 어떻게 말할까 무엇을 말할까 걱정하지 마. 그 시간에 너희가 말할 것을 받게 돼.\\""},{"n":20,"t":"\\"말하는 이는 너희가 아니라 너희 안에서 말씀하시는 너희 아버지의 영이야.\\""},{"n":21,"t":"\\"형제가 형제를 죽이려고 넘기고, 아버지가 자식을, 자녀가 부모를 거슬러 일어나 죽게 할 거야.\\""},{"n":22,"t":"\\"내 이름 때문에 모든 사람에게 미움을 받겠지만 끝까지 견디는 사람은 구원받을 거야.\\""},{"n":23,"t":"\\"이 동네에서 박해받거든 다른 동네로 피해. 진정으로 말한다. 너희가 이스라엘 동네를 다 돌기 전에 사람의 아들이 올 거야.\\""},{"n":24,"t":"\\"제자는 선생보다 높지 않고 종은 주인보다 높지 않아.\\""},{"n":25,"t":"\\"제자가 자기 선생과 같고 종이 자기 주인과 같으면 그것으로 충분해. 집주인을 바알세불이라 했으니, 그 식구들에게는 얼마나 더 그러겠어!\\""},{"n":26,"t":"\\"그러니까 사람들을 두려워하지 마. 가려진 것은 드러나고 숨겨진 것은 알려질 거야.\\""},{"n":27,"t":"\\"내가 어두운 데서 너희에게 말하는 것을 너희는 밝은 데서 말하고, 너희가 귓속말로 들은 것을 지붕 위에서 외쳐.\\""},{"n":28,"t":"\\"몸은 죽일 수 있어도 영혼을 죽일 수 없는 사람들을 두려워하지 마. 오히려 몸과 영혼을 다 멸하실 수 있는 분을 두려워해.\\""},{"n":29,"t":"\\"참새 두 마리가 한 푼에 팔리지 않니? 그런데 너희 아버지께서 모르시면 그 한 마리도 땅에 떨어지지 않아.\\""},{"n":30,"t":"\\"너희 머리카락까지도 다 세어져 있어.\\""},{"n":31,"t":"\\"그러니까 두려워하지 마. 너희는 많은 참새보다 더 귀해.\\""},{"n":32,"t":"\\"누구든지 사람들 앞에서 나를 인정하면 나도 하늘에 계신 내 아버지 앞에서 그 사람을 인정할 거야.\\""},{"n":33,"t":"\\"그러나 누구든지 사람들 앞에서 나를 부인하면 나도 하늘에 계신 내 아버지 앞에서 그 사람을 부인할 거야.\\""},{"n":34,"t":"\\"내가 세상에 평화를 주러 왔다고 생각하지 마. 평화가 아니라 검을 주러 왔어.\\""},{"n":35,"t":"\\"내가 온 것은 사람을 자기 아버지와, 딸을 자기 어머니와, 며느리를 자기 시어머니와 갈라놓으려는 것이야.\\""},{"n":36,"t":"\\"사람의 원수가 자기 식구가 될 거야.\\""},{"n":37,"t":"\\"아버지나 어머니를 나보다 더 사랑하는 사람은 내게 적합하지 않고, 아들이나 딸을 나보다 더 사랑하는 사람도 내게 적합하지 않아.\\""},{"n":38,"t":"\\"자기 십자가를 지고 나를 따르지 않는 사람도 내게 적합하지 않아.\\""},{"n":39,"t":"\\"자기 목숨을 얻으려는 사람은 잃을 거고, 나를 위해 자기 목숨을 잃는 사람은 얻을 거야.\\""},{"n":40,"t":"\\"너희를 받는 사람은 나를 받는 거고, 나를 받는 사람은 나를 보내신 분을 받는 거야.\\""},{"n":41,"t":"\\"예언자를 예언자라고 받는 사람은 예언자의 상을 받고, 의인을 의인이라고 받는 사람은 의인의 상을 받을 거야.\\""},{"n":42,"t":"\\"누구든지 이 작은 사람 중 한 사람에게 제자라는 이름으로 시원한 물 한 잔이라도 주면, 진정으로 말한다. 그 사람은 결코 자기 상을 잃지 않을 거야.\\""}]}},{"chapter":11,"title":"세례 요한과 안식의 초대","verses":{"krv":[{"n":1,"t":"예수께서 열 두 제자에게 명하시기를 마치시고 이에 저희 여러 동리에서 가르치시며 전도하시려고 거기를 떠나 가시니라"},{"n":2,"t":"요한이 옥에서 그리스도의 하신 일을 듣고 제자들을 보내어"},{"n":3,"t":"예수께 여짜오되 오실 그이가 당신이오니이까 우리가 다른이를 기다리오리이까"},{"n":4,"t":"예수께서 대답하여 가라사대 너희가 가서 듣고 보는 것을 요한에게 고하되"},{"n":5,"t":"소경이 보며 앉은뱅이가 걸으며 문둥이가 깨끗함을 받으며 귀머거리가 들으며 죽은 자가 살아나며 가난한 자에게 복음이 전파된다 하라"},{"n":6,"t":"누구든지 나를 인하여 실족하지 아니하는 자는 복이 있도다 하시니라"},{"n":7,"t":"저희가 떠나매 예수께서 무리에게 요한에 대하여 말씀하시되 너희가 무엇을 보려고 광야에 나갔더냐 바람에 흔들리는 갈대냐"},{"n":8,"t":"그러면 너희가 무엇을 보려고 나갔더냐 부드러운 옷 입은 사람이냐 부드러운 옷을 입은 자들은 왕궁에 있느니라"},{"n":9,"t":"그러면 너희가 어찌하여 나갔더냐 선지자를 보려더냐 옳다 내가 너희에게 이르노니 선지자보다도 나은 자니라"},{"n":10,"t":"기록된바 보라 내가 내 사자를 네 앞에 보내노니 저가 네 길을 네 앞에 예비하리라 하신 것이 이 사람에 대한 말씀이니라"},{"n":11,"t":"내가 진실로 너희에게 말하노니 여자가 낳은 자 중에 세례요한보다 큰 이가 일어남이 없도다 그러나 천국에서는 극히 작은 자라도 저보다 크니라"},{"n":12,"t":"세례요한의 때부터 지금까지 천국은 침노를 당하나니 침노하는 자는 빼앗느니라"},{"n":13,"t":"모든 선지자와 및 율법의 예언한 것이 요한까지니"},{"n":14,"t":"만일 너희가 즐겨 받을진대 오리라 한 엘리야가 곧 이 사람이니라"},{"n":15,"t":"귀 있는 자는 들을지어다"},{"n":16,"t":"이 세대를 무엇으로 비유할꼬 비유컨대 아이들이 장터에 앉아 제 동무를 불러"},{"n":17,"t":"가로되 우리가 너희를 향하여 피리를 불어도 너희가 춤추지 않고 우리가 애곡하여도 너희가 가슴을 치지 아니하였다 함과 같도다"},{"n":18,"t":"요한이 와서 먹지도 않고 마시지도 아니하매 저희가 말하기를 귀신이 들렸다 하더니"},{"n":19,"t":"인자는 와서 먹고 마시매 말하기를 보라 먹기를 탐하고 포도주를 즐기는 사람이요 세리와 죄인의 친구로다 하니 지혜는 그 행한 일로 인하여 옳다 함을 얻느니라"},{"n":20,"t":"예수께서 권능을 가장 많이 베푸신 고을들이 회개치 아니하므로 그 때에 책망하시되"},{"n":21,"t":"화가 있을진저 고라신아 화가 있을진저 벳새다야 너희에게서 행한 모든 권능을 두로와 시돈에서 행하였더면 저희가 벌써 베옷을 입고 재에 앉아 회개하였으리라"},{"n":22,"t":"내가 너희에게 이르노니 심판 날에 두로와 시돈이 너희보다 견디기 쉬우리라"},{"n":23,"t":"가버나움아 네가 하늘에까지 높아지겠느냐 음부에까지 낮아지리라 네게서 행한 모든 권능을 소돔에서 행하였더면 그 성이 오늘날까지 있었으리라"},{"n":24,"t":"내가 너희에게 이르노니 심판 날에 소돔 땅이 너보다 견디기 쉬우리라 하시니라"},{"n":25,"t":"그 때에 예수께서 대답하여 가라사대 천지의 주재이신 아버지여 이것을 지혜롭고 슬기 있는 자들에게는 숨기시고 어린 아이들에게는 나타내심을 감사하나이다"},{"n":26,"t":"옳소이다 이렇게 된 것이 아버지의 뜻이니이다"},{"n":27,"t":"내 아버지께서 모든 것을 내게 주셨으니 아버지 외에는 아들을 아는 자가 없고 아들과 또 아들의 소원대로 계시를 받는 자 외에는 아버지를 아는 자가 없느니라"},{"n":28,"t":"수고하고 무거운 짐진 자들아 다 내게로 오라 내가 너희를 쉬게 하리라"},{"n":29,"t":"나는 마음이 온유하고 겸손하니 나의 멍에를 메고 내게 배우라 그러면 너희 마음이 쉼을 얻으리니"},{"n":30,"t":"이는 내 멍에는 쉽고 내 짐은 가벼움이라 하시니라"}],"kids":[{"n":1,"t":"예수님이 열두 제자에게 명령하기를 마치신 후, 그곳을 떠나 여러 동네를 다니며 가르치고 전하셨어요."},{"n":2,"t":"요한은 감옥에서 그리스도가 하시는 일을 듣고 자기 제자들을 보내,"},{"n":3,"t":"\\"오실 그분이 당신이신가요, 아니면 우리가 다른 분을 기다려야 하나요?\\" 하고 물었어요."},{"n":4,"t":"예수님이 대답하셨어요. \\"가서 너희가 듣고 보는 것을 요한에게 전해.\\""},{"n":5,"t":"\\"맹인이 보고 다리 저는 사람이 걷고 나병 환자가 깨끗이 되고 귀머거리가 듣고 죽은 사람이 살아나고 가난한 사람에게 복음이 전해져.\\""},{"n":6,"t":"\\"나 때문에 걸려 넘어지지 않는 사람은 복이 있다.\\""},{"n":7,"t":"그들이 돌아갈 때 예수님이 무리에게 요한에 대해 말씀하기 시작하셨어요. \\"너희가 무엇을 보러 광야에 갔니? 바람에 흔들리는 갈대였니?\\""},{"n":8,"t":"\\"그러면 무엇을 보러 갔니? 좋은 옷을 입은 사람이었니? 좋은 옷을 입은 사람은 왕궁에 있잖아.\\""},{"n":9,"t":"\\"그러면 무엇을 보러 갔니? 예언자였니? 그래, 내가 너희에게 말한다. 예언자보다 더 큰 사람이야.\\""},{"n":10,"t":"\\"이 사람은 \'보라, 내가 내 사자를 네 앞에 보낸다. 그가 네 앞에서 네 길을 예비할 거야\'라고 기록된 사람이야.\\""},{"n":11,"t":"\\"진정으로 말한다. 여자가 낳은 사람 가운데 세례 요한보다 큰 사람이 없었어. 그러나 천국에서는 가장 작은 사람이 그보다 커.\\""},{"n":12,"t":"\\"세례 요한의 때부터 지금까지 천국은 침노를 당하고 침노하는 사람들이 그것을 빼앗아.\\""},{"n":13,"t":"\\"모든 예언자와 율법이 요한까지 예언했어.\\""},{"n":14,"t":"\\"너희가 받아들이려 한다면, 와야 할 그 엘리야가 바로 이 사람이야.\\""},{"n":15,"t":"\\"귀 있는 사람은 들어라.\\""},{"n":16,"t":"\\"이 세대를 무엇에 비유할까? 마치 시장에 앉아 다른 친구들에게 외치는 아이들과 같아.\\""},{"n":17,"t":"\\"우리가 피리를 불었는데 너희가 춤추지 않았고, 우리가 슬픈 노래를 불렀는데 너희가 가슴을 치며 울지 않았다.\\""},{"n":18,"t":"\\"요한이 와서 먹지도 마시지도 않으니 사람들이 \'귀신 들렸다\' 하고,\\""},{"n":19,"t":"\\"사람의 아들이 와서 먹고 마시니 \'먹기를 좋아하고 술 마시기를 좋아하는 사람, 세리와 죄인의 친구다\' 해. 그러나 지혜는 그 행한 일로 옳다는 것을 증명해.\\""},{"n":20,"t":"그때 예수님이 자기의 많은 능력이 나타났는데도 회개하지 않은 도시들을 꾸짖기 시작하셨어요."},{"n":21,"t":"\\"화 있을 거야, 고라신아! 화 있을 거야, 벳새다야! 너희에게 행한 능력이 두로와 시돈에서 일어났더라면 그들이 벌써 베옷을 입고 재를 뒤집어쓰고 회개했을 거야.\\""},{"n":22,"t":"\\"내가 너희에게 말한다. 심판 날에 너희보다 두로와 시돈이 더 견디기 쉬울 거야.\\""},{"n":23,"t":"\\"너 가버나움아, 하늘까지 높아지겠니? 음부까지 낮아질 거야. 너에게 행한 능력이 소돔에서 일어났더라면 그 도시는 오늘까지 남아 있었을 거야.\\""},{"n":24,"t":"\\"내가 너에게 말한다. 심판 날에 너보다 소돔 땅이 더 견디기 쉬울 거야.\\""},{"n":25,"t":"그때 예수님이 말씀하셨어요. \\"하늘과 땅의 주인이신 아버지, 이 일을 지혜롭고 슬기로운 사람에게는 숨기시고 어린아이들에게는 나타내신 것을 감사드려요.\\""},{"n":26,"t":"\\"예, 아버지, 이것이 아버지의 뜻이었어요.\\""},{"n":27,"t":"\\"내 아버지께서 모든 것을 내게 주셨어. 아버지 외에는 아들을 아는 사람이 없고, 아들과 아들이 알려 주려는 사람 외에는 아버지를 아는 사람이 없어.\\""},{"n":28,"t":"\\"수고하고 무거운 짐을 진 사람들아, 다 내게로 와. 내가 너희를 쉬게 할게.\\""},{"n":29,"t":"\\"소가 멍에를 메고 밭을 갈듯이, 너희도 내 멍에를 메고 내게서 배워. 나는 마음이 온유하고 겸손하니 너희 영혼이 쉼을 얻을 거야.\\""},{"n":30,"t":"\\"내 멍에는 편하고 내 짐은 가벼워.\\""}]}},{"chapter":12,"title":"안식일의 주인이신 예수님","verses":{"krv":[{"n":1,"t":"그 때에 예수께서 안식일에 밀밭사이로 가실쌔 제자들이 시장하여 이삭을 잘라 먹으니"},{"n":2,"t":"바리새인들이 보고 예수께 고하되 보시오 당신의 제자들이 안식일에 하지 못할 일을 하나이다"},{"n":3,"t":"예수께서 가라사대 다윗이 자기와 그 함께한 자들이 시장할 때에 한 일을 읽지 못하였느냐"},{"n":4,"t":"그가 하나님의 전에 들어가서 제사장 외에는 자기나 그 함께한 자들이 먹지 못하는 진설병을 먹지 아니하였느냐"},{"n":5,"t":"또 안식일에 제사장들이 성전 안에서 안식을 범하여도 죄가 없음을 너희가 율법에서 읽지 못하였느냐"},{"n":6,"t":"내가 너희에게 이르노니 성전보다 더 큰 이가 여기 있느니라"},{"n":7,"t":"나는 자비를 원하고 제사를 원치 아니하노라 하신 뜻을 너희가 알았더면 무죄한 자를 죄로 정치 아니하였으리라"},{"n":8,"t":"인자는 안식일의 주인이니라 하시니라"},{"n":9,"t":"거기를 떠나 저희 회당에 들어가시니"},{"n":10,"t":"한편 손 마른 사람이 있는지라 사람들이 예수를 송사하려 하여 물어 가로되 안식일에 병 고치는 것이 옳으니이까"},{"n":11,"t":"예수께서 가라사대 너희 중에 어느 사람이 양 한 마리가 있어 안식일에 구덩이에 빠졌으면 붙잡아 내지 않겠느냐"},{"n":12,"t":"사람이 양보다 얼마나 더 귀하냐 그러므로 안식일에 선을 행하는것이 옳으니라 하시고"},{"n":13,"t":"이에 그 사람에게 이르시되 손을 내밀라 하시니 저가 내밀매 다른 손과 같이 회복되어 성하더라"},{"n":14,"t":"바리새인들이 나가서 어떻게 하여 예수를 죽일꼬 의논하거늘"},{"n":15,"t":"예수께서 아시고 거기를 떠나가시니 사람이 많이 좇는지라 예수께서 저희 병을 다 고치시고"},{"n":16,"t":"자기를 나타내지 말라 경계하셨으니"},{"n":17,"t":"이는 선지자 이사야로 말씀하신바"},{"n":18,"t":"보라 나의 택한 종 곧 내 마음에 기뻐하는 바 나의 사랑하는 자로다 내가 내 성령을 줄터이니 그가 심판을 이방에 알게 하리라"},{"n":19,"t":"그가 다투지도 아니하며 들레지도 아니하리니 아무도 길에서 그 소리를 듣지 못하리라"},{"n":20,"t":"상한 갈대를 꺾지 아니하며 꺼져가는 심지를 끄지 아니하기를 심판하여 이길 때까지 하리니"},{"n":21,"t":"또한 이방들이 그 이름을 바라리라 함을 이루려 하심이니라"},{"n":22,"t":"그 때에 귀신들려 눈 멀고 벙어리 된 자를 데리고 왔거늘 예수께서 고쳐 주시매 그 벙어리가 말하며 보게 된지라"},{"n":23,"t":"무리가 다 놀라 가로되 이는 다윗의 자손이 아니냐 하니"},{"n":24,"t":"바리새인들은 듣고 가로되 이가 귀신의 왕 바알세불을 힘입지 않고는 귀신을 쫓아 내지 못하느니라 하거늘"},{"n":25,"t":"예수께서 저희 생각을 아시고 가라사대 스스로 분쟁하는 나라마다 황폐하여질 것이요 스스로 분쟁하는 동리나 집마다 서지 못하리라"},{"n":26,"t":"사단이 만일 사단을 쫓아내면 스스로 분쟁하는 것이니 그리하고야 저의 나라가 어떻게 서겠느냐"},{"n":27,"t":"또 내가 바알세불을 힘입어 귀신을 쫓아 내면 너희 아들들은 누구를 힘입어 쫓아내느냐 그러므로 저희가 너희 재판관이 되리라"},{"n":28,"t":"그러나 내가 하나님의 성령을 힘입어 귀신을 쫓아내는것이면 하나님의 나라가 이미 너희에게 임하였느니라"},{"n":29,"t":"사람이 먼저 강한 자를 결박하지 않고야 어떻게 그 강한 자의 집에 들어가 그 세간을 늑탈하겠느냐 결박한 후에야 그 집을 늑탈하리라"},{"n":30,"t":"나와 함께 아니하는 자는 나를 반대하는 자요 나와 함께 모으지 아니하는 자는 헤치는 자니라"},{"n":31,"t":"그러므로 내가 너희에게 이르노니 사람의 모든 죄와 훼방은 사하심을 얻되 성령을 훼방하는 것은 사하심을 얻지 못하겠고"},{"n":32,"t":"또 누구든지 말로 인자를 거역하면 사하심을 얻되 누구든지 말로 성령을 거역하면 이 세상과 오는 세상에도 사하심을 얻지 못하리라"},{"n":33,"t":"나무도 좋고 실과도 좋다 하든지 나무도 좋지 않고 실과도 좋지 않다 하든지 하라 그 실과로 나무를 아느니라"},{"n":34,"t":"독사의 자식들아 너희는 악하니 어떻게 선한 말을 할 수 있느냐 이는 마음에 가득한 것을 입으로 말함이라"},{"n":35,"t":"선한 사람은 그 쌓은 선에서 선한 것을 내고 악한 사람은 그 쌓은 악에서 악한 것을 내느니라"},{"n":36,"t":"내가 너희에게 이르노니 사람이 무슨 무익한 말을 하든지 심판 날에 이에 대하여 심문을 받으리니"},{"n":37,"t":"네 말로 의롭다 함을 받고 네 말로 정죄함을 받으리라"},{"n":38,"t":"그 때에 서기관과 바리새인 중 몇 사람이 말하되 선생님이여 우리에게 표적 보여주시기를 원하나이다"},{"n":39,"t":"예수께서 대답하여 가라사대 악하고 음란한 세대가 표적을 구하나 선지자 요나의 표적 밖에는 보일 표적이 없느니라"},{"n":40,"t":"요나가 밤낮 사흘을 큰 물고기 뱃속에 있었던것같이 인자도 밤낮 사흘을 땅 속에 있으리라"},{"n":41,"t":"심판 때에 니느웨 사람들이 일어나 이 세대 사람을 정죄하리니 이는 그들이 요나의 전도를 듣고 회개하였음이어니와 요나보다 더 큰 이가 여기 있으며"},{"n":42,"t":"심판 때에 남방 여왕이 일어나 이 세대 사람을 정죄하리니 이는 그가 솔로몬의 지혜로운 말을 들으려고 땅 끝에서 왔음이어니와 솔로몬보다 더 큰이가 여기있느니라"},{"n":43,"t":"더러운 귀신이 사람에게서 나갔을 때에 물 없는 곳으로 다니며 쉬기를 구하되 얻지 못하고"},{"n":44,"t":"이에 가로되 내가 나온 내 집으로 돌아가리라 하고 와 보니 그 집이 비고 소제되고 수리 되었거늘"},{"n":45,"t":"이에 가서 저보다 더 악한 귀신 일곱을 데리고 들어가서 거하니 그 사람의 나중 형편이 전보다 더욱 심하게 되느니라 이 악한 세대가 또한 이렇게 되리라"},{"n":46,"t":"예수께서 무리에게 말씀하실 때에 그 모친과 동생들이 예수께 말하려고 밖에 섰더니"},{"n":47,"t":"한사람이 예수께 여짜오되 보소서 당신의 모친과 동생들이 당신께 말하려고 밖에 섰나이다 하니"},{"n":48,"t":"말하던 사람에게 대답하여 가라사대 누가 내 모친이며 내 동생들이냐 하시고"},{"n":49,"t":"손을 내밀어 제자들을 가리켜 가라사대 나의 모친과 나의 동생들을 보라"},{"n":50,"t":"누구든지 하늘에 계신 내 아버지의 뜻대로 하는 자가 내 형제요 자매요 모친이니라 하시더라"}],"kids":[{"n":1,"t":"그 무렵 안식일에 예수님이 밀밭을 지나가실 때 제자들이 배가 고파서 이삭을 잘라 먹기 시작했어요."},{"n":2,"t":"바리새인들이 보고 말했어요. \\"보세요, 주님의 제자들이 안식일에 해서는 안 될 일을 하고 있어요.\\""},{"n":3,"t":"예수님이 대답하셨어요. \\"다윗과 그 일행이 배고팠을 때 무엇을 했는지 너희가 읽어 보지 않았니?\\""},{"n":4,"t":"\\"그가 하나님의 집에 들어가 제사장들 외에는 먹어서는 안 되는 진설병을 먹지 않았니?\\""},{"n":5,"t":"\\"또 율법에 제사장들이 안식일에 성전에서 안식일을 어겨도 죄가 없다는 걸 너희가 읽어 보지 않았니?\\""},{"n":6,"t":"\\"내가 너희에게 말한다. 여기 성전보다 더 큰 분이 있다.\\""},{"n":7,"t":"\\"\'나는 자비를 원하고 제사를 원치 않는다\'는 말의 뜻을 너희가 알았더라면 죄 없는 사람을 정죄하지 않았을 거야.\\""},{"n":8,"t":"\\"사람의 아들은 안식일의 주인이다.\\""},{"n":9,"t":"예수님이 그곳을 떠나 그들의 회당에 들어가셨어요."},{"n":10,"t":"거기에 한쪽 손이 마른 사람이 있었어요. 사람들이 예수님을 고소할 거리를 찾으려고 \\"안식일에 병을 고치는 게 합법인가요?\\" 하고 물었어요."},{"n":11,"t":"예수님이 말씀하셨어요. \\"너희 중에 누가 양 한 마리를 가졌는데 안식일에 그것이 구덩이에 빠지면 잡아서 끌어내지 않겠니?\\""},{"n":12,"t":"\\"사람이 양보다 얼마나 더 귀하니! 그러니까 안식일에 좋은 일을 하는 것은 합법이야.\\""},{"n":13,"t":"그러고 그 사람에게 \\"손을 펴라\\" 하셨어요. 그가 손을 펴자 다른 손처럼 완전해졌어요."},{"n":14,"t":"바리새인들이 나가서 어떻게 예수님을 죽일까 의논했어요."},{"n":15,"t":"예수님이 그것을 아시고 그곳을 떠나셨어요. 많은 사람들이 그분을 따랐는데 다 고쳐 주셨어요."},{"n":16,"t":"그리고 자기를 알리지 말라고 엄히 명령하셨어요."},{"n":17,"t":"이는 예언자 이사야의 말이 이루어진 거예요."},{"n":18,"t":"\\"보라, 내가 택한 내 종이다. 내 마음에 기뻐하는 내 사랑하는 자다. 내가 내 영을 그에게 줄 거고 그가 이방인들에게 정의를 알릴 거야.\\""},{"n":19,"t":"\\"그는 다투지 않고 외치지도 않으며 거리에서 그의 소리를 들을 사람이 없을 거야.\\""},{"n":20,"t":"\\"그는 상한 갈대를 꺾지 않고 꺼져 가는 심지를 끄지 않으며, 마침내 정의를 이길 때까지 행할 거야.\\""},{"n":21,"t":"\\"이방인들이 그 이름에 소망을 둘 거야.\\""},{"n":22,"t":"사람들이 귀신 들려 눈멀고 말 못하는 사람을 예수님께 데리고 왔어요. 예수님이 고쳐 주시자 그 사람이 말도 하고 보기도 했어요."},{"n":23,"t":"모든 무리가 놀라며 \\"이 사람이 혹시 다윗의 자손이 아닌가?\\" 하고 말했어요."},{"n":24,"t":"바리새인들이 듣고 \\"이 사람이 귀신의 우두머리 바알세불의 힘이 아니면 귀신을 쫓아내지 못해\\" 하고 말했어요."},{"n":25,"t":"예수님이 그들의 생각을 아시고 말씀하셨어요. \\"스스로 분쟁하는 나라마다 망하고, 스스로 분쟁하는 도시나 집은 서지 못해.\\""},{"n":26,"t":"\\"사탄이 사탄을 쫓아내면 스스로 분쟁하는 거니까 그 나라가 어떻게 서겠어?\\""},{"n":27,"t":"\\"내가 바알세불의 힘으로 귀신을 쫓아낸다면 너희 아들들은 누구의 힘으로 쫓아내니? 그러니까 그들이 너희 재판관이 될 거야.\\""},{"n":28,"t":"\\"하지만 내가 하나님의 영으로 귀신을 쫓아낸다면 하나님의 나라가 너희에게 임한 거야.\\""},{"n":29,"t":"\\"누가 강한 사람의 집에 들어가 그의 물건을 빼앗으려면 먼저 그를 묶지 않고 어떻게 그렇게 할 수 있겠니? 묶고 나서야 그 집을 털 수 있어.\\""},{"n":30,"t":"\\"나와 함께 하지 않는 사람은 나를 반대하는 사람이고, 나와 함께 모으지 않는 사람은 흩어 버리는 사람이야.\\""},{"n":31,"t":"\\"내가 너희에게 말한다. 사람의 모든 죄와 모독은 용서받을 수 있지만 성령을 모독하는 죄는 용서받지 못해.\\""},{"n":32,"t":"\\"누구든지 사람의 아들을 거슬러 말하면 용서받지만, 성령을 거슬러 말하면 이 세상이나 오는 세상에서도 용서받지 못해.\\""},{"n":33,"t":"\\"나무를 좋다 하면 열매도 좋다 하고, 나무를 못쓰겠다 하면 열매도 못쓰겠다고 해. 열매를 보고 나무를 알 수 있어.\\""},{"n":34,"t":"\\"독사의 자식들아, 너희가 악하면서 어떻게 좋은 말을 할 수 있겠니? 마음에 가득한 것을 입으로 말하는 거야.\\""},{"n":35,"t":"\\"선한 사람은 선한 창고에서 선한 것을 내고 악한 사람은 악한 창고에서 악한 것을 내.\\""},{"n":36,"t":"\\"내가 너희에게 말한다. 사람이 말하는 모든 무익한 말마다 심판 날에 책임을 져야 해.\\""},{"n":37,"t":"\\"네 말로 의롭다 함을 받고, 네 말로 죄가 있다 함을 받을 거야.\\""},{"n":38,"t":"그때 율법 학자와 바리새인 몇 사람이 말했어요. \\"선생님, 우리는 주님에게서 표적을 보고 싶어요.\\""},{"n":39,"t":"예수님이 대답하셨어요. \\"악하고 음란한 세대가 표적을 구하는구나. 그러나 예언자 요나의 표적 외에는 표적을 받지 못할 거야.\\""},{"n":40,"t":"\\"요나가 큰 물고기 뱃속에서 사흘 밤낮을 보낸 것처럼, 사람의 아들도 땅속에서 사흘 밤낮을 보낼 거야.\\""},{"n":41,"t":"\\"심판 때에 니느웨 사람들이 일어나 이 세대를 정죄할 거야. 그들은 요나의 전도에 회개했거든. 그런데 요나보다 더 큰 분이 여기 있어.\\""},{"n":42,"t":"\\"심판 때에 남방 여왕이 일어나 이 세대를 정죄할 거야. 그녀는 솔로몬의 지혜를 들으러 땅끝에서 왔거든. 그런데 솔로몬보다 더 큰 분이 여기 있어.\\""},{"n":43,"t":"\\"더러운 영이 사람에게서 나가면 물 없는 곳을 돌아다니며 쉴 곳을 찾는데, 찾지 못해.\\""},{"n":44,"t":"\\"그러면 \'내가 나왔던 내 집으로 돌아갈 거야\' 하고는, 와서 비어 있고 청소되어 정돈된 것을 봐.\\""},{"n":45,"t":"\\"그러고 가서 자기보다 더 악한 영 일곱을 데려와 들어가 살아. 그래서 그 사람의 나중 형편이 처음보다 더 나빠져. 이 악한 세대도 그렇게 될 거야.\\""},{"n":46,"t":"예수님이 무리에게 말씀하고 계실 때, 어머니와 형제들이 예수님께 말하려고 밖에 서 있었어요."},{"n":47,"t":"누군가 예수님께 \\"어머니와 형제들이 밖에 서서 주님과 말하기를 원해요\\" 하고 알렸어요."},{"n":48,"t":"예수님이 대답하셨어요. \\"누가 내 어머니며 누가 내 형제들이지?\\""},{"n":49,"t":"그러고 손을 펴서 제자들을 가리키며 말씀하셨어요. \\"보라, 내 어머니와 내 형제들이다.\\""},{"n":50,"t":"\\"누구든지 하늘에 계신 내 아버지의 뜻을 행하는 사람이 내 형제고 자매고 어머니다.\\""}]}},{"chapter":13,"title":"천국 비유 일곱 가지","verses":{"krv":[{"n":1,"t":"그 날에 예수께서 집에서 나가사 바닷가에 앉으시매"},{"n":2,"t":"큰 무리가 그에게로 모여 들거늘 예수께서 배에 올라가 앉으시고 온 무리는 해변에 섰더니"},{"n":3,"t":"예수께서 비유로 여러가지를 저희에게 말씀하여 가라사대 씨를 뿌리는 자가 뿌리러 나가서"},{"n":4,"t":"뿌릴쌔 더러는 길 가에 떨어지매 새들이 와서 먹어버렸고"},{"n":5,"t":"더러는 흙이 얇은 돌밭에 떨어지매 흙이 깊지 아니하므로 곧 싹이 나오나"},{"n":6,"t":"해가 돋은 후에 타져서 뿌리가 없으므로 말랐고"},{"n":7,"t":"더러는 가시떨기 위에 떨어지매 가시가 자라서 기운을 막았고"},{"n":8,"t":"더러는 좋은 땅에 떨어지매 혹 백배, 혹 육십배, 혹 삼십배의 결실을 하였느니라"},{"n":9,"t":"귀 있는 자는 들으라 하시니라"},{"n":10,"t":"제자들이 예수께 나아와 가로되 어찌하여 저희에게 비유로 말씀하시나이까"},{"n":11,"t":"대답하여 가라사대 천국의 비밀을 아는 것이 너희에게는 허락되었으나 저희에게는 아니 되었나니"},{"n":12,"t":"무릇 있는 자는 받아 넉넉하게 되되 무릇 없는 자는 그 있는 것도 빼앗기리라"},{"n":13,"t":"그러므로 내가 저희에게 비유로 말하기는 저희가 보아도 보지 못하며 들어도 듣지 못하며 깨닫지 못함이니라"},{"n":14,"t":"이사야의 예언이 저희에게 이루었으니 일렀으되 너희가 듣기는 들어도 깨닫지 못할 것이요 보기는 보아도 알지 못하리라"},{"n":15,"t":"이 백성들의 마음이 완악하여져서 그 귀는 듣기에 둔하고 눈은 감았으니 이는 눈으로 보고 귀로 듣고 마음으로 깨달아 돌이켜 내게 고침을 받을까 두려워함이라 하였느니라"},{"n":16,"t":"그러나 너희 눈은 봄으로 너희 귀는 들음으로 복이 있도다"},{"n":17,"t":"내가 진실로 너희에게 이르노니 많은 선지자와 의인이 너희 보는 것들을 보고자 하여도 보지 못하였고 너희 듣는 것들을 듣고자 하여도 듣지 못하였느니라"},{"n":18,"t":"그런즉 씨 뿌리는 비유를 들으라"},{"n":19,"t":"아무나 천국 말씀을 듣고 깨닫지 못할 때는 악한 자가 와서 그 마음에 뿌리운 것을 빼앗나니 이는 곧 길가에 뿌리운 자요"},{"n":20,"t":"돌밭에 뿌리웠다는 것은 말씀을 듣고 즉시 기쁨으로 받되"},{"n":21,"t":"그 속에 뿌리가 없어 잠시 견디다가 말씀을 인하여 환난이나 핍박이 일어나는 때에는 곧 넘어지는 자요"},{"n":22,"t":"가시떨기에 뿌리웠다는 것은 말씀을 들으나 세상의 염려와 재리의 유혹에 말씀이 막혀 결실치 못하는 자요"},{"n":23,"t":"좋은 땅에 뿌리웠다는 것은 말씀을 듣고 깨닫는 자니 결실하여 혹 백배, 혹 육십배, 혹 삼십배가 되느니라 하시더라"},{"n":24,"t":"예수께서 그들 앞에 또 비유를 베풀어 가라사대 천국은 좋은 씨를 제 밭에 뿌린 사람과 같으니"},{"n":25,"t":"사람들이 잘 때에 그 원수가 와서 곡식 가운데 가라지를 덧뿌리고 갔더니"},{"n":26,"t":"싹이 나고 결실할 때에 가라지도 보이거늘"},{"n":27,"t":"집 주인의 종들이 와서 말하되 주여 밭에 좋은 씨를 심지 아니하였나이까 그러면 가라지가 어디서 생겼나이까"},{"n":28,"t":"주인이 가로되 원수가 이렇게 하였구나 종들이 말하되 그러면 우리가 가서 이것을 뽑기를 원하시나이까"},{"n":29,"t":"주인이 가로되 가만 두어라 가라지를 뽑다가 곡식까지 뽑을까 염려하노라"},{"n":30,"t":"둘 다 추수 때까지 함께 자라게 두어라 추수 때에 내가 추숫군들에게 말하기를 가라지는 먼저 거두어 불사르게 단으로 묶고 곡식은 모아 내 곳간에 넣으라 하리라"},{"n":31,"t":"또 비유를 베풀어 가라사대 천국은 마치 사람이 자기 밭에 갖다 심은 겨자씨 한 알 같으니"},{"n":32,"t":"이는 모든 씨보다 작은 것이로되 자란 후에는 나물보다 커서 나무가 되매 공중의 새들이 와서 그 가지에 깃들이느니라"},{"n":33,"t":"또 비유로 말씀하시되 천국은 마치 여자가 가루 서말 속에 갖다 넣어 전부 부풀게 한 누룩과 같으니라"},{"n":34,"t":"예수께서 이 모든 것을 무리에게 비유로 말씀하시고 비유가 아니면 아무 것도 말씀하지 아니하셨으니"},{"n":35,"t":"이는 선지자로 말씀하신바 내가 입을 열어 비유로 말하고 창세부터 감추인 것들을 드러내리라 함을 이루려 하심이니라"},{"n":36,"t":"이에 예수께서 무리를 떠나사 집에 들어가시니 제자들이 나아와 가로되 밭의 가라지의 비유를 우리에게 설명하여 주소서"},{"n":37,"t":"대답하여 가라사대 좋은 씨를 뿌리는 이는 인자요"},{"n":38,"t":"밭은 세상이요 좋은 씨는 천국의 아들들이요 가라지는 악한 자의 아들들이요"},{"n":39,"t":"가라지를 심은 원수는 마귀요 추수때는 세상 끝이요 추숫군은 천사들이니"},{"n":40,"t":"그런즉 가라지를 거두어 불에 사르는것같이 세상끝에도 그러하리라"},{"n":41,"t":"인자가 그 천사들을 보내리니 저희가 그 나라에서 모든 넘어지게 하는 것과 또 불법을 행하는 자들을 거두어 내어"},{"n":42,"t":"풀무불에 던져 넣으리니 거기서 울며 이를 갊이 있으리라"},{"n":43,"t":"그 때에 의인들은 자기 아버지 나라에서 해와 같이 빛나리라 귀 있는 자는 들으라"},{"n":44,"t":"천국은 마치 밭에 감추인 보화와 같으니 사람이 이를 발견한 후 숨겨 두고 기뻐하여 돌아가서 자기의 소유를 다 팔아 그 밭을 샀느니라"},{"n":45,"t":"또 천국은 마치 좋은 진주를 구하는 장사와 같으니"},{"n":46,"t":"극히 값진 진주 하나를 만나매 가서 자기의 소유를 다 팔아 그 진주를 샀느니라"},{"n":47,"t":"또 천국은 마치 바다에 치고 각종 물고기를 모는 그물과 같으니"},{"n":48,"t":"그물에 가득하매 물 가로 끌어 내고 앉아서 좋은 것은 그릇에 담고 못된 것은 내어 버리느니라"},{"n":49,"t":"세상 끝에도 이러하리라 천사들이 와서 의인 중에서 악인을 갈라 내어"},{"n":50,"t":"풀무불에 던져 넣으리니 거기서 울며 이를 갊이 있으리라"},{"n":51,"t":"이 모든 것을 깨달았느냐 하시니 대답하되 그러하오이다"},{"n":52,"t":"예수께서 가라사대 그러므로 천국의 제자된 서기관마다 마치 새것과 옛것을 그 곳간에서 내어오는 집주인과 같으니라"},{"n":53,"t":"예수께서 이 모든 비유를 마치신 후에 거기를 떠나서"},{"n":54,"t":"고향으로 돌아가사 저희 회당에서 가르치시니 저희가 놀라 가로되 이 사람의 이 지혜와 이런 능력이 어디서 났느뇨"},{"n":55,"t":"이는 그 목수의 아들이 아니냐 그 모친은 마리아, 그 형제들은 야고보, 요셉, 시몬, 유다라 하지 않느냐"},{"n":56,"t":"그 누이들은 다 우리와 함께 있지 아니하냐 그런즉 이 사람의 이 모든 것이 어디서 났느뇨 하고"},{"n":57,"t":"예수를 배척한지라 예수께서 저희에게 말씀하시되 선지자가 자기 고향과 자기 집 외에서는 존경을 받지 않음이 없느니라 하시고"},{"n":58,"t":"저희의 믿지 않음을 인하여 거기서 많은 능력을 행치 아니하시니라"}],"kids":[{"n":1,"t":"그날 예수님이 집에서 나가 호숫가에 앉으셨어요."},{"n":2,"t":"큰 무리가 모여 와서 예수님은 배에 들어가 앉으셨고, 모든 무리는 해변에 서 있었어요."},{"n":3,"t":"예수님은 여러 가지 비유로 그들에게 많은 것을 가르치셨어요. \\"한 농부가 씨를 뿌리러 나갔어요.\\""},{"n":4,"t":"\\"씨를 뿌릴 때 어떤 씨는 길가에 떨어져 새들이 와서 먹어 버렸어요.\\""},{"n":5,"t":"\\"어떤 씨는 흙이 적은 돌밭에 떨어졌어요. 흙이 깊지 않아 곧 싹이 나왔지만,\\""},{"n":6,"t":"\\"해가 뜨자 타 버려 뿌리가 없어서 말라 버렸어요.\\""},{"n":7,"t":"\\"어떤 씨는 가시덤불 속에 떨어져 가시들이 자라서 그 씨를 막아 버렸어요.\\""},{"n":8,"t":"\\"어떤 씨는 좋은 땅에 떨어져 열매를 맺어 어떤 것은 백 배, 어떤 것은 육십 배, 어떤 것은 삼십 배가 되었어요.\\""},{"n":9,"t":"\\"귀 있는 사람은 들어라.\\""},{"n":10,"t":"제자들이 와서 예수님께 물었어요. \\"왜 그들에게 비유로 말씀하세요?\\""},{"n":11,"t":"예수님이 대답하셨어요. \\"천국의 비밀을 아는 것이 너희에게는 허락되었지만 그들에게는 허락되지 않았어.\\""},{"n":12,"t":"\\"있는 사람에게는 더 주어져 풍성하게 되고, 없는 사람에게는 있는 것도 빼앗길 거야.\\""},{"n":13,"t":"\\"그래서 내가 그들에게 비유로 말해. 그들이 보아도 보지 못하고 들어도 듣지 못하고 깨닫지 못하기 때문이야.\\""},{"n":14,"t":"\\"그들에게서 이사야의 예언이 이루어졌어. \'너희가 듣기는 들어도 깨닫지 못하고, 보기는 보아도 알지 못한다.\\""},{"n":15,"t":"\\"이 백성의 마음이 굳어지고 귀가 둔하고 눈이 감겼다. 이는 눈으로 보고 귀로 듣고 마음으로 깨닫고 돌아와 내가 그들을 고치게 되는 것을 막으려 함이다.\'\\""},{"n":16,"t":"\\"그러나 너희 눈은 보니까 복이 있고, 너희 귀는 들으니까 복이 있다.\\""},{"n":17,"t":"\\"진정으로 말한다. 많은 예언자와 의인들이 너희가 보는 것을 보고자 했지만 보지 못했고, 너희가 듣는 것을 듣고자 했지만 듣지 못했어.\\""},{"n":18,"t":"\\"씨 뿌리는 사람의 비유를 들어 봐.\\""},{"n":19,"t":"\\"누구든지 천국 말씀을 듣고 깨닫지 못하면 악한 자가 와서 마음에 뿌려진 것을 빼앗아 가. 이것이 길가에 뿌려진 씨야.\\""},{"n":20,"t":"\\"돌밭에 뿌려진 씨는 말씀을 듣고 즉시 기쁨으로 받지만,\\""},{"n":21,"t":"\\"그 안에 뿌리가 없어 잠시뿐이라 말씀 때문에 환난이나 박해가 일어나면 곧 넘어져.\\""},{"n":22,"t":"\\"가시덤불에 뿌려진 씨는 말씀을 듣지만 세상의 걱정과 재물의 유혹이 말씀을 막아 열매를 맺지 못해.\\""},{"n":23,"t":"\\"좋은 땅에 뿌려진 씨는 말씀을 듣고 깨달은 사람이야. 그가 열매를 맺어 어떤 것은 백 배, 어떤 것은 육십 배, 어떤 것은 삼십 배가 돼.\\""},{"n":24,"t":"예수님이 또 다른 비유를 들려 주셨어요. \\"천국은 자기 밭에 좋은 씨를 뿌린 사람과 같아.\\""},{"n":25,"t":"\\"사람들이 잠든 동안 원수가 와서 밀 사이에 가라지 씨를 뿌리고 가 버렸어.\\""},{"n":26,"t":"\\"싹이 나서 열매를 맺을 때에 가라지도 함께 나타났어.\\""},{"n":27,"t":"\\"종들이 주인에게 와서 말했어. \'주인님, 밭에 좋은 씨를 뿌리지 않았나요? 어디서 가라지가 났어요?\'\\""},{"n":28,"t":"\\"주인이 \'원수가 한 일이다\' 하고 답하니, 종들이 \'우리가 가서 그것을 뽑을까요?\' 하고 물었어.\\""},{"n":29,"t":"\\"주인이 말했어. \'아니야. 가라지를 뽑다가 밀까지 같이 뽑을지도 몰라.\\""},{"n":30,"t":"\\"추수 때까지 둘 다 자라게 두어라. 추수 때에 내가 추수꾼에게 먼저 가라지를 모아 단으로 묶어 불태우고 밀은 내 창고에 넣으라고 할 거야.\'\\""},{"n":31,"t":"예수님이 또 다른 비유를 들려 주셨어요. \\"천국은 사람이 자기 밭에 심은 겨자씨와 같아.\\""},{"n":32,"t":"\\"그것은 모든 씨보다 작지만 자라면 풀보다 더 커서 나무가 되어 공중의 새들이 와서 그 가지에 깃들어.\\""},{"n":33,"t":"또 다른 비유를 들려 주셨어요. \\"천국은 어떤 여자가 가루 서 말 속에 넣어 다 부풀게 한 누룩과 같아.\\""},{"n":34,"t":"예수님은 이 모든 것을 무리에게 비유로 말씀하셨고, 비유 없이는 아무것도 말씀하지 않으셨어요."},{"n":35,"t":"이는 예언자의 말이 이루어진 거예요. \\"내가 입을 열어 비유로 말하고, 창세부터 감추어 둔 것들을 말할 거야.\\""},{"n":36,"t":"그때 예수님이 무리를 떠나 집에 들어가셨어요. 제자들이 와서 \\"밭의 가라지 비유를 우리에게 풀어 주세요\\" 하고 청했어요."},{"n":37,"t":"예수님이 대답하셨어요. \\"좋은 씨를 뿌리는 사람은 사람의 아들이고,\\""},{"n":38,"t":"\\"밭은 세상이고, 좋은 씨는 천국의 자녀들이고, 가라지는 악한 자의 자녀들이야.\\""},{"n":39,"t":"\\"가라지를 뿌린 원수는 마귀고, 추수 때는 세상의 끝이고, 추수꾼들은 천사들이야.\\""},{"n":40,"t":"\\"가라지를 모아 불에 태우는 것처럼 세상 끝에도 그렇게 될 거야.\\""},{"n":41,"t":"\\"사람의 아들이 천사들을 보내 죄짓게 하는 모든 것과 불법을 행하는 사람들을 그분의 나라에서 거둘 거야.\\""},{"n":42,"t":"\\"그들을 불 풀무에 던지니 거기서 울며 이를 갈게 될 거야.\\""},{"n":43,"t":"\\"그때 의인들은 그들의 아버지의 나라에서 해처럼 빛날 거야. 귀 있는 사람은 들어라.\\""},{"n":44,"t":"\\"천국은 밭에 감춰진 보물과 같아. 사람이 그것을 발견하면 다시 감추고 기뻐서 가서 자기 것 모두를 팔아 그 밭을 사.\\""},{"n":45,"t":"\\"또 천국은 좋은 진주를 찾는 상인과 같아.\\""},{"n":46,"t":"\\"그가 값진 진주 하나를 발견하면 가서 자기 것 모두를 팔아 그것을 사.\\""},{"n":47,"t":"\\"또 천국은 바다에 던져 모든 종류의 물고기를 모으는 그물과 같아.\\""},{"n":48,"t":"\\"그물이 가득 차면 사람들이 해변으로 끌어내 앉아서 좋은 것은 그릇에 담고 못쓸 것은 버려.\\""},{"n":49,"t":"\\"세상 끝에도 그렇게 될 거야. 천사들이 와서 의인 가운데서 악인들을 갈라내,\\""},{"n":50,"t":"\\"불 풀무에 던질 거야. 거기서 울며 이를 갈게 될 거야.\\""},{"n":51,"t":"\\"이 모든 것을 너희가 깨달았니?\\" 그들이 \\"예\\" 하고 대답했어요."},{"n":52,"t":"예수님이 말씀하셨어요. \\"그러므로 천국의 제자가 된 율법 학자마다 자기 창고에서 새것과 옛것을 꺼내는 집주인과 같아.\\""},{"n":53,"t":"예수님이 이 비유들을 마치시고 그곳을 떠나셨어요."},{"n":54,"t":"자기 동네에 오셔서 회당에서 가르치시니, 사람들이 놀라며 \\"이 사람이 어디서 이런 지혜와 능력을 얻었지?\\" 하고 말했어요."},{"n":55,"t":"\\"이 사람은 목수의 아들이 아니야? 그의 어머니는 마리아라 하지 않니? 그의 형제들은 야고보와 요셉과 시몬과 유다야.\\""},{"n":56,"t":"\\"그의 누이들도 다 우리와 함께 있잖아. 그런데 이 사람이 이 모든 걸 어디서 얻었어?\\""},{"n":57,"t":"그들이 예수님 때문에 걸려 넘어졌어요. 예수님이 말씀하셨어요. \\"예언자는 자기 동네와 자기 집 외에는 무시당하지 않아.\\""},{"n":58,"t":"그곳에서 예수님은 그들의 불신 때문에 많은 능력을 행하지 않으셨어요."}]}},{"chapter":14,"title":"오병이어와 물 위를 걸으심","verses":{"krv":[{"n":1,"t":"그 때에 분봉왕 헤롯이 예수의 소문을 듣고"},{"n":2,"t":"그 신하들에게 이르되 이는 세례요한이라 저가 죽은 자 가운데서 살아났으니 그러므로 이런 권능이 그 속에서 운동하는도다 하더라"},{"n":3,"t":"전에 헤롯이 그 동생 빌립의 아내 헤로디아의 일로 요한을 잡아 결박하여 옥에 가두었으니"},{"n":4,"t":"이는 요한이 헤롯에게 말하되 당신이 그 여자를 취한 것이 옳지 않다 하였음이라"},{"n":5,"t":"헤롯이 요한을 죽이려 하되 민중이 저를 선지자로 여기므로 민중을 두려워하더니"},{"n":6,"t":"마침 헤롯의 생일을 당하여 헤로디아의 딸이 연석 가운데서 춤을 추어 헤롯을 기쁘게 하니"},{"n":7,"t":"헤롯이 맹세로 그에게 무엇이든지 달라는대로 주겠다 허락하거늘"},{"n":8,"t":"그가 제 어미의 시킴을 듣고 가로되 세례요한의 머리를 소반에 담아 여기서 내게 주소서 하니"},{"n":9,"t":"왕이 근심하나 자기의 맹세한것과 그 함께 앉은 사람들을 인하여 주라 명하고"},{"n":10,"t":"사람을 보내어 요한을 옥에서 목 베어"},{"n":11,"t":"그 머리를 소반에 담아다가 그 여아에게 주니 그가 제 어미에게 가져가니라"},{"n":12,"t":"요한의 제자들이 와서 시체를 가져다가 장사하고 가서 예수께 고하니라"},{"n":13,"t":"예수께서 들으시고 배를 타고 떠나사 따로 빈들에 가시니 무리가 듣고 여러 고을로부터 걸어서 좇아간지라"},{"n":14,"t":"예수께서 나오사 큰 무리를 보시고 불쌍히 여기사 그 중에 있는 병인을 고쳐 주시니라"},{"n":15,"t":"저녁이 되매 제자들이 나아와 가로되 이곳은 빈들이요 때도 이미 저물었으니 무리를 보내어 마을에 들어가 먹을 것을 사먹게 하소서"},{"n":16,"t":"예수께서 가라사대 갈것 없다 너희가 먹을 것을 주라"},{"n":17,"t":"제자들이 가로되 여기 우리에게 있는 것은 떡 다섯 개와 물고기 두 마리 뿐이니이다"},{"n":18,"t":"가라사대 그것을 내게 가져오라 하시고"},{"n":19,"t":"무리를 명하여 잔디 위에 앉히시고 떡 다섯개와 물고기 두 마리를 가지사 하늘을 우러러 축사하시고 떡을 떼어 제자들에게 주시매 제자들이 무리에게 주니"},{"n":20,"t":"다 배불리 먹고 남은 조각을 열 두 바구니에 차게 거두었으며"},{"n":21,"t":"먹은 사람은 여자와 아이 외에 오천 명이나 되었더라"},{"n":22,"t":"예수께서 즉시 제자들을 재촉하사 자기가 무리를 보내는 동안에 배를 타고 앞서 건너편으로 가게 하시고"},{"n":23,"t":"무리를 보내신 후에 기도하러 따로 산에 올라가시다 저물매 거기 혼자 계시더니"},{"n":24,"t":"배가 이미 육지에서 수리나 떠나서 바람이 거슬리므로 물결을 인하여 고난을 당하더라"},{"n":25,"t":"밤 사경에 예수께서 바다 위로 걸어서 제자들에게 오시니"},{"n":26,"t":"제자들이 그 바다 위로 걸어 오심을 보고 놀라 유령이라 하며 무서워하여 소리지르거늘"},{"n":27,"t":"예수께서 즉시 일러 가라사대 안심하라 내니 두려워 말라"},{"n":28,"t":"베드로가 대답하여 가로되 주여 만일 주시어든 나를 명하사 물 위로 오라 하소서 한대"},{"n":29,"t":"오라 하시니 베드로가 배에서 내려 물 위로 걸어서 예수께로 가되"},{"n":30,"t":"바람을 보고 무서워 빠져 가는지라 소리질러 가로되 주여 나를 구원하소서 하니"},{"n":31,"t":"예수께서 즉시 손을 내밀어 저를 붙잡으시며 가라사대 믿음이 적은 자여 왜 의심하였느냐 하시고"},{"n":32,"t":"배에 함께 오르매 바람이 그치는지라"},{"n":33,"t":"배에 있는 사람들이 예수께 절하며 가로되 진실로 하나님의 아들이로소이다 하더라"},{"n":34,"t":"저희가 건너가 게네사렛 땅에 이르니"},{"n":35,"t":"그곳 사람들이 예수신 줄을 알고 그 근방에 두루 통지하여 모든 병든 자를 예수께 데리고 와서"},{"n":36,"t":"다만 예수의 옷가에라도 손을 대게 하시기를 간구하니 손을 대는자는 다 나음을 얻으니라"}],"kids":[{"n":1,"t":"그 무렵 지방 왕 헤롯이 예수님에 대한 소문을 들었어요."},{"n":2,"t":"그가 신하들에게 말했어요. \\"이 사람은 세례 요한이 죽은 사람 가운데서 살아난 거야. 그래서 능력이 그에게서 나타나는 거야.\\""},{"n":3,"t":"헤롯은 동생 빌립의 아내 헤로디아 때문에 요한을 잡아 묶어 감옥에 가둔 적이 있어요."},{"n":4,"t":"요한이 \\"그 여자를 아내로 데리고 사는 것은 옳지 않아요\\" 하고 말했기 때문이에요."},{"n":5,"t":"헤롯은 요한을 죽이고 싶었지만 무리가 그를 예언자로 여겼기 때문에 두려워서 못했어요."},{"n":6,"t":"헤롯의 생일에 헤로디아의 딸이 손님들 앞에서 춤을 추어 헤롯을 기쁘게 했어요."},{"n":7,"t":"헤롯이 무엇이든 그녀가 구하는 대로 주겠다고 약속하며 맹세했어요."},{"n":8,"t":"어머니의 사주를 받은 그녀가 \\"세례 요한의 머리를 쟁반에 담아 주세요\\" 하고 말했어요."},{"n":9,"t":"왕은 슬펐지만 자기 맹세와 함께 앉은 손님들 때문에 들어주라고 명령했어요."},{"n":10,"t":"그는 사람을 보내 감옥에서 요한의 목을 베게 했어요."},{"n":11,"t":"그 머리를 쟁반에 담아 가져다가 그 여자에게 주니, 그녀가 어머니에게 가져다 드렸어요."},{"n":12,"t":"요한의 제자들이 와서 시신을 가져다가 장사 지내고 예수님께 가서 알렸어요."},{"n":13,"t":"예수님이 듣고 배를 타고 따로 한적한 곳으로 떠나셨어요. 무리가 듣고 동네들에서 걸어서 따라왔어요."},{"n":14,"t":"예수님이 나와서 큰 무리를 보시고 그들을 불쌍히 여겨 병자들을 고쳐 주셨어요."},{"n":15,"t":"날이 저물자 제자들이 와서 말했어요. \\"여기는 한적한 곳이고 시간도 늦었어요. 무리를 보내 동네에 가서 먹을 것을 사 먹게 하세요.\\""},{"n":16,"t":"예수님이 말씀하셨어요. \\"보낼 필요 없어. 너희가 먹을 것을 줘.\\""},{"n":17,"t":"제자들이 \\"여기 우리에게는 빵 다섯 덩이와 물고기 두 마리밖에 없어요\\" 하고 말했어요."},{"n":18,"t":"예수님이 \\"그것을 내게 가져오너라\\" 하셨어요."},{"n":19,"t":"무리를 풀밭에 앉게 하시고 빵 다섯과 물고기 두 마리를 가져다가 하늘을 우러러 축복하시고 떼어 제자들에게 주시자 그들이 무리에게 나누어 주었어요."},{"n":20,"t":"모두 다 먹고 배가 불렀어요. 남은 조각이 열두 바구니에 가득했어요."},{"n":21,"t":"먹은 사람은 여자와 어린이 외에 남자 약 오천 명이었어요."},{"n":22,"t":"예수님이 곧 제자들을 재촉하여 배에 태우고 자기보다 먼저 건너편으로 가게 하셨어요. 그동안 무리를 보내고 계셨어요."},{"n":23,"t":"무리를 보내신 후 따로 기도하시려고 산에 올라가셨어요. 저녁이 됐는데도 거기 혼자 계셨어요."},{"n":24,"t":"한편 배는 이미 호수 한가운데에 있어서 바람이 마주 불어 파도에 시달리고 있었어요."},{"n":25,"t":"새벽 네 시쯤 예수님이 호수 위를 걸어 그들에게 가셨어요."},{"n":26,"t":"제자들이 예수님께서 호수 위로 걸어오시는 것을 보고 놀라서 \\"유령이다!\\" 하고 두려워하며 소리쳤어요."},{"n":27,"t":"예수님이 곧 그들에게 말씀하셨어요. \\"안심해. 나야. 두려워하지 마.\\""},{"n":28,"t":"베드로가 대답했어요. \\"주님, 정말 주님이시거든 저에게 명하사 물 위로 걸어 주님께 오게 해 주세요.\\""},{"n":29,"t":"예수님이 \\"오라\\" 하셨어요. 베드로가 배에서 내려 물 위를 걸어 예수님께 갔어요."},{"n":30,"t":"그러나 바람을 보고 두려워하여 빠져 가니 \\"주님, 저를 구해 주세요!\\" 하고 외쳤어요."},{"n":31,"t":"예수님이 즉시 손을 내밀어 그를 붙잡으시며 말씀하셨어요. \\"믿음이 적은 자야, 왜 의심했니?\\""},{"n":32,"t":"그들이 배에 오르자 바람이 그쳤어요."},{"n":33,"t":"배에 있던 사람들이 예수님께 절하며 \\"진실로 하나님의 아들이세요\\" 하고 말했어요."},{"n":34,"t":"그들이 건너가 게네사렛 땅에 닿았어요."},{"n":35,"t":"그곳 사람들이 예수님을 알아보고 사방으로 사람을 보내 모든 병자를 데리고 왔어요."},{"n":36,"t":"그들이 예수님의 옷자락만이라도 만지게 해 달라고 간청했고, 만진 사람은 다 나았어요."}]}},{"chapter":15,"title":"사람을 진짜로 더럽히는 것","verses":{"krv":[{"n":1,"t":"그 때에 바리새인과 서기관들이 예루살렘으로부터 예수께 나아와 가로되"},{"n":2,"t":"당신의 제자들이 어찌하여 장로들의 유전을 범하나이까 떡 먹을 때에 손을 씻지 아니하나이다"},{"n":3,"t":"대답하여 가라사대 너희는 어찌하여 너희 유전으로 하나님의 계명을 범하느뇨"},{"n":4,"t":"하나님이 이르셨으되 네 부모를 공경하라 하시고 또 아비나 어미를 훼방하는 자는 반드시 죽으리라 하셨거늘"},{"n":5,"t":"너희는 가로되 누구든지 아비에게나 어미에게 말하기를 내가 드려 유익하게 할것이 하나님께 드림이 되었다고 하기만 하면"},{"n":6,"t":"그 부모를 공경할 것이 없다 하여 너희 유전으로 하나님의 말씀을 폐하는도다"},{"n":7,"t":"외식하는 자들아 이사야가 너희에게 대하여 잘 예언하였도다 일렀으되"},{"n":8,"t":"이 백성이 입술로는 나를 존경하되 마음은 내게서 멀도다"},{"n":9,"t":"사람의 계명으로 교훈을 삼아 가르치니 나를 헛되이 경배하는도다 하였느니라 하시고"},{"n":10,"t":"무리를 불러 이르시되 듣고 깨달으라"},{"n":11,"t":"입에 들어가는 것이 사람을 더럽게 하는 것이 아니라 입에서 나오는 그것이 사람을 더럽게 하는 것이니라"},{"n":12,"t":"이에 제자들이 나아와 가로되 바리새인들이 이 말씀을 듣고 걸림이 된줄 아시나이까"},{"n":13,"t":"예수께서 대답하여 가라사대 심은 것마다 내 천부께서 심으시지 않은 것은 뽑힐 것이니"},{"n":14,"t":"그냥 두어라 저희는 소경이되어 소경을 인도하는 자로다 만일 소경이 소경을 인도하면 둘이 다 구덩이에 빠지리라 하신대"},{"n":15,"t":"베드로가 대답하여 가로되 이 비유를 우리에게 설명하여 주옵소서"},{"n":16,"t":"예수께서 가라사대 너희도 아직까지 깨달음이 없느냐"},{"n":17,"t":"입으로 들어가는 모든 것은 배로 들어가서 뒤로 내어버려지는 줄을 알지 못하느냐"},{"n":18,"t":"입에서 나오는 것들은 마음에서 나오나니 이것이야말로 사람을 더럽게 하느니라"},{"n":19,"t":"마음에서 나오는 것은 악한 생각과 살인과 간음과 음란과 도적질과 거짓 증거와 훼방이니"},{"n":20,"t":"이런 것들이 사람을 더럽게 하는 것이요 씻지 않은 손으로 먹는 것은 사람을 더럽게 하지 못하느니라"},{"n":21,"t":"예수께서 거기서 나가사 두로와 시돈 지방으로 들어가시니"},{"n":22,"t":"가나안 여자 하나가 그 지경에서 나와서 소리질러 가로되 주 다윗의 자손이여 나를 불쌍히 여기소서 내 딸이 흉악히 귀신들렸나이다 하되"},{"n":23,"t":"예수는 한 말씀도 대답지 아니하시니 제자들이 와서 청하여 말하되 그 여자가 우리 뒤에서 소리를 지르오니 보내소서"},{"n":24,"t":"예수께서 대답하여 가라사대 나는 이스라엘 집의 잃어버린 양 외에는 다른데로 보내심을 받지 아니하였노라 하신대"},{"n":25,"t":"여자가 와서 예수께 절하며 가로되 주여 저를 도우소서"},{"n":26,"t":"대답하여 가라사대 자녀의 떡을 취하여 개들에게 던짐이 마땅치 아니하니라"},{"n":27,"t":"여자가 가로되 주여 옳소이다마는 개들도 제 주인의 상에서 떨어지는 부스러기를 먹나이다 하니"},{"n":28,"t":"이에 예수께서 대답하여 가라사대 여자야 네 믿음이 크도다 네 소원대로 되리라 하시니 그 시로부터 그의 딸이 나으니라"},{"n":29,"t":"예수께서 거기서 떠나사 갈릴리 호숫가에 이르러 산에 올라가 거기 앉으시니"},{"n":30,"t":"큰 무리가 절뚝발이와 불구자와 소경과 벙어리와 기타 여럿을 데리고 와서 예수의 발앞에 두매 고쳐 주시니"},{"n":31,"t":"벙어리가 말하고 불구자가 건전하고 절뚝발이가 걸으며 소경이 보는 것을 무리가 보고 기이히 여겨 이스라엘의 하나님께 영광을 돌리니라"},{"n":32,"t":"예수께서 제자들을 불러 가라사대 내가 무리를 불쌍히 여기노라 저희가 나와 함께 있은지 이미 사흘이매 먹을 것이 없도다 길에서 기진할까 하여 굶겨 보내지 못하겠노라"},{"n":33,"t":"제자들이 가로되 광야에 있어 우리가 어디서 이런 무리의 배부를만큼 떡을 얻으리이까"},{"n":34,"t":"예수께서 가라사대 너희에게 떡이 몇 개나있느냐 가로되 일곱개와 작은 생선 두어 마리가 있나이다 하거늘"},{"n":35,"t":"예수께서 무리를 명하사 땅에 앉게 하시고"},{"n":36,"t":"떡 일곱 개와 그 생선을 가지사 축사하시고 떼어 제자들에게 주시니 제자들이 무리에게 주매"},{"n":37,"t":"다 배불리 먹고 남은 조각을 일곱 광주리에 차게 거두었으며"},{"n":38,"t":"먹은 자는 여자와 아이 외에 사천 명이었더라"},{"n":39,"t":"예수께서 무리를 흩어 보내시고 배에 오르사 마가단 지경에 가시니라"}],"kids":[{"n":1,"t":"그때 예루살렘에서 온 바리새인들과 율법 학자들이 예수님께 와서 말했어요."},{"n":2,"t":"\\"왜 주님의 제자들은 장로들의 전통을 어기나요? 빵을 먹을 때 손을 씻지 않아요.\\""},{"n":3,"t":"예수님이 대답하셨어요. \\"너희는 왜 너희 전통을 위해 하나님의 계명을 어기니?\\""},{"n":4,"t":"\\"하나님은 \'네 아버지와 어머니를 공경하라\'고 하셨고 \'아버지나 어머니를 욕하는 사람은 반드시 죽임을 당하라\'고 하셨어.\\""},{"n":5,"t":"\\"그런데 너희는 \'누가 자기 아버지나 어머니에게 「내게서 받을 것이 하나님께 드린 예물이 되었다」라고 하면\',\\""},{"n":6,"t":"\\"그 사람은 자기 아버지나 어머니를 공경하지 않아도 된다고 가르쳐. 너희 전통 때문에 너희가 하나님의 말씀을 없애 버렸어.\\""},{"n":7,"t":"\\"위선자들아, 이사야가 너희를 두고 잘 예언했어.\\""},{"n":8,"t":"\\"\'이 백성은 입술로는 나를 공경하지만 그들의 마음은 나에게서 멀다.\\""},{"n":9,"t":"\\"사람의 가르침을 교훈으로 가르치니 헛되이 나를 예배한다.\'\\""},{"n":10,"t":"예수님이 무리를 불러 말씀하셨어요. \\"들어라, 깨달아라.\\""},{"n":11,"t":"\\"입으로 들어가는 것이 사람을 더럽히는 게 아니라 입에서 나오는 것이 사람을 더럽혀.\\""},{"n":12,"t":"제자들이 와서 \\"바리새인들이 이 말씀을 듣고 화가 난 것을 아세요?\\" 하고 말했어요."},{"n":13,"t":"예수님이 대답하셨어요. \\"하늘에 계신 내 아버지께서 심지 않으신 식물마다 뽑힐 거야.\\""},{"n":14,"t":"\\"그냥 두어라. 그들은 맹인을 인도하는 맹인이야. 맹인이 맹인을 인도하면 둘 다 구덩이에 빠져.\\""},{"n":15,"t":"베드로가 \\"이 비유를 풀어 주세요\\" 하고 말했어요."},{"n":16,"t":"예수님이 말씀하셨어요. \\"너희도 아직 깨닫지 못하니?\\""},{"n":17,"t":"\\"입으로 들어가는 것은 무엇이든 배 속으로 가서 변소로 나가는 줄을 깨닫지 못하니?\\""},{"n":18,"t":"\\"그러나 입에서 나오는 것은 마음에서 나와 사람을 더럽혀.\\""},{"n":19,"t":"\\"마음에서 악한 생각, 살인, 간음, 음행, 도둑질, 거짓 증언, 모독이 나와.\\""},{"n":20,"t":"\\"이것들이 사람을 더럽히는 거야. 손을 씻지 않고 먹는 것은 사람을 더럽히지 않아.\\""},{"n":21,"t":"예수님이 거기서 떠나 두로와 시돈 지역으로 가셨어요."},{"n":22,"t":"그 지역의 가나안 여자 한 사람이 와서 외쳤어요. \\"주님, 다윗의 자손이여, 저를 불쌍히 여겨 주세요. 제 딸이 귀신에게 심하게 시달려요.\\""},{"n":23,"t":"예수님이 한 마디도 대답하지 않으셨어요. 제자들이 와서 청했어요. \\"그 여자를 보내세요. 우리 뒤를 쫓아오며 외쳐요.\\""},{"n":24,"t":"예수님이 \\"나는 이스라엘 집의 잃은 양 외에는 다른 사람에게 보냄을 받지 않았어\\" 하고 말씀하셨어요."},{"n":25,"t":"그 여자가 와서 예수님께 절하며 \\"주님, 저를 도와주세요\\" 하고 청했어요."},{"n":26,"t":"예수님이 \\"자녀의 빵을 가져다 강아지에게 던져 주는 것은 옳지 않아\\" 하고 말씀하셨어요."},{"n":27,"t":"그 여자가 \\"맞아요, 주님. 그러나 강아지도 주인의 상에서 떨어지는 부스러기는 먹어요\\" 하고 대답했어요."},{"n":28,"t":"예수님이 \\"여자야, 네 믿음이 크다. 네 소원대로 될 거야\\" 하고 말씀하셨어요. 바로 그 시간에 그녀의 딸이 나았어요."},{"n":29,"t":"예수님이 거기서 떠나 갈릴리 호숫가에 이르러 산에 올라가 앉으셨어요."},{"n":30,"t":"큰 무리가 다리 저는 사람, 맹인, 말 못 하는 사람, 손발이 불편한 사람과 다른 많은 사람들을 데리고 와서 예수님의 발 앞에 두었고, 예수님이 그들을 고쳐 주셨어요."},{"n":31,"t":"말 못 하는 사람이 말하고 손발이 불편한 사람이 성해지고 다리 저는 사람이 걷고 맹인이 보는 것을 무리가 보고 놀라며 이스라엘의 하나님을 찬양했어요."},{"n":32,"t":"예수님이 제자들을 부르시고 말씀하셨어요. \\"이 무리를 보니 불쌍해. 사흘이나 나와 함께 있었는데 먹을 게 없어. 굶겨 보내고 싶지 않다. 길에서 지칠지도 모르거든.\\""},{"n":33,"t":"제자들이 \\"이 광야에서 어디서 이렇게 많은 무리를 배부르게 할 빵을 얻을 수 있어요?\\" 하고 말했어요."},{"n":34,"t":"예수님이 \\"빵이 몇 덩이 있니?\\" 하고 물으셨어요. 그들이 \\"일곱 덩이와 작은 물고기 몇 마리가 있어요\\" 하고 대답했어요."},{"n":35,"t":"예수님이 무리에게 땅에 앉으라고 명하셨어요."},{"n":36,"t":"그리고 일곱 덩이와 물고기를 가져다 감사 기도를 드리고 떼어 제자들에게 주시자 그들이 무리에게 나누어 주었어요."},{"n":37,"t":"모두 다 먹고 배불렀어요. 남은 조각이 일곱 바구니에 가득했어요."},{"n":38,"t":"먹은 사람은 여자와 어린이 외에 남자 사천 명이었어요."},{"n":39,"t":"예수님이 무리를 보내신 후 배에 타고 마가단 지역으로 가셨어요."}]}},{"chapter":16,"title":"베드로의 신앙고백","verses":{"krv":[{"n":1,"t":"바리새인과 사두개인들이 와서 예수를 시험하여 하늘로서 오는 표적 보이기를 청하니"},{"n":2,"t":"예수께서 대답하여 가라사대 너희가 저녁에 하늘이 붉으면 날이 좋겠다 하고"},{"n":3,"t":"아침에 하늘이 붉고 흐리면 오늘은 날이 궂겠다 하나니 너희가 천기는 분별할줄 알면서 시대의 표적은 분별할 수 없느냐"},{"n":4,"t":"악하고 음란한 세대가 표적을 구하나 요나의 표적 밖에는 보여 줄 표적이 없느니라 하시고 저희를 떠나 가시다"},{"n":5,"t":"제자들이 건너편으로 갈쌔 떡 가져가기를 잊었더니"},{"n":6,"t":"예수께서 이르시되 삼가 바리새인과 사두개인들의 누룩을 주의하라 하신대"},{"n":7,"t":"제자들이 서로 의논하여 가로되 우리가 떡을 가져 오지 아니하였도다 하거늘"},{"n":8,"t":"예수께서 아시고 가라사대 믿음이 적은 자들아 어찌 떡이 없음으로 서로 의논하느냐"},{"n":9,"t":"너희가 아직도 깨닫지 못하느냐 떡 다섯 개로 오천명을 먹이고 주운 것이 몇 바구니며"},{"n":10,"t":"떡 일곱 개로 사천 명을 먹이고 주운 것이 몇 광주리이던 것을 기억지 못하느냐"},{"n":11,"t":"어찌 내 말한 것이 떡에 관함이 아닌 줄을 깨닫지 못하느냐 오직 바리새인과 사두개인들의 누룩을 주의하라 하시니"},{"n":12,"t":"그제야 제자들이 떡의 누룩이 아니요 바리새인과 사두개인들의 교훈을 삼가라고 말씀하신 줄을 깨달으니라"},{"n":13,"t":"예수께서 가이사랴 빌립보 지방에 이르러 제자들에게 물어 가라사대 사람들이 인자를 누구라 하느냐"},{"n":14,"t":"가로되 더러는 세례 요한, 더러는 엘리야, 어떤이는 예레미야나 선지자 중의 하나라 하나이다"},{"n":15,"t":"가라사대 너희는 나를 누구라 하느냐"},{"n":16,"t":"시몬 베드로가 대답하여 가로되 주는 그리스도시요 살아계신 하나님의 아들이시니이다"},{"n":17,"t":"예수께서 대답하여 가라사대 바요나 시몬아 네가 복이 있도다 이를 네게 알게 한 이는 혈육이 아니요 하늘에 계신 내 아버지시니라"},{"n":18,"t":"또 내가 네게 이르노니 너는 베드로라 내가 이 반석 위에 내 교회를 세우리니 음부의 권세가 이기지 못하리라"},{"n":19,"t":"내가 천국 열쇠를 네게 주리니 네가 땅에서 무엇이든지 매면 하늘에서도 매일 것이요 네가 땅에서 무엇이든지 풀면 하늘에서도 풀리리라 하시고"},{"n":20,"t":"이에 제자들을 경계하사 자기가 그리스도인 것을 아무에게도 이르지 말라 하시니라"},{"n":21,"t":"이 때로부터 예수 그리스도께서 자기가 예루살렘에 올라가 장로들과 대제사장들과 서기관들에게 많은 고난을 받고 죽임을 당하고 제 삼일에 살아나야 할 것을 제자들에게 비로소 가르치시니"},{"n":22,"t":"베드로가 예수를 붙들고 간하여 가로되 주여 그리 마옵소서 이 일이 결코 주에게 미치지 아니하리이다"},{"n":23,"t":"예수께서 돌이키시며 베드로에게 이르시되 사단아 내 뒤로 물러 가라 너는 나를 넘어지게 하는 자로다 네가 하나님의 일을 생각지 아니하고 도리어 사람의 일을 생각하는도다 하시고"},{"n":24,"t":"이에 예수께서 제자들에게 이르시되 아무든지 나를 따라 오려거든 자기를 부인하고 자기 십자가를 지고 나를 좇을 것이니라"},{"n":25,"t":"누구든지 제 목숨을 구원코자 하면 잃을 것이요 누구든지 나를 위하여 제 목숨을 잃으면 찾으리라"},{"n":26,"t":"사람이 만일 온 천하를 얻고도 제 목숨을 잃으면 무엇이 유익하리요 사람이 무엇을 주고 제 목숨을 바꾸겠느냐"},{"n":27,"t":"인자가 아버지의 영광으로 그 천사들과 함께 오리니 그 때에 각 사람의 행한대로 갚으리라"},{"n":28,"t":"진실로 너희에게 이르노니 여기 섰는 사람 중에 죽기 전에 인자가 그 왕권을 가지고 오는 것을 볼 자들도 있느니라"}],"kids":[{"n":1,"t":"바리새인과 사두개인들이 와서 예수님을 시험하려고 하늘에서 오는 표적을 보여 달라고 했어요."},{"n":2,"t":"예수님이 대답하셨어요. \\"저녁이 되면 \'하늘이 붉으니 날이 좋겠다\' 하고,\\""},{"n":3,"t":"\\"아침에는 \'하늘이 붉고 흐리니 오늘 날씨가 나쁘겠다\' 하잖아. 너희가 하늘의 모습은 분별할 줄 알면서 어찌 시대의 표적은 분별하지 못하니?\\""},{"n":4,"t":"\\"악하고 음란한 세대가 표적을 구하지만 요나의 표적 외에는 받을 게 없다.\\" 그러고 그들을 떠나가셨어요."},{"n":5,"t":"제자들이 건너편에 갔을 때 빵 가져오는 것을 잊어버렸어요."},{"n":6,"t":"예수님이 \\"바리새인과 사두개인의 누룩을 조심해\\" 하고 말씀하셨어요."},{"n":7,"t":"제자들이 \\"우리가 빵을 가져오지 않아서 그러시는 거야\\" 하고 서로 말했어요."},{"n":8,"t":"예수님이 그것을 아시고 말씀하셨어요. \\"믿음이 적은 자들아, 너희가 빵이 없다고 왜 서로 말하니?\\""},{"n":9,"t":"\\"아직도 깨닫지 못하니? 빵 다섯과 오천 명을 기억하지 못하니? 그때 몇 바구니 거두었니?\\""},{"n":10,"t":"\\"빵 일곱과 사천 명을 기억 못하니? 그때 몇 바구니 거두었니?\\""},{"n":11,"t":"\\"내가 빵에 대해 말하지 않은 줄을 어찌 깨닫지 못하니? 바리새인과 사두개인의 누룩을 조심해야 한다고 말한 거야.\\""},{"n":12,"t":"그제야 제자들은 예수님이 빵의 누룩이 아니라 바리새인과 사두개인의 가르침을 조심하라는 뜻인 줄 깨달았어요."},{"n":13,"t":"예수님이 가이사랴 빌립보 지역에 가셔서 제자들에게 물으셨어요. \\"사람들이 사람의 아들을 누구라고 하니?\\""},{"n":14,"t":"그들이 대답했어요. \\"어떤 사람은 세례 요한, 어떤 사람은 엘리야, 또 어떤 사람은 예레미야나 예언자 중 하나라고 해요.\\""},{"n":15,"t":"예수님이 \\"너희는 나를 누구라고 하니?\\" 하고 물으셨어요."},{"n":16,"t":"시몬 베드로가 대답했어요. \\"주님은 그리스도시고 살아 계신 하나님의 아들이세요.\\""},{"n":17,"t":"예수님이 말씀하셨어요. \\"바요나 시몬아, 너에게 복이 있다. 이것을 알게 한 분은 사람이 아니라 하늘에 계신 내 아버지셔.\\""},{"n":18,"t":"\\"내가 너에게 말한다. 너는 베드로다. 내가 이 반석 위에 내 교회를 세울 거고 음부의 권세가 그것을 이기지 못할 거야.\\""},{"n":19,"t":"\\"내가 너에게 천국 열쇠를 줄 거야. 네가 땅에서 매면 하늘에서도 매이고 네가 땅에서 풀면 하늘에서도 풀릴 거야.\\""},{"n":20,"t":"그러고 예수님이 자기가 그리스도라고 아무에게도 말하지 말라고 제자들에게 분부하셨어요."},{"n":21,"t":"그때부터 예수님은 자기가 예루살렘에 가서 장로들과 대제사장들과 율법 학자들에게 많은 고난을 받고 죽임을 당했다가 사흘 만에 살아나야 한다는 것을 제자들에게 알리기 시작하셨어요."},{"n":22,"t":"베드로가 예수님을 붙들고 말리며 \\"주님, 절대 그럴 수 없어요. 이런 일이 결코 일어나면 안 돼요\\" 하고 말했어요."},{"n":23,"t":"예수님이 돌아서서 베드로에게 말씀하셨어요. \\"사탄아, 내 뒤로 물러가라. 너는 내게 걸림돌이야. 네가 하나님의 일이 아니라 사람의 일을 생각하고 있어.\\""},{"n":24,"t":"그리고 예수님이 제자들에게 말씀하셨어요. \\"누구든지 나를 따라오려거든 자기를 부인하고 자기 십자가를 지고 나를 따르라.\\""},{"n":25,"t":"\\"자기 목숨을 구하려는 사람은 잃고, 나를 위해 자기 목숨을 잃는 사람은 얻을 거야.\\""},{"n":26,"t":"\\"사람이 온 세상을 얻고도 자기 영혼을 잃으면 무슨 유익이 있겠어? 사람이 자기 영혼과 무엇을 바꿀 수 있을까?\\""},{"n":27,"t":"\\"사람의 아들이 아버지의 영광 가운데 천사들과 함께 와서 각 사람에게 그 행위대로 갚아 줄 거야.\\""},{"n":28,"t":"\\"진정으로 말한다. 여기 서 있는 사람들 중에 사람의 아들이 자기 나라에 임하는 것을 보기 전에는 죽음을 맛보지 않을 사람들이 있어.\\""}]}},{"chapter":17,"title":"변화산의 영광","verses":{"krv":[{"n":1,"t":"엿새 후에 예수께서 베드로와 야고보와 그 형제 요한을 데리시고 따로 높은 산에 올라가셨더니"},{"n":2,"t":"저희 앞에서 변형되사 그 얼굴이 해 같이 빛나며 옷이 빛과 같이 희어졌더라"},{"n":3,"t":"때에 모세와 엘리야가 예수로 더불어 말씀하는 것이 저희에게 보이거늘"},{"n":4,"t":"베드로가 예수께 여짜와 가로되 주여 우리가 여기 있는 것이 좋사오니 주께서 만일 원하시면 내가 여기서 초막 셋을 짓되 하나는 주를 위하여, 하나는 모세를 위하여, 하나는 엘리야를 위하여 하리이다"},{"n":5,"t":"말할 때에 홀연히 빛난 구름이 저희를 덮으며 구름 속에서 소리가 나서 가로되 이는 내 사랑하는 아들이요 내 기뻐하는 자니 너희는 저의 말을 들으라 하는지라"},{"n":6,"t":"제자들이 듣고 엎드리어 심히 두려워하니"},{"n":7,"t":"예수께서 나아와 저희에게 손을 대시며 가라사대 일어나라 두려워 말라 하신대"},{"n":8,"t":"제자들이 눈을 들고 보매 오직 예수 외에는 아무도 보이지 아니하더라"},{"n":9,"t":"저희가 산에서 내려올 때에 예수께서 명하여 가라사대 인자가 죽은 자 가운데서 살아나기 전에는 본것을 아무에게도 이르지 말라 하시니"},{"n":10,"t":"제자들이 묻자와 가로되 그러면 어찌하여 서기관들이 엘리야가 먼저 와야 하리라 하나이까"},{"n":11,"t":"예수께서 대답하여 가라사대 엘리야가 과연 먼저 와서 모든 일을 회복하리라"},{"n":12,"t":"내가 너희에게 말하노니 엘리야가 이미 왔으되 사람들이 알지 못하고 임의로 대우하였도다 인자도 이와 같이 그들에게 고난을 받으리라 하시니"},{"n":13,"t":"그제야 제자들이 예수의 말씀하신 것이 세례 요한인 줄을 깨달으니라"},{"n":14,"t":"저희가 무리에게 이르매 한 사람이 예수께 와서 꿇어 엎드리어 가로되"},{"n":15,"t":"주여 내 아들을 불쌍히 여기소서 저가 간질로 심히 고생하여 자주 불에도 넘어지며 물에도 넘어지는지라"},{"n":16,"t":"내가 주의 제자들에게 데리고 왔으나 능히 고치지 못하더이다"},{"n":17,"t":"예수께서 대답하여 가라사대 믿음이 없고 패역한 세대여 내가 얼마나 너희와 함께 있으며 얼마나 너희를 참으리요 그를 이리로 데려오라 하시다"},{"n":18,"t":"이에 예수께서 꾸짖으시니 귀신이 나가고 아이가 그때부터 나으니라"},{"n":19,"t":"이 때에 제자들이 종용히 예수께 나아와 가로되 우리는 어찌하여 쫓아내지 못하였나이까"},{"n":20,"t":"가라사대 너희 믿음이 적은 연고니라 진실로 너희에게 이르노니 너희가 만일 믿음이 한 겨자씨 만큼만 있으면 이 산을 명하여 여기서 저기로 옮기라 하여도 옮길 것이요 또 너희가 못할 것이 없으리라"},{"n":21,"t":"(없 음)"},{"n":22,"t":"갈릴리에 모일 때에 예수께서 제자들에게 이르시되 인자가 장차 사람들의 손에 넘기워"},{"n":23,"t":"죽임을 당하고 제 삼일에 살아나리라 하시니 제자들이 심히 근심하더라"},{"n":24,"t":"가버나움에 이르니 반 세겔 받는 자들이 베드로에게 나아와 가로되 너의 선생이 반 세겔을 내지 아니하느냐"},{"n":25,"t":"가로되 내신다 하고 집에 들어가니 예수께서 먼저 가라사대 시몬아 네 생각은 어떠하뇨 세상 임금들이 뉘게 관세와 정세를 받느냐 자기 아들에게냐 타인에게냐"},{"n":26,"t":"베드로가 가로되 타인에게니이다 예수께서 가라사대 그러하면 아들들은 세를 면하리라"},{"n":27,"t":"그러나 우리가 저희로 오해케 하지 않기 위하여 네가 바다에 가서 낚시를 던져 먼저 오르는 고기를 가져 입을 열면 돈 한 세겔을 얻을 것이니 가져다가 나와 너를 위하여 주라 하시니라"}],"kids":[{"n":1,"t":"엿새 후에 예수님이 베드로와 야고보와 그의 동생 요한을 데리고 따로 높은 산에 올라가셨어요."},{"n":2,"t":"그들 앞에서 예수님의 모습이 변해 얼굴이 해처럼 빛나고 옷이 빛처럼 희어졌어요."},{"n":3,"t":"갑자기 모세와 엘리야가 나타나 예수님과 함께 이야기했어요."},{"n":4,"t":"베드로가 예수님께 말했어요. \\"주님, 여기 있는 게 좋겠어요. 원하시면 여기에 초막 셋을 짓겠어요. 하나는 주님 것, 하나는 모세 것, 하나는 엘리야 것을요.\\""},{"n":5,"t":"베드로가 말하고 있을 때, 빛난 구름이 그들을 덮고 구름 속에서 소리가 들렸어요. \\"이는 내 사랑하는 아들이야. 내가 그를 매우 기뻐해. 너희는 그의 말을 들어라.\\""},{"n":6,"t":"제자들이 듣고 엎드려 몹시 두려워했어요."},{"n":7,"t":"예수님이 다가오셔서 그들을 만지며 \\"일어나라, 두려워하지 마라\\" 하고 말씀하셨어요."},{"n":8,"t":"그들이 눈을 들어 보니 예수님 외에는 아무도 보이지 않았어요."},{"n":9,"t":"산에서 내려올 때 예수님이 그들에게 분부하셨어요. \\"사람의 아들이 죽은 자 가운데서 살아날 때까지 너희가 본 환상을 아무에게도 말하지 마라.\\""},{"n":10,"t":"제자들이 물었어요. \\"그러면 왜 율법 학자들은 엘리야가 먼저 와야 한다고 해요?\\""},{"n":11,"t":"예수님이 대답하셨어요. \\"엘리야가 와서 모든 것을 회복할 거야.\\""},{"n":12,"t":"\\"그러나 내가 너희에게 말한다. 엘리야가 이미 왔는데 사람들이 그를 알아보지 못하고 마음대로 대했어. 이와 같이 사람의 아들도 그들에게 고난을 받게 될 거야.\\""},{"n":13,"t":"그제야 제자들이 예수님이 세례 요한에 대해 말씀하신 것을 깨달았어요."},{"n":14,"t":"그들이 무리에게 갔을 때 한 사람이 예수님께 와서 무릎을 꿇고 말했어요."},{"n":15,"t":"\\"주님, 제 아들을 불쌍히 여겨 주세요. 간질로 심하게 고통받고 자주 불이나 물에 빠져요.\\""},{"n":16,"t":"\\"주님의 제자들에게 데리고 왔으나 그들이 고치지 못했어요.\\""},{"n":17,"t":"예수님이 대답하셨어요. \\"믿음 없고 비뚤어진 세대야! 내가 언제까지 너희와 함께 있을까? 언제까지 너희를 참아야 할까? 그를 내게 데려오너라.\\""},{"n":18,"t":"예수님이 귀신을 꾸짖으시자 귀신이 나가고 그 아이가 그 시간부터 나았어요."},{"n":19,"t":"그때 제자들이 예수님께 따로 와서 \\"왜 우리가 그것을 쫓아내지 못했어요?\\" 하고 물었어요."},{"n":20,"t":"예수님이 대답하셨어요. \\"너희 믿음이 적기 때문이야. 진정으로 말한다. 너희에게 겨자씨 한 알만큼의 믿음이 있어도 이 산을 향해 \'여기서 저기로 옮겨라\' 하면 옮겨질 거고, 너희에게 못 할 일이 없을 거야.\\""},{"n":21,"t":"\\"그러나 이 종류는 기도와 금식이 아니면 나가지 않아.\\""},{"n":22,"t":"그들이 갈릴리에 모였을 때 예수님이 말씀하셨어요. \\"사람의 아들이 사람들의 손에 넘겨질 거야.\\""},{"n":23,"t":"\\"그리고 사람들이 그를 죽일 거고, 그가 사흘째 되는 날에 다시 살아날 거야.\\" 제자들이 매우 슬퍼했어요."},{"n":24,"t":"그들이 가버나움에 갔을 때 성전세를 받는 사람들이 베드로에게 와서 \\"너희 선생님은 성전세를 내지 않니?\\" 하고 물었어요."},{"n":25,"t":"베드로가 \\"내요\\" 하고 대답했어요. 베드로가 집에 들어가니 예수님이 먼저 말씀하셨어요. \\"시몬아, 어떻게 생각하니? 세상 임금들이 누구에게서 관세나 세금을 받니? 자기 아들에게서니, 다른 사람에게서니?\\""},{"n":26,"t":"베드로가 \\"다른 사람에게서요\\" 하고 대답하니, 예수님이 \\"그러면 아들들은 면제되는 거야\\" 하고 말씀하셨어요."},{"n":27,"t":"\\"그러나 그들을 걸려 넘어지게 하지 않기 위해, 호수에 가서 낚시를 던지고 먼저 잡힌 물고기의 입을 열어 봐. 한 세겔을 발견할 거야. 그것을 가져다가 나와 너를 위해 그들에게 주어라.\\""}]}},{"chapter":18,"title":"천국에서 큰 자","verses":{"krv":[{"n":1,"t":"그 때에 제자들이 예수께 나아와 가로되 천국에서는 누가 크니이까"},{"n":2,"t":"예수께서 한 어린 아이를 불러 저희 가운데 세우시고"},{"n":3,"t":"가라사대 진실로 너희에게 이르노니 너희가 돌이켜 어린 아이들과 같이 되지 아니하면 결단코 천국에 들어가지 못하리라"},{"n":4,"t":"그러므로 누구든지 이 어린 아이와 같이 자기를 낮추는 그이가 천국에서 큰 자니라"},{"n":5,"t":"또 누구든지 내 이름으로 이런 어린 아이 하나를 영접하면 곧 나를 영접함이니"},{"n":6,"t":"누구든지 나를 믿는 이 소자 중 하나를 실족케 하면 차라리 연자 맷돌을 그 목에 달리우고 깊은 바다에 빠뜨리우는 것이 나으니라"},{"n":7,"t":"실족케 하는 일들이 있음을 인하여 세상에 화가 있도다 실족케 하는 일이 없을 수는 없으나 실족케 하는 그 사람에게는 화가 있도다"},{"n":8,"t":"만일 네 손이나 네 발이 너를 범죄케 하거든 찍어 내버리라 불구자나 절뚝발이로 영생에 들어가는 것이 두 손과 두 발을 가지고 영원한 불에 던지우는 것보다 나으니라"},{"n":9,"t":"만일 네 눈이 너를 범죄케 하거든 빼어 내버리라 한 눈으로 영생에 들어가는 것이 두 눈을 가지고 지옥 불에 던지우는 것보다 나으니라"},{"n":10,"t":"삼가 이 소자 중에 하나도 업신여기지 말라 너희에게 말하노니 저희 천사들이 하늘에서 하늘에계신 내 아버지의 얼굴을 항상 뵈옵느니라"},{"n":11,"t":"(없 음)"},{"n":12,"t":"너희 생각에는 어떻겠느뇨 만일 어떤 사람이 양 일백 마리가 있는데 그 중에 하나가 길을 잃었으면 그 아흔 아홉 마리를 산에 두고 가서 길 잃은 양을 찾지 않겠느냐"},{"n":13,"t":"진실로 너희에게 이르노니 만일 찾으면 길을 잃지 아니한 아흔 아홉 마리보다 이것을 더 기뻐하리라"},{"n":14,"t":"이와 같이 이 소자 중에 하나라도 잃어지는 것은 하늘에 계신 너희 아버지의 뜻이 아니니라"},{"n":15,"t":"네 형제가 죄를 범하거든 가서 너와 그 사람과만 상대하여 권고하라 만일 들으면 네가 네 형제를 얻은 것이요"},{"n":16,"t":"만일 듣지 않거든 한 두 사람을 데리고 가서 두 세 증인의 입으로 말마다 증참케 하라"},{"n":17,"t":"만일 그들의 말도 듣지 않거든 교회에 말하고 교회의 말도 듣지 않거든 이방인과 세리와 같이 여기라"},{"n":18,"t":"진실로 너희에게 이르노니 무엇이든지 너희가 땅에서 매면 하늘에서도 매일 것이요 무엇이든지 땅에서 풀면 하늘에서도 풀리리라"},{"n":19,"t":"진실로 다시 너희에게 이르노니 너희 중에 두 사람이 땅에서 합심하여 무엇이든지 구하면 하늘에 계신 내 아버지께서 저희를 위하여 이루게 하시리라"},{"n":20,"t":"두 세 사람이 내 이름으로 모인 곳에는 나도 그들 중에 있느니라"},{"n":21,"t":"그 때에 베드로가 나아와 가로되 주여 형제가 내게 죄를 범하면 몇번이나 용서하여 주리이까 일곱번까지 하오리이까"},{"n":22,"t":"예수께서 가라사대 네게 이르노니 일곱번 뿐 아니라 일흔번씩 일곱번이라도 할지니라"},{"n":23,"t":"이러므로 천국은 그 종들과 회계하려 하던 어떤 임금과 같으니"},{"n":24,"t":"회계할 때에 일만 달란트 빚진 자 하나를 데려오매"},{"n":25,"t":"갚을 것이 없는지라 주인이 명하여 그 몸과 처와 자식들과 모든 소유를 다 팔아 갚게 하라 한대"},{"n":26,"t":"그 종이 엎드리어 절하며 가로되 내게 참으소서 다 갚으리이다 하거늘"},{"n":27,"t":"그 종의 주인이 불쌍히 여겨 놓아 보내며 그 빚을 탕감하여 주었더니"},{"n":28,"t":"그 종이 나가서 제게 백 데나리온 빚진 동관 하나를 만나 붙들어 목을 잡고 가로되 빚을 갚으라 하매"},{"n":29,"t":"그 동관이 엎드리어 간구하여 가로되 나를 참아 주소서 갚으리이다 하되"},{"n":30,"t":"허락하지 아니하고 이에 가서 저가 빚을 갚도록 옥에 가두거늘"},{"n":31,"t":"그 동관들이 그것을 보고 심히 민망하여 주인에게 가서 그 일을 다 고하니"},{"n":32,"t":"이에 주인이 저를 불러다가 말하되 악한 종아 네가 빌기에 내가 네 빚을 전부 탕감하여 주었거늘"},{"n":33,"t":"내가 너를 불쌍히 여김과 같이 너도 네 동관을 불쌍히 여김이 마땅치 아니하냐 하고"},{"n":34,"t":"주인이 노하여 그 빚을 다 갚도록 저를 옥졸들에게 붙이니라"},{"n":35,"t":"너희가 각각 중심으로 형제를 용서하지 아니하면 내 천부께서도 너희에게 이와 같이 하시리라"}],"kids":[{"n":1,"t":"그때 제자들이 예수님께 와서 \\"천국에서 누가 가장 크나요?\\" 하고 물었어요."},{"n":2,"t":"예수님이 어린아이 하나를 불러 그들 가운데 세우시고,"},{"n":3,"t":"말씀하셨어요. \\"진정으로 말한다. 너희가 돌이켜 어린아이들과 같이 되지 않으면 결코 천국에 들어가지 못할 거야.\\""},{"n":4,"t":"\\"그러므로 누구든지 이 어린아이처럼 자기를 낮추는 사람이 천국에서 가장 큰 사람이야.\\""},{"n":5,"t":"\\"누구든지 내 이름으로 이런 어린아이 하나를 받아들이는 사람은 나를 받아들이는 거야.\\""},{"n":6,"t":"\\"누구든지 나를 믿는 이 작은 사람 중 하나를 걸려 넘어지게 하면, 차라리 큰 맷돌을 목에 매고 깊은 바다에 빠지는 것이 나아.\\""},{"n":7,"t":"\\"걸림돌 때문에 세상에 화가 있다! 걸림돌이 있는 것은 어쩔 수 없지만, 걸림돌을 놓는 그 사람에게는 화가 있다!\\""},{"n":8,"t":"\\"네 손이나 발이 너를 죄짓게 하거든 잘라 버려라. 두 손 두 발을 가지고 영원한 불에 던져지는 것보다 절름발이나 외팔로 생명에 들어가는 게 나아.\\""},{"n":9,"t":"\\"네 눈이 너를 죄짓게 하거든 빼서 버려라. 두 눈을 가지고 지옥 불에 던져지는 것보다 한 눈으로 생명에 들어가는 게 나아.\\""},{"n":10,"t":"\\"이 작은 사람들 중 하나라도 업신여기지 않도록 조심해. 내가 너희에게 말한다. 그들의 천사들이 하늘에서 항상 내 하늘 아버지의 얼굴을 보고 있어.\\""},{"n":11,"t":"\\"사람의 아들이 잃은 자를 구원하러 왔어.\\""},{"n":12,"t":"\\"어떻게 생각하니? 어떤 사람에게 양 백 마리가 있는데 그중 한 마리가 길을 잃었다면, 그가 아흔아홉 마리를 산에 두고 가서 길 잃은 양을 찾지 않겠니?\\""},{"n":13,"t":"\\"진정으로 말한다. 만약 그것을 찾으면 길을 잃지 않은 아흔아홉보다 그것 때문에 더 기뻐할 거야.\\""},{"n":14,"t":"\\"이와 같이 이 작은 사람 중 하나라도 잃는 것은 하늘에 계신 너희 아버지의 뜻이 아니야.\\""},{"n":15,"t":"\\"네 형제가 너에게 잘못하거든 가서 너와 그 사이에 단둘이 있을 때 잘못을 말해 줘. 그가 들으면 네가 그 형제를 얻은 거야.\\""},{"n":16,"t":"\\"그러나 듣지 않거든 한두 사람을 데리고 가서 두세 증인의 입으로 모든 말을 확인해.\\""},{"n":17,"t":"\\"만약 그들의 말도 듣지 않거든 교회에 말하고, 교회의 말도 듣지 않거든 이방인이나 세리처럼 여겨라.\\""},{"n":18,"t":"\\"진정으로 말한다. 너희가 땅에서 매면 하늘에서도 매이고, 너희가 땅에서 풀면 하늘에서도 풀릴 거야.\\""},{"n":19,"t":"\\"또 말한다. 너희 중 두 사람이 땅에서 합심하여 무엇이든지 구하면 하늘에 계신 내 아버지께서 그들을 위해 이루어 주실 거야.\\""},{"n":20,"t":"\\"두세 사람이 내 이름으로 모인 곳에는 나도 그들 가운데 있어.\\""},{"n":21,"t":"그때 베드로가 와서 \\"주님, 형제가 저에게 잘못하면 몇 번이나 용서해 줘야 해요? 일곱 번까지요?\\" 하고 물었어요."},{"n":22,"t":"예수님이 대답하셨어요. \\"네게 말한다. 일곱 번뿐 아니라 일흔 번씩 일곱 번이라도 해야 해.\\""},{"n":23,"t":"\\"그러므로 천국은 자기 종들과 셈을 가리려고 한 임금에 비유할 수 있어.\\""},{"n":24,"t":"\\"셈을 시작할 때 만 달란트 빚진 사람 하나가 끌려왔어.\\""},{"n":25,"t":"\\"그가 갚을 수 없으니, 주인이 그와 아내와 자녀들과 모든 소유를 팔아 갚으라고 명령했어.\\""},{"n":26,"t":"\\"그 종이 엎드려 절하며 \'참아 주세요. 다 갚을게요\' 하고 간청했어.\\""},{"n":27,"t":"\\"주인이 그 종을 불쌍히 여겨 그를 풀어 주고 빚을 탕감해 주었어.\\""},{"n":28,"t":"\\"그런데 그 종이 나가서 자기에게 백 데나리온 빚진 동료 한 사람을 만나, 잡고 목을 졸라 \'내게 빚진 것을 갚아라\' 하고 말했어.\\""},{"n":29,"t":"\\"그 동료가 엎드려 \'참아 줘. 갚을게\' 하고 간청했지만,\\""},{"n":30,"t":"\\"그가 들으려 하지 않고 가서 그 빚을 다 갚을 때까지 감옥에 가두었어.\\""},{"n":31,"t":"\\"동료 종들이 보고 매우 슬퍼서 자기들의 주인에게 가서 모든 일을 알렸어.\\""},{"n":32,"t":"\\"주인이 그 종을 불러 말했어. \'악한 종아, 네가 빌었기에 내가 그 모든 빚을 탕감해 주었는데,\\""},{"n":33,"t":"\\"내가 너를 불쌍히 여긴 것 같이 너도 동료를 불쌍히 여겼어야 하지 않니?\'\\""},{"n":34,"t":"\\"주인이 화가 나서 그 빚을 다 갚을 때까지 그를 감옥지기에게 넘겼어.\\""},{"n":35,"t":"\\"너희가 각각 마음으로부터 자기 형제를 용서하지 않으면 내 하늘 아버지께서도 너희에게 그렇게 하실 거야.\\""}]}},{"chapter":19,"title":"결혼과 어린아이 축복","verses":{"krv":[{"n":1,"t":"예수께서 이 말씀을 마치시고 갈릴리에서 떠나 요단강 건너 유대 지경에 이르시니"},{"n":2,"t":"큰 무리가 좇거늘 예수께서 거기서 저희 병을 고치시더라"},{"n":3,"t":"바리새인들이 예수께 나아와 그를 시험하여 가로되 사람이 아무 연고를 물론하고 그 아내를 내어버리는 것이 옳으니이까"},{"n":4,"t":"예수께서 대답하여 가라사대 사람을 지으신 이가 본래 저희를 남자와 여자로 만드시고"},{"n":5,"t":"말씀하시기를 이러므로 사람이 그 부모를 떠나서 아내에게 합하여 그 둘이 한 몸이 될지니라 하신 것을 읽지 못하였느냐"},{"n":6,"t":"이러한즉 이제 둘이 아니요 한 몸이니 그러므로 하나님이 짝지어 주신 것을 사람이 나누지 못할지니라 하시니"},{"n":7,"t":"여짜오되 그러하면 어찌하여 모세는 이혼 증서를 주어서 내어버리라 명하였나이까"},{"n":8,"t":"예수께서 가라사대 모세가 너희 마음의 완악함을 인하여 아내 내어버림을 허락하였거니와 본래는 그렇지 아니하니라"},{"n":9,"t":"내가 너희에게 말하노니 누구든지 음행한 연고 외에 아내를 내어버리고 다른데 장가 드는 자는 간음함이니라"},{"n":10,"t":"제자들이 가로되 만일 사람이 아내에게 이같이 할진대 장가 들지 않는 것이 좋삽나이다"},{"n":11,"t":"예수께서 가라사대 사람마다 이 말을 받지 못하고 오직 타고난 자라야 할지니라"},{"n":12,"t":"어미의 태로부터 된 고자도 있고 사람이 만든 고자도 있고 천국을 위하여 스스로 된 고자도 있도다 이 말을 받을만한 자는 받을지어다"},{"n":13,"t":"때에 사람들이 예수의 안수하고 기도하심을 바라고 어린 아이들을 데리고 오매 제자들이 꾸짖거늘"},{"n":14,"t":"예수께서 가라사대 어린 아이들을 용납하고 내게 오는 것을 금하지 말라 천국이 이런 자의 것이니라 하시고"},{"n":15,"t":"저희 위에 안수하시고 거기서 떠나시니라"},{"n":16,"t":"어떤 사람이 주께 와서 가로되 선생님이여 내가 무슨 선한 일을 하여야 영생을 얻으리이까"},{"n":17,"t":"예수께서 가라사대 어찌하여 선한 일을 내게 묻느냐 선한이는 오직 한 분이시니라 네가 생명에 들어 가려면 계명들을 지키라"},{"n":18,"t":"가로되 어느 계명이오니이까 예수께서 가라사대 살인하지 말라, 간음하지 말라, 도적질하지 말라, 거짓증거하지 말라,"},{"n":19,"t":"네 부모를 공경하라 네 이웃을 네 몸과 같이 사랑하라 하신 것이니라"},{"n":20,"t":"그 청년이 가로되 이 모든 것을 내가 지키었사오니 아직도 무엇이 부족하니이까"},{"n":21,"t":"예수께서 가라사대 네가 온전하고자 할진대 가서 네 소유를 팔아 가난한 자들을 주라 그리하면 하늘에서 보화가 네게 있으리라 그리고 와서 나를 좇으라 하시니"},{"n":22,"t":"그 청년이 재물이 많으므로 이 말씀을 듣고 근심하며 가니라"},{"n":23,"t":"예수께서 제자들에게 이르시되 내가 진실로 너희에게 이르노니 부자는 천국에 들어가기가 어려우니라"},{"n":24,"t":"다시 너희에게 말하노니 약대가 바늘귀로 들어가는 것이 부자가 하나님의 나라에 들어가는 것보다 쉬우니라 하신대"},{"n":25,"t":"제자들이 듣고 심히 놀라 가로되 그런즉 누가 구원을 얻을 수 있으리이까"},{"n":26,"t":"예수께서 저희를 보시며 가라사대 사람으로는 할 수 없으되 하나님으로서는 다 할 수 있느니라"},{"n":27,"t":"이에 베드로가 대답하여 가로되 보소서 우리가 모든 것을 버리고 주를 좇았사오니 그런즉 우리가 무엇을 얻으리이까"},{"n":28,"t":"예수께서 가라사대 내가 진실로 너희에게 이르노니 세상이 새롭게 되어 인자가 자기 영광의 보좌에 앉을 때에 나를 좇는 너희도 열 두 보좌에 앉아 이스라엘 열 두 지파를 심판하리라"},{"n":29,"t":"또 내 이름을 위하여 집이나 형제나 자매나 부모나 자식이나 전토를 버린 자마다 여러 배를 받고 또 영생을 상속하리라"},{"n":30,"t":"그러나 먼저 된 자로서 나중 되고 나중 된 자로서 먼저 될 자가 많으니라"}],"kids":[{"n":1,"t":"예수님이 이 말씀을 마치시고 갈릴리를 떠나 요단강 건너편 유대 지역으로 가셨어요."},{"n":2,"t":"큰 무리가 그분을 따라오자 거기서 그들을 고쳐 주셨어요."},{"n":3,"t":"바리새인들이 와서 예수님을 시험하려고 \\"어떤 이유로든 사람이 자기 아내를 버리는 것이 합법인가요?\\" 하고 물었어요."},{"n":4,"t":"예수님이 대답하셨어요. \\"너희가 읽지 않았니? 처음부터 사람을 지으신 분이 그들을 남자와 여자로 만드시고,\\""},{"n":5,"t":"\\"\'그래서 사람이 자기 부모를 떠나 그의 아내와 합하여 둘이 한 몸이 될 거야\'라고 말씀하셨어.\\""},{"n":6,"t":"\\"그러므로 그들이 더 이상 둘이 아니라 한 몸이야. 그러니까 하나님이 짝지어 주신 것을 사람이 갈라놓지 마라.\\""},{"n":7,"t":"바리새인들이 \\"그러면 모세는 왜 이혼증서를 주고 버리라고 명령했어요?\\" 하고 물었어요."},{"n":8,"t":"예수님이 대답하셨어요. \\"너희 마음이 굳어서 모세가 아내를 버리는 것을 허락했지만 처음부터 그렇지 않았어.\\""},{"n":9,"t":"\\"내가 너희에게 말한다. 음란한 일 외에 아내를 버리고 다른 여자와 결혼하는 사람은 간음하는 거야.\\""},{"n":10,"t":"제자들이 \\"사람과 아내의 관계가 그렇다면 결혼하지 않는 것이 좋겠어요\\" 하고 말했어요."},{"n":11,"t":"예수님이 대답하셨어요. \\"모든 사람이 이 말을 받아들이는 게 아니라 받게 된 사람만 받아.\\""},{"n":12,"t":"\\"태어날 때부터 결혼하지 않는 사람도 있고, 사람들에 의해 그렇게 된 사람도 있고, 천국을 위해 스스로 그렇게 한 사람도 있어. 받을 수 있는 사람은 받아라.\\""},{"n":13,"t":"그때 사람들이 예수님이 손을 얹고 기도해 주시도록 어린아이들을 데리고 왔는데 제자들이 막았어요."},{"n":14,"t":"예수님이 \\"어린아이들을 가만 두고 내게 오는 것을 막지 마. 천국은 이런 사람들의 것이야\\" 하고 말씀하셨어요."},{"n":15,"t":"그리고 그들에게 손을 얹어 주신 후에 그곳을 떠나셨어요."},{"n":16,"t":"한 사람이 와서 \\"선생님, 영생을 얻으려면 무슨 선한 일을 해야 해요?\\" 하고 물었어요."},{"n":17,"t":"예수님이 \\"왜 내게 선한 것에 대해 묻니? 선하신 분은 한 분이셔. 네가 생명에 들어가려면 계명들을 지켜라\\" 하고 대답하셨어요."},{"n":18,"t":"그가 \\"어느 것들이요?\\" 하고 묻자, 예수님이 \\"살인하지 말라, 간음하지 말라, 도둑질하지 말라, 거짓 증언하지 말라,\\""},{"n":19,"t":"\\"네 부모를 공경하라, 네 이웃을 네 몸처럼 사랑하라\\" 하셨어요."},{"n":20,"t":"그 청년이 \\"이 모든 것을 다 지켰는데 아직 무엇이 부족해요?\\" 하고 말했어요."},{"n":21,"t":"예수님이 \\"네가 온전해지려거든 가서 네가 가진 것을 팔아 가난한 사람에게 주어라. 그러면 하늘에 보물이 있을 거야. 그런 후에 와서 나를 따르라\\" 하고 말씀하셨어요."},{"n":22,"t":"청년이 이 말씀을 듣고 슬퍼하며 떠났어요. 그는 재산이 많았기 때문이에요."},{"n":23,"t":"예수님이 제자들에게 \\"진정으로 말한다. 부자는 천국에 들어가기 어려워\\" 하고 말씀하셨어요."},{"n":24,"t":"\\"다시 말한다. 부자가 하나님 나라에 들어가는 것보다 낙타가 바늘귀로 들어가는 것이 더 쉬워.\\""},{"n":25,"t":"제자들이 듣고 매우 놀라서 \\"그러면 누가 구원받을 수 있어요?\\" 하고 말했어요."},{"n":26,"t":"예수님이 그들을 보시고 \\"사람으로는 할 수 없지만 하나님께는 모든 것이 가능해\\" 하고 말씀하셨어요."},{"n":27,"t":"베드로가 \\"보세요, 우리는 모든 것을 버리고 주님을 따랐어요. 그러면 우리에게 무엇이 있을까요?\\" 하고 말했어요."},{"n":28,"t":"예수님이 대답하셨어요. \\"진정으로 말한다. 새 세상에서 사람의 아들이 그분의 영광의 보좌에 앉을 때, 나를 따른 너희도 열두 보좌에 앉아 이스라엘 열두 지파를 다스릴 거야.\\""},{"n":29,"t":"\\"내 이름을 위해 집이나 형제나 자매나 아버지나 어머니나 자녀나 토지를 버린 사람마다 백 배를 받고 영생을 물려받을 거야.\\""},{"n":30,"t":"\\"그러나 먼저 된 사람으로서 나중 되고, 나중 된 사람으로서 먼저 될 사람이 많을 거야.\\""}]}},{"chapter":20,"title":"포도원 품꾼 비유","verses":{"krv":[{"n":1,"t":"천국은 마치 품군을 얻어 포도원에 들여 보내려고 이른 아침에 나간 집 주인과 같으니"},{"n":2,"t":"저가 하루 한 데나리온씩 품군들과 약속하여 포도원에 들여 보내고"},{"n":3,"t":"또 제 삼시에 나가 보니 장터에 놀고 섰는 사람들이 또 있는지라"},{"n":4,"t":"저희에게 이르되 너희도 포도원에 들어가라 내가 너희에게 상당하게 주리라 하니 저희가 가고"},{"n":5,"t":"제 육시와 제 구시에 또 나가 그와 같이 하고"},{"n":6,"t":"제 십일시에도 나가 보니 섰는 사람들이 또 있는지라"},{"n":7,"t":"가로되 너희는 어찌하여 종일토록 놀고 여기 섰느뇨 가로되 우리를 품군으로 쓰는 이가 없음이니이다 가로되 너희도 포도원에 들어가라 하니라"},{"n":8,"t":"저물매 포도원 주인이 청지기에게 이르되 품군들을 불러 나중 온 자로부터 시작하여 먼저 온 자까지 삯을 주라 하니"},{"n":9,"t":"제 십일시에 온 자들이 와서 한 데나리온씩을 받거늘"},{"n":10,"t":"먼저 온 자들이 와서 더 받을 줄 알았더니 저희도 한 데나리온씩 받은지라"},{"n":11,"t":"받은 후 집 주인을 원망하여 가로되"},{"n":12,"t":"나중 온 이 사람들은 한 시간만 일하였거늘 저희를 종일 수고와 더위를 견딘 우리와 같게 하였나이다"},{"n":13,"t":"주인이 그 중의 한 사람에게 대답하여 가로되 친구여 내가 네게 잘못한 것이 없노라 네가 나와 한 데나리온의 약속을 하지 아니하였느냐"},{"n":14,"t":"네 것이나 가지고 가라 나중 온 이 사람에게 너와 같이 주는 것이 내 뜻이니라"},{"n":15,"t":"내 것을 가지고 내 뜻대로 할 것이 아니냐 내가 선하므로 네가 악하게 보느냐"},{"n":16,"t":"이와 같이 나중 된 자로서 먼저 되고 먼저 된 자로서 나중 되리라"},{"n":17,"t":"예수께서 예루살렘으로 올라가려 하실 때에 열 두 제자를 따로 데리시고 길에서 이르시되"},{"n":18,"t":"보라 우리가 예루살렘으로 올라가노니 인자가 대제사장들과 서기관들에게 넘기우매 저희가 죽이기로 결안하고"},{"n":19,"t":"이방인들에게 넘겨주어 그를 능욕하며 채찍질하며 십자가에 못 박게 하리니 제 삼일에 살아나리라"},{"n":20,"t":"그 때에 세베대의 아들의 어미가 그 아들들을 데리고 예수께 와서 절하며 무엇을 구하니"},{"n":21,"t":"예수께서 가라사대 무엇을 원하느뇨 가로되 이 나의 두 아들을 주의 나라에서 하나는 주의 우편에 하나는 주의 좌편에 앉게 명하소서"},{"n":22,"t":"예수께서 대답하여 가라사대 너희 구하는 것을 너희가 알지 못하는도다 나의 마시려는 잔을 너희가 마실 수 있느냐 저희가 말하되 할 수 있나이다"},{"n":23,"t":"가라사대 너희가 과연 내 잔을 마시려니와 내 좌우편에 앉는 것은 나의 줄것이 아니라 내 아버지께서 누구를 위하여 예비하셨든지 그들이 얻을 것이니라"},{"n":24,"t":"열 제자가 듣고 그 두 형제에 대하여 분히 여기거늘"},{"n":25,"t":"예수께서 제자들을 불러다가 가라사대 이방인의 집권자들이 저희를 임의로 주관하고 그 대인들이 저희에게 권세를 부리는 줄을 너희가 알거니와"},{"n":26,"t":"너희 중에는 그렇지 아니하니 너희 중에 누구든지 크고자 하는 자는 너희를 섬기는 자가 되고"},{"n":27,"t":"너희 중에 누구든지 으뜸이 되고자 하는 자는 너희 종이 되어야 하리라"},{"n":28,"t":"인자가 온것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라"},{"n":29,"t":"저희가 여리고에서 떠나 갈때에 큰 무리가 예수를 좇더라"},{"n":30,"t":"소경 둘이 길 가에 앉았다가 예수께서 지나가신다 함을 듣고 소리질러 가로되 주여 우리를 불쌍히 여기소서 다윗의 자손이여 하니"},{"n":31,"t":"무리가 꾸짖어 잠잠하라 하되 더욱 소리질러 가로되 주여 우리를 불쌍히 여기소서 다윗의 자손이여 하는지라"},{"n":32,"t":"예수께서 머물러 서서 저희를 불러"},{"n":33,"t":"가라사대 너희에게 무엇을 하여 주기를 원하느냐 가로되 주여 우리 눈 뜨기를 원하나이다"},{"n":34,"t":"예수께서 민망히 여기사 저희 눈을 만지시니 곧 보게 되어 저희가 예수를 좇으니라"}],"kids":[{"n":1,"t":"\\"천국은 자기 포도원에 일꾼을 고용하려고 이른 아침에 나간 집주인과 같아.\\""},{"n":2,"t":"\\"그가 일꾼들과 하루 한 데나리온에 약속하고 포도원에 보냈어.\\""},{"n":3,"t":"\\"아홉 시쯤 나가서 시장에 빈둥거리는 다른 사람들을 보고,\\""},{"n":4,"t":"\\"\'너희도 포도원에 가라. 정당한 것을 주겠다\' 하고 말했어. 그들이 갔어.\\""},{"n":5,"t":"\\"열두 시와 오후 세 시쯤 또 나가서 그렇게 했어.\\""},{"n":6,"t":"\\"오후 다섯 시쯤 나가서 또 다른 사람들이 서 있는 것을 보고 \'왜 너희가 하루 종일 빈둥거리며 여기 서 있니?\' 하고 말했어.\\""},{"n":7,"t":"\\"그들이 \'우리를 고용하는 사람이 없어요\' 하고 대답하니, 그가 \'너희도 포도원에 가라\' 하고 말했어.\\""},{"n":8,"t":"\\"저녁이 되자 포도원 주인이 자기 관리인에게 말했어. \'일꾼들을 불러 나중 온 자로부터 시작해 처음 온 자까지 일한 값을 줘.\'\\""},{"n":9,"t":"\\"오후 다섯 시쯤 고용된 사람들이 와서 각각 한 데나리온씩 받았어.\\""},{"n":10,"t":"\\"처음 사람들이 와서 더 많이 받을 줄 알았는데 그들도 각각 한 데나리온씩 받았어.\\""},{"n":11,"t":"\\"그것을 받고는 집주인에게 불평하며,\\""},{"n":12,"t":"\\"\'나중 온 이 사람들은 한 시간밖에 일하지 않았는데, 종일 일하고 더위를 견딘 우리와 같이 대우했어요\' 하고 말했어.\\""},{"n":13,"t":"\\"주인이 그중 한 사람에게 \'친구야, 내가 너를 부당하게 대한 게 아니야. 너와 내가 한 데나리온에 약속하지 않았니?\'\\""},{"n":14,"t":"\\"\'네 것을 가지고 가라. 나중 온 이 사람에게도 너와 같이 주는 것이 내 뜻이야.\\""},{"n":15,"t":"\\"\'내 것으로 내가 원하는 대로 할 권리가 없니? 내가 선해서 네 눈이 악해진 거니?\'\\""},{"n":16,"t":"\\"이처럼 나중 된 사람이 먼저 되고 먼저 된 사람이 나중 될 거야.\\""},{"n":17,"t":"예수님이 예루살렘으로 올라가실 때 길에서 열두 제자를 따로 데리고 말씀하셨어요."},{"n":18,"t":"\\"보라, 우리가 예루살렘으로 올라간다. 사람의 아들이 대제사장들과 율법 학자들에게 넘겨질 거야. 그들이 그를 사형에 처하기로 정하고,\\""},{"n":19,"t":"\\"이방인들에게 넘겨 조롱하고 채찍질하고 십자가에 못 박게 할 거야. 그러나 사흘째 되는 날에 그가 살아날 거야.\\""},{"n":20,"t":"그때 세베대의 아들들의 어머니가 자기 아들들과 함께 예수님께 와서 절하며 무언가를 청하려 했어요."},{"n":21,"t":"예수님이 \\"무엇을 원하니?\\" 하고 물으셨어요. 그녀가 \\"이 두 아들이 주님의 나라에서 하나는 주님의 오른쪽에, 하나는 왼쪽에 앉게 해 주세요\\" 하고 말했어요."},{"n":22,"t":"예수님이 \\"너희가 무엇을 구하는지 모르는구나. 내가 마시려는 잔을 너희가 마실 수 있겠니?\\" 하고 말씀하셨어요. 그들이 \\"할 수 있어요\\" 하고 대답했어요."},{"n":23,"t":"예수님이 말씀하셨어요. \\"내 잔은 마실 거야. 그러나 내 오른쪽과 왼쪽에 앉는 것은 내가 줄 게 아니라 내 아버지께서 준비하신 사람들에게 주어질 거야.\\""},{"n":24,"t":"열 제자가 듣고 두 형제에게 화가 났어요."},{"n":25,"t":"예수님이 그들을 불러 말씀하셨어요. \\"이방인의 통치자들이 그들을 다스리고 큰 사람들이 권세를 부리는 것을 너희가 알지.\\""},{"n":26,"t":"\\"너희 중에는 그렇지 않아. 너희 중에 누구든 크게 되려는 사람은 너희 종이 되고,\\""},{"n":27,"t":"\\"너희 중에 누구든 첫째가 되려는 사람은 너희 노예가 되어야 해.\\""},{"n":28,"t":"\\"사람의 아들이 섬김을 받으러 온 게 아니라 섬기러 왔고 자기 목숨을 많은 사람의 대속물로 주러 왔어.\\""},{"n":29,"t":"그들이 여리고에서 나갈 때 큰 무리가 예수님을 따라왔어요."},{"n":30,"t":"길가에 앉아 있던 두 맹인이 예수님이 지나가신다는 것을 듣고 \\"주님, 다윗의 자손이여, 우리를 불쌍히 여겨 주세요!\\" 하고 외쳤어요."},{"n":31,"t":"무리가 조용히 하라고 꾸짖었지만, 그들은 더 크게 \\"주님, 다윗의 자손이여, 우리를 불쌍히 여겨 주세요!\\" 하고 외쳤어요."},{"n":32,"t":"예수님이 멈춰 서서 그들을 부르시고 \\"무엇을 해 주기를 원하니?\\" 하고 물으셨어요."},{"n":33,"t":"그들이 \\"주님, 우리 눈이 열리기를 원해요\\" 하고 대답했어요."},{"n":34,"t":"예수님이 불쌍히 여겨 그들의 눈을 만지셨어요. 곧 그들의 눈이 보게 되어 예수님을 따랐어요."}]}},{"chapter":21,"title":"예루살렘 입성과 성전 청결","verses":{"krv":[{"n":1,"t":"저희가 예루살렘에 가까이 와서 감람산 벳바게에 이르렀을 때에 예수께서 두 제자를 보내시며"},{"n":2,"t":"이르시되 너희 맞은편 마을로 가라 곧 매인 나귀와 나귀 새끼가 함께 있는 것을 보리니 풀어 내게로 끌고 오너라"},{"n":3,"t":"만일 누가 무슨 말을 하거든 주가 쓰시겠다 하라 그리하면 즉시 보내리라 하시니"},{"n":4,"t":"이는 선지자로 하신 말씀을 이루려 하심이라 일렀으되"},{"n":5,"t":"시온 딸에게 이르기를 네 왕이 네게 임하나니 그는 겸손하여 나귀, 곧 멍에 메는 짐승의 새끼를 탔도다 하라 하였느니라"},{"n":6,"t":"제자들이 가서 예수의 명하신대로 하여"},{"n":7,"t":"나귀와 나귀 새끼를 끌고 와서 자기들의 겉옷을 그 위에 얹으매 예수께서 그 위에 타시니"},{"n":8,"t":"무리의 대부분은 그 겉옷을 길에 펴며 다른이는 나무 가지를 베어 길에 펴고"},{"n":9,"t":"앞에서 가고 뒤에서 따르는 무리가 소리질러 가로되 호산나 다윗의 자손이여 찬송하리로다 주의 이름으로 오시는 이여 가장 높은 곳에서 호산나 하더라"},{"n":10,"t":"예수께서 예루살렘에 들어가시니 온 성이 소동하여 가로되 이는 누구뇨 하거늘"},{"n":11,"t":"무리가 가로되 갈릴리 나사렛에서 나온 선지자 예수라 하니라"},{"n":12,"t":"예수께서 성전에 들어가사 성전 안에서 매매하는 모든 자를 내어 쫓으시며 돈 바꾸는 자들의 상과 비둘기 파는 자들의 의자를 둘러 엎으시고"},{"n":13,"t":"저희에게 이르시되 기록된바 내 집은 기도하는 집이라 일컬음을 받으리라 하였거늘 너희는 강도의 굴혈을 만드는도다 하시니라"},{"n":14,"t":"소경과 저는 자들이 성전에서 예수께 나아오매 고쳐주시니"},{"n":15,"t":"대제사장들과 서기관들이 예수의 하시는 이상한 일과 또 성전에서 소리질러 호산나 다윗의 자손이여 하는 아이들을 보고 분하여"},{"n":16,"t":"예수께 말하되 저희의 하는 말을 듣느뇨 예수께서 가라사대 그렇다 어린 아기와 젖먹이들의 입에서 나오는 찬미를 온전케 하셨나이다 함을 너희가 읽어 본 일이 없느냐 하시고"},{"n":17,"t":"그들을 떠나 성 밖으로 베다니에 가서 거기서 유하시니라"},{"n":18,"t":"이른 아침에 성으로 들어오실 때에 시장하신지라"},{"n":19,"t":"길 가에서 한 무화과나무를 보시고 그리로 가사 잎사귀 밖에 아무 것도 얻지 못하시고 나무에게 이르시되 이제부터 영원토록 네게 열매가 맺지 못하리라 하시니 무화과나무가 곧 마른지라"},{"n":20,"t":"제자들이 보고 이상히 여겨 가로되 무화과나무가 어찌하여 곧 말랐나이까"},{"n":21,"t":"예수께서 대답하여 가라사대 내가 진실로 너희에게 이르노니 만일 너희가 믿음이 있고 의심치 아니하면 이 무화과나무에게 된 이런 일만 할뿐 아니라 이 산더러 들려 바다에 던지우라 하여도 될것이요"},{"n":22,"t":"너희가 기도할 때에 무엇이든지 믿고 구하는 것은 다 받으리라 하시니라"},{"n":23,"t":"예수께서 성전에 들어가 가르치실쌔 대제사장들과 백성의 장로들이 나아와 가로되 네가 무슨 권세로 이런 일을 하느뇨 또 누가 이 권세를 주었느뇨"},{"n":24,"t":"예수께서 대답하시되 나도 한 말을 너희에게 물으리니 너희가 대답하면 나도 무슨 권세로 이런 일을 하는지 이르리라"},{"n":25,"t":"요한의 세례가 어디로서 왔느냐 하늘로서냐 사람에게로서냐 저희가 서로 의논하여 가로되 만일 하늘로서라 하면 어찌하여 저를 믿지 아니하였느냐 할것이요"},{"n":26,"t":"만일 사람에게로서라 하면 모든 사람이 요한을 선지자로 여기니 백성이 무섭다 하여"},{"n":27,"t":"예수께 대답하여 가로되 우리가 알지 못하노라 하니 예수께서 가라사대 나도 무슨 권세로 이런 일을 하는지 너희에게 이르지 아니하리라"},{"n":28,"t":"그러나 너희 생각에는 어떠하뇨 한 사람이 두 아들이 있는데 맏아들에게 가서 이르되 얘 오늘 포도원에 가서 일하라 하니"},{"n":29,"t":"대답하여 가로되 아버지여 가겠소이다 하더니 가지 아니하고"},{"n":30,"t":"둘째 아들에게 가서 또 이같이 말하니 대답하여 가로되 싫소이다 하더니 그 후에 뉘우치고 갔으니"},{"n":31,"t":"그 둘 중애 누가 아비의 뜻대로 하였느뇨 가로되 둘째 아들이니이다 예수께서 저희에게 이르시되 내가 진실로 너희에게 이르노니 세리들과 창기들이 너희보다 먼저 하나님의 나라에 들어가리라"},{"n":32,"t":"요한이 의의 도로 너희에게 왔거늘 너희는 저를 믿지 아니하였으되 세리와 창기는 믿었으며 너희는 이것을 보고도 종시 뉘우쳐 믿지 아니하였도다"},{"n":33,"t":"다시 한 비유를 들으라 한 집 주인이 포도원을 만들고 산울로 두르고 거기 즙 짜는 구유를 파고 망대를 짓고 농부들에게 세로 주고 타국에 갔더니"},{"n":34,"t":"실과 때가 가까우매 그 실과를 받으려고 자기 종들을 농부들에게 보내니"},{"n":35,"t":"농부들이 종들을 잡아 하나는 심히 때리고 하나는 죽이고 하나는 돌로 쳤거늘"},{"n":36,"t":"다시 다른 종들을 처음보다 많이 보내니 저희에게도 그렇게 하였는지라"},{"n":37,"t":"후에 자기 아들을 보내며 가로되 저희가 내 아들은 공경하리라 하였더니"},{"n":38,"t":"농부들이 그 아들을 보고 서로 말하되 이는 상속자니 자 죽이고 그의 유업을 차지하자 하고"},{"n":39,"t":"이에 잡아 포도원 밖에 내어쫓아 죽였느니라"},{"n":40,"t":"그러면 포도원 주인이 올 때에 이 농부들을 어떻게 하겠느뇨"},{"n":41,"t":"저희가 말하되 이 악한 자들을 진멸하고 포도원은 제때에 실과를 바칠만한 다른 농부들에게 세로 줄찌니이다"},{"n":42,"t":"예수께서 가라사대 너희가 성경에 건축자들의 버린 돌이 모퉁이의 머릿돌이 되었나니 이것은 주로 말미암아 된것이요 우리 눈에 기이하도다 함을 읽어 본 일이 없느냐"},{"n":43,"t":"그러므로 내가 너희에게 이르노니 하나님의 나라를 너희는 빼앗기고 그 나라의 열매 맺는 백성이 받으리라"},{"n":44,"t":"이 돌 위에 떨어지는 자는 깨어지겠고 이 돌이 사람 위에 떨어지면 저를 가루로 만들어 흩으리라 하시니"},{"n":45,"t":"대제사장들과 바리새인들이 예수의 비유를 듣고 자기들을 가리켜 말씀하심인줄 알고"},{"n":46,"t":"잡고자 하나 무리를 무서워하니 이는 저희가 예수를 선지자로 앎이었더라"}],"kids":[{"n":1,"t":"그들이 예루살렘 가까이 가서 감람산에 있는 벳바게에 이르렀을 때, 예수님이 두 제자를 보내며,"},{"n":2,"t":"\\"맞은편 마을로 가라. 곧 매여 있는 나귀와 그 곁에 새끼를 발견할 거야. 풀어서 내게 끌고 와.\\""},{"n":3,"t":"\\"누가 무어라 하거든 \'주님께서 쓰십니다\' 하고 답해라. 그러면 곧 보낼 거야.\\""},{"n":4,"t":"이는 예언자를 통해 하신 말씀이 이루어진 거예요."},{"n":5,"t":"\\"시온 딸에게 말하라. 보라, 네 임금이 네게 오신다. 온유하셔서 나귀를 타고 어린 나귀, 곧 짐 싣는 짐승의 새끼를 타고 오신다.\\""},{"n":6,"t":"제자들이 가서 예수님이 명하신 대로 하고,"},{"n":7,"t":"나귀와 새끼를 끌고 와 그 위에 자기 옷을 얹으니, 예수님이 그 위에 앉으셨어요."},{"n":8,"t":"많은 무리가 자기 옷을 길에 펴고, 다른 사람들은 나뭇가지를 잘라 길에 폈어요."},{"n":9,"t":"앞서 가고 뒤따르는 무리들이 외쳤어요. \\"호산나 다윗의 자손이여! 주의 이름으로 오시는 분에게 복이 있다! 가장 높은 곳에서 호산나!\\""},{"n":10,"t":"예수님이 예루살렘에 들어가시자 온 도시가 \\"이가 누구냐?\\" 하고 술렁였어요."},{"n":11,"t":"무리가 \\"이분은 갈릴리 나사렛에서 오신 예언자 예수님이다\\" 하고 말했어요."},{"n":12,"t":"예수님이 성전에 들어가 거기서 사고파는 모든 사람들을 내쫓고, 돈 바꾸는 사람들의 상과 비둘기 파는 사람들의 의자를 둘러엎으셨어요."},{"n":13,"t":"그리고 말씀하셨어요. \\"기록되었다. \'내 집은 기도하는 집이라 불릴 거다.\' 그런데 너희가 그것을 강도의 굴로 만들었구나.\\""},{"n":14,"t":"성전에서 맹인과 다리 저는 사람들이 예수님께 나아왔고, 그분이 그들을 고쳐 주셨어요."},{"n":15,"t":"대제사장들과 율법 학자들이 예수님께서 하시는 놀라운 일과 어린아이들이 성전에서 \\"호산나 다윗의 자손이여!\\" 하고 외치는 것을 보고 화가 났어요."},{"n":16,"t":"그들이 \\"이 아이들이 무어라 하는지 듣고 계세요?\\" 하고 묻자, 예수님이 \\"그래. \'어린아이와 젖먹이의 입에서 찬양이 나오게 하셨다\'라는 말을 너희가 읽어 보지 않았니?\\" 하고 말씀하셨어요."},{"n":17,"t":"그리고 그들을 떠나 도시를 나가서 베다니로 가셔서 거기서 머무셨어요."},{"n":18,"t":"이튿날 아침 도시로 돌아오시는 길에 배가 고프셨어요."},{"n":19,"t":"길가의 무화과나무 한 그루를 보시고 가까이 가셨지만 잎사귀 외에 아무것도 없었어요. 예수님이 \\"이제부터 영원히 너에게서 열매가 나지 않을 거다\\" 하고 말씀하시자, 무화과나무가 곧 말라 버렸어요."},{"n":20,"t":"제자들이 보고 놀라며 \\"무화과나무가 어떻게 이렇게 곧 말랐어요?\\" 하고 말했어요."},{"n":21,"t":"예수님이 대답하셨어요. \\"진정으로 말한다. 너희에게 믿음이 있고 의심하지 않으면 이 무화과나무에 한 일뿐 아니라 이 산에게 \'여기서 들려 바다에 던져져라\' 해도 될 거야.\\""},{"n":22,"t":"\\"기도 가운데 너희가 믿고 구하는 것은 무엇이든 다 받을 거야.\\""},{"n":23,"t":"예수님이 성전에 들어가 가르치실 때 대제사장들과 백성의 장로들이 와서 \\"무슨 권세로 이런 일을 하나요? 누가 이 권세를 주었나요?\\" 하고 물었어요."},{"n":24,"t":"예수님이 \\"나도 한 가지 물을 게 있어. 너희가 답하면 내가 무슨 권세로 이런 일을 하는지 말해 줄게.\\""},{"n":25,"t":"\\"요한의 세례는 어디서 왔니? 하늘에서니, 사람에게서니?\\" 그들이 서로 의논하며 말했어요. \\"우리가 \'하늘에서\' 하면 \'왜 그를 믿지 않았니?\' 할 거야.\\""},{"n":26,"t":"\\"\'사람에게서\'라고 하기에는 무리가 두려워. 다 요한을 예언자로 여기거든.\\""},{"n":27,"t":"그래서 그들이 \\"모르겠어요\\" 하고 대답하니, 예수님이 \\"그러면 나도 무슨 권세로 이런 일을 하는지 너희에게 말하지 않겠다\\" 하고 말씀하셨어요."},{"n":28,"t":"\\"너희 생각은 어떠니? 어떤 사람에게 두 아들이 있는데, 큰아들에게 가서 \'얘야, 오늘 포도원에 가서 일해\' 하고 말했어.\\""},{"n":29,"t":"\\"그가 \'싫어요\' 하고 답했지만 나중에 마음을 바꿔 갔어.\\""},{"n":30,"t":"\\"둘째에게도 와서 똑같이 말하니, 그가 \'예, 아버지\' 하고 답했지만 가지 않았어.\\""},{"n":31,"t":"\\"이 둘 중 누가 아버지의 뜻대로 했니?\\" 그들이 \\"첫째요\\" 하고 답했어요. 예수님이 \\"진정으로 말한다. 세리와 창녀들이 너희보다 먼저 하나님 나라에 들어간다.\\""},{"n":32,"t":"\\"요한이 너희에게 의의 길로 왔지만 너희는 그를 믿지 않았고, 세리와 창녀는 믿었어. 너희는 보고도 끝까지 회개하여 그를 믿지 않았다.\\""},{"n":33,"t":"\\"또 다른 비유를 들어 봐. 한 집주인이 포도원을 만들고 둘레에 울타리를 치고 포도즙 짜는 곳을 파고 망대를 세운 뒤 농부들에게 빌려 주고 멀리 떠났어.\\""},{"n":34,"t":"\\"열매 때가 가까이 오자 자기 열매를 받으려고 종들을 농부들에게 보냈어.\\""},{"n":35,"t":"\\"농부들이 그 종들을 잡아 하나는 때리고 하나는 죽이고 하나는 돌로 쳤어.\\""},{"n":36,"t":"\\"주인이 다시 처음보다 더 많은 종들을 보냈지만 그들도 그렇게 했어.\\""},{"n":37,"t":"\\"마지막으로 자기 아들을 보내며 \'내 아들은 존경하겠지\' 하고 말했어.\\""},{"n":38,"t":"\\"그러나 농부들이 아들을 보고 서로 말했어. \'이 사람은 상속자야. 죽이고 그의 유산을 차지하자.\'\\""},{"n":39,"t":"\\"그들이 아들을 잡아 포도원 밖으로 던지고 죽여 버렸어.\\""},{"n":40,"t":"\\"그러면 포도원 주인이 와서 그 농부들을 어떻게 할까?\\""},{"n":41,"t":"그들이 대답했어요. \\"그 악한 자들을 가차 없이 멸하고 그 포도원을 제때에 열매를 바칠 다른 농부들에게 빌려 줄 거예요.\\""},{"n":42,"t":"예수님이 말씀하셨어요. \\"성경에서 \'건축자들이 버린 돌이 모퉁이의 머릿돌이 되었다. 이것은 주께서 하신 일이고 우리 눈에 놀랍다\'고 한 말을 너희가 읽지 않았니?\\""},{"n":43,"t":"\\"그래서 내가 너희에게 말한다. 하나님 나라가 너희에게서 빼앗겨 그 나라의 열매를 맺는 백성에게 주어질 거야.\\""},{"n":44,"t":"\\"이 돌 위에 떨어지는 사람은 부서지고, 이 돌이 위에 떨어지는 사람은 가루가 될 거야.\\""},{"n":45,"t":"대제사장들과 바리새인들이 예수님의 비유를 듣고 자기들을 가리켜 말씀하신 줄 알았어요."},{"n":46,"t":"그래서 잡으려 했지만 무리가 그를 예언자로 여겼기 때문에 무서워서 못했어요."}]}},{"chapter":22,"title":"가이사의 것과 부활 논쟁","verses":{"krv":[{"n":1,"t":"예수께서 다시 비유로 대답하여 가라사대"},{"n":2,"t":"천국은 마치 자기 아들을 위하여 혼인 잔치를 베푼 어떤 임금과 같으니"},{"n":3,"t":"그 종들을 보내어 그 청한 사람들을 혼인 잔치에 오라 하였더니 오기를 싫어하거늘"},{"n":4,"t":"다시 다른 종들을 보내며 가로되 청한 사람들에게 이르기를 내가 오찬을 준비하되 나의 소와 살진 짐승을 잡고 모든 것을 갖추었으니 혼인 잔치에 오소서 하라 하였더니"},{"n":5,"t":"저희가 돌아보지도 않고 하나는 자기 밭으로, 하나는 자기 상업차로 가고"},{"n":6,"t":"그 남은 자들은 종들을 잡아 능욕하고 죽이니"},{"n":7,"t":"임금이 노하여 군대를 보내어 그 살인한 자들을 진멸하고 그 동네를 불사르고"},{"n":8,"t":"이에 종들에게 이르되 혼인 잔치는 예비되었으나 청한 사람들은 합당치 아니하니"},{"n":9,"t":"사거리 길에 가서 사람을 만나는대로 혼인 잔치에 청하여 오너라 한대"},{"n":10,"t":"종들이 길에 나가 악한 자나 선한 자나 만나는 대로 모두 데려오니 혼인자리에 손이 가득한지라"},{"n":11,"t":"임금이 손을 보러 들어올쌔 거기서 예복을 입지 않은 한 사람을 보고"},{"n":12,"t":"가로되 친구여 어찌하여 예복을 입지 않고 여기 들어왔느냐 하니 저가 유구무언이어늘"},{"n":13,"t":"임금이 사환들에게 말하되 그 수족을 결박하여 바깥 어두움에 내어 던지라 거기서 슬피 울며 이를 갊이 있으리라 하니라"},{"n":14,"t":"청함을 받은 자는 많되 택함을 입은 자는 적으니라"},{"n":15,"t":"이에 바리새인들이 가서 어떻게 하여 예수로 말의 올무에 걸리게 할까 상론하고"},{"n":16,"t":"자기 제자들을 헤롯 당원들과 함께 예수께 보내어 말하되 선생님이여 우리가 아노니 당신은 참되시고 참으로써 하나님의 도를 가르치시며 아무라도 꺼리는 일이 없으시니 이는 사람을 외모로 보지 아니하심이니이다"},{"n":17,"t":"그러면 당신의 생각에는 어떠한지 우리에게 이르소서 가이사에게 세를 바치는 것이 가하니이까 불가하니이까 한대"},{"n":18,"t":"예수께서 저희의 악함을 아시고 가라사대 외식하는 자들아 어찌하여 나를 시험하느냐"},{"n":19,"t":"셋돈을 내게 보이라 하시니 데나리온 하나를 가져왔거늘"},{"n":20,"t":"예수께서 말씀하시되 이 형상과 이 글이 뉘 것이냐"},{"n":21,"t":"가로되 가이사의 것이니이다 이에 가라사대 그런즉 가이사의 것은 가이사에게, 하나님의 것은 하나님께 바치라 하시니"},{"n":22,"t":"저희가 이 말씀을 듣고 기이히 여겨 예수를 떠나가니라"},{"n":23,"t":"부활이 없다 하는 사두개인들이 그 날에 예수께 와서 물어 가로되"},{"n":24,"t":"선생님이여 모세가 일렀으되 사람이 만일 자식이 없이 죽으면 그 동생이 그 아내에게 장가들어 형을 위하여 후사를 세울찌니라 하였나이다"},{"n":25,"t":"우리 중에 칠 형제가 있었는데 맏이 장가 들었다가 죽어 후사가 없으므로 그의 아내를 그 동생에게 끼쳐두고"},{"n":26,"t":"그 둘째와 세째로 일곱째까지 그렇게 하다가"},{"n":27,"t":"최후에 그 여자도 죽었나이다"},{"n":28,"t":"그런즉 저희가 다 그를 취하였으니 부활 때에 일곱 중에 뉘 아내가 되리이까"},{"n":29,"t":"예수께서 대답하여 가라사대 너희가 성경도 하나님의 능력도 알지 못하는고로 오해하였도다"},{"n":30,"t":"부활 때에는 장가도 아니가고 시집도 아니가고 하늘에 있는 천사들과 같으니라"},{"n":31,"t":"죽은자의 부활을 의논할찐대 하나님이 너희에게 말씀하신바"},{"n":32,"t":"나는 아브라함의 하나님이요 이삭의 하나님이요 야곱의 하나님이로라 하신 것을 읽어 보지 못하였느냐 하나님은 죽은 자의 하나님이 아니요 산 자의 하나님이시니라 하시니"},{"n":33,"t":"무리가 듣고 그의 가르치심에 놀라더라"},{"n":34,"t":"예수께서 사두개인들로 대답할 수 없게 하셨다 함을 바리새인들이 듣고 모였는데"},{"n":35,"t":"그 중에 한 율법사가 예수를 시험하여 묻되"},{"n":36,"t":"선생님이여 율법 중에 어느 계명이 크니이까"},{"n":37,"t":"예수께서 가라사대 네 마음을 다하고 목숨을 다하고 뜻을 다하여 주 너의 하나님을 사랑하라 하셨으니"},{"n":38,"t":"이것이 크고 첫째 되는 계명이요"},{"n":39,"t":"둘째는 그와 같으니 네 이웃을 네 몸과 같이 사랑하라 하셨으니"},{"n":40,"t":"이 두 계명이 온 율법과 선지자의 강령이니라"},{"n":41,"t":"바리새인들이 모였을 때에 예수께서 그들에게 물으시되"},{"n":42,"t":"너희는 그리스도에 대하여 어떻게 생각하느냐 뉘 자손이냐 대답하되 다윗의 자손이니이다"},{"n":43,"t":"가라사대 그러면 다윗이 성령에 감동하여 어찌 그리스도를 주라 칭하여 말하되"},{"n":44,"t":"주께서 내 주께 이르시되 내가 네 원수를 네 발 아래 둘 때까지 내 우편에 앉았으라 하셨도다 하였느냐"},{"n":45,"t":"다윗이 그리스도를 주라 칭하였은즉 어찌 그의 자손이 되겠느냐 하시니"},{"n":46,"t":"한 말도 능히 대답하는 자가 없고 그 날부터 감히 그에게 묻는 자도 없더라"}],"kids":[{"n":1,"t":"예수님이 또 다시 비유로 그들에게 말씀하셨어요."},{"n":2,"t":"\\"천국은 자기 아들을 위해 잔치를 베푼 임금에 비유할 수 있어.\\""},{"n":3,"t":"\\"그가 자기 종들을 보내 잔치에 초대받은 사람들을 부르게 했지만 그들이 오려 하지 않았어.\\""},{"n":4,"t":"\\"또 다른 종들을 보내며 말했어. \'초대받은 사람들에게 「내가 음식을 다 준비하고 황소와 살진 짐승을 잡았으며 모든 것이 준비되었으니, 잔치에 오십시오」 하고 알려라.\'\\""},{"n":5,"t":"\\"하지만 그들은 신경 쓰지 않고 자기 길로 가 버려, 한 사람은 자기 밭으로, 한 사람은 장사하러 가 버렸어.\\""},{"n":6,"t":"\\"나머지 사람들은 종들을 잡아 모욕하고 죽였어.\\""},{"n":7,"t":"\\"임금이 화가 나서 군대를 보내 그 살인자들을 멸하고 그들의 도시를 불태웠어.\\""},{"n":8,"t":"\\"그러고 종들에게 말했어. \'혼인 잔치는 준비되었는데 초대받은 사람들은 자격이 없다.\\""},{"n":9,"t":"\\"네거리로 가서 만나는 대로 모두 잔치에 청해라.\'\\""},{"n":10,"t":"\\"종들이 나가 길에서 만난 사람을 다 모았는데 악한 사람이나 선한 사람이나 다 모이니 잔치 자리가 손님으로 가득 찼어.\\""},{"n":11,"t":"\\"임금이 손님을 보러 들어왔다가 거기서 혼인 예복을 입지 않은 한 사람을 보고,\\""},{"n":12,"t":"\\"\'친구야, 어떻게 예복을 입지 않고 여기 들어왔니?\' 하고 물었어. 그가 말이 없자,\\""},{"n":13,"t":"\\"임금이 종들에게 말했어. \'그의 손과 발을 묶어 바깥 어둠에 던져라. 거기서 울며 이를 갈게 될 거야.\'\\""},{"n":14,"t":"\\"부름받은 사람은 많지만 택함받은 사람은 적어.\\""},{"n":15,"t":"그때 바리새인들이 가서 어떻게 예수님을 말로 걸려 넘어지게 할까 의논했어요."},{"n":16,"t":"그들이 자기 제자들을 헤롯의 무리와 함께 예수님께 보내어 말했어요. \\"선생님, 우리는 주님이 진실하시고 진리로 하나님의 길을 가르치며 사람을 두려워하지 않으시는 줄 알아요.\\""},{"n":17,"t":"\\"그러니 어떻게 생각하는지 말씀해 주세요. 가이사에게 세금을 내는 것이 합법인가요, 아닌가요?\\""},{"n":18,"t":"예수님이 그들의 악의를 아시고 \\"위선자들아, 왜 나를 시험하니?\\""},{"n":19,"t":"\\"세금으로 내는 돈을 내게 보여 봐\\" 하시자, 그들이 데나리온 하나를 가져왔어요."},{"n":20,"t":"예수님이 \\"이 형상과 글자가 누구의 것이니?\\" 하고 물으셨어요."},{"n":21,"t":"\\"가이사의 것이에요\\" 하고 그들이 답했어요. 예수님이 \\"그러면 가이사의 것은 가이사에게, 하나님의 것은 하나님께 바쳐라\\" 하고 말씀하셨어요."},{"n":22,"t":"그들이 듣고 놀라서 예수님을 떠나 갔어요."},{"n":23,"t":"그날 부활이 없다고 말하는 사두개인들이 예수님께 와서 물었어요."},{"n":24,"t":"\\"선생님, 모세가 \'사람이 자녀 없이 죽으면 그 동생이 형수와 결혼하여 형을 위해 후손을 잇게 하라\'고 했어요.\\""},{"n":25,"t":"\\"우리 가운데 일곱 형제가 있었는데, 첫째가 결혼하고 죽었어요. 후손이 없어 동생이 형수를 아내로 맞았어요.\\""},{"n":26,"t":"\\"둘째도 셋째도, 일곱째까지 그렇게 됐어요.\\""},{"n":27,"t":"\\"그 후에 그 여자도 죽었어요.\\""},{"n":28,"t":"\\"그러면 부활 때 그 여자는 누구의 아내가 돼요? 일곱 다 그녀의 남편이었거든요.\\""},{"n":29,"t":"예수님이 대답하셨어요. \\"너희가 성경도 하나님의 능력도 알지 못해서 잘못 알고 있어.\\""},{"n":30,"t":"\\"부활 때에는 결혼하지도 결혼시키지도 않고 하늘에 있는 천사들과 같아.\\""},{"n":31,"t":"\\"죽은 사람의 부활에 대해 하나님이 너희에게 하신 말씀을 읽어 보지 않았니?\\""},{"n":32,"t":"\\"\'나는 아브라함의 하나님, 이삭의 하나님, 야곱의 하나님이다.\' 하나님은 죽은 사람의 하나님이 아니고 살아 있는 사람의 하나님이셔.\\""},{"n":33,"t":"무리가 듣고 그분의 가르침에 놀랐어요."},{"n":34,"t":"바리새인들이 예수님이 사두개인들을 잠잠하게 하셨다는 소식을 듣고 함께 모였어요."},{"n":35,"t":"그중 한 율법 학자가 예수님을 시험하려고 물었어요."},{"n":36,"t":"\\"선생님, 율법 중에 어느 계명이 큰가요?\\""},{"n":37,"t":"예수님이 대답하셨어요. \\"네 마음을 다하고 목숨을 다하고 뜻을 다하여 주 너의 하나님을 사랑하라.\\""},{"n":38,"t":"\\"이것이 첫째 되고 큰 계명이야.\\""},{"n":39,"t":"\\"둘째도 그와 같으니 \'네 이웃을 네 몸처럼 사랑하라\'야.\\""},{"n":40,"t":"\\"이 두 계명에 모든 율법과 예언자들의 가르침이 달려 있어.\\""},{"n":41,"t":"바리새인들이 모였을 때 예수님이 물으셨어요."},{"n":42,"t":"\\"너희는 그리스도에 대해 어떻게 생각하니? 그는 누구의 자손이니?\\" 그들이 \\"다윗의 자손이요\\" 하고 답했어요."},{"n":43,"t":"예수님이 말씀하셨어요. \\"그러면 다윗이 성령으로 그를 어떻게 주님이라 부르며,\\""},{"n":44,"t":"\\"\'주께서 내 주께 말씀하시기를 「내가 네 원수를 네 발 아래 둘 때까지 내 오른쪽에 앉아라」 하셨다\'라고 한 거니?\\""},{"n":45,"t":"\\"다윗이 그리스도를 주라 부르는데 어떻게 그가 그의 자손이 되겠니?\\""},{"n":46,"t":"아무도 한 마디도 대답하지 못했고, 그날 이후로 감히 다시 묻는 사람이 없었어요."}]}},{"chapter":23,"title":"화 있을진저","verses":{"krv":[{"n":1,"t":"이에 예수께서 무리와 제자들에게 말씀하여 가라사대"},{"n":2,"t":"서기관들과 바리새인들이 모세의 자리에 앉았으니"},{"n":3,"t":"그러므로 무엇이든지 저희의 말하는 바는 행하고 지키되 저희의 하는 행위는 본받지 말라 저희는 말만 하고 행치 아니하며"},{"n":4,"t":"또 무거운 짐을 묶어 사람의 어깨에 지우되 자기는 이것을 한 손가락으로도 움직이려 하지 아니하며"},{"n":5,"t":"저희 모든 행위를 사람에게 보이고자 하여 하나니 곧 그 차는 경문을 넓게 하며 옷술을 크게 하고"},{"n":6,"t":"잔치의 상석과 회당의 상좌와"},{"n":7,"t":"시장에서 문안 받는 것과 사람에게 랍비라 칭함을 받는 것을 좋아하느니라"},{"n":8,"t":"그러나 너희는 랍비라 칭함을 받지 말라 너희 선생은 하나이요 너희는 다 형제니라"},{"n":9,"t":"땅에 있는 자를 아비라 하지 말라 너희 아버지는 하나이시니 곧 하늘에 계신 자시니라"},{"n":10,"t":"또한 지도자라 칭함을 받지 말라 너희 지도자는 하나이니 곧 그리스도니라"},{"n":11,"t":"너희 중에 큰 자는 너희를 섬기는 자가 되어야 하리라"},{"n":12,"t":"누구든지 자기를 높이는 자는 낮아지고 누구든지 자기를 낮추는 자는 높아지리라"},{"n":13,"t":"화 있을찐저 외식하는 서기관들과 바리새인들이여 너희는 천국 문을 사람들 앞에서 닫고 너희도 들어가지 않고 들어가려 하는 자도 들어가지 못하게 하는도다"},{"n":14,"t":"(없 음)"},{"n":15,"t":"화 있을찐저 외식하는 서기관들과 바리새인들이여 너희는 교인 하나를 얻기 위하여 바다와 육지를 두루 다니다가 생기면 너희보다 배나 더 지옥 자식이 되게 하는도다"},{"n":16,"t":"화 있을찐저 소경된 인도자여 너희가 말하되 누구든지 성전으로 맹세하면 아무 일 없거니와 성전의 금으로 맹세하면 지킬지라 하는도다"},{"n":17,"t":"우맹이요 소경들이여 어느 것이 크뇨 그 금이냐 금을 거룩하게 하는 성전이냐"},{"n":18,"t":"너희가 또 이르되 누구든지 제단으로 맹세하면 아무 일 없거니와 그 위에 있는 예물로 맹세하면 지킬찌라 하는도다"},{"n":19,"t":"소경들이여 어느 것이 크뇨 그 예물이냐 예물을 거룩하게 하는 제단이냐"},{"n":20,"t":"그러므로 제단으로 맹세하는 자는 제단과 그 위에 있는 모든 것으로 맹세함이요"},{"n":21,"t":"또 성전으로 맹세하는 자는 성전과 그 안에 계신 이로 맹세함이요"},{"n":22,"t":"또 하늘로 맹세하는 자는 하나님의 보좌와 그 위에 앉으신 이로 맹세함이니라"},{"n":23,"t":"화 있을찐저 외식하는 서기관들과 바리새인들이여 너희가 박하와 회향과 근채의 십일조를 드리되 율법의 더 중한바 의와 인과 신은 버렸도다 그러나 이것도 행하고 저것도 버리지 말아야 할찌니라"},{"n":24,"t":"소경된 인도자여 하루살이는 걸러 내고 약대는 삼키는도다"},{"n":25,"t":"화 있을찐저 외식하는 서기관들과 바리새인들이여 잔과 대접의 겉은 깨끗이 하되 그 안에는 탐욕과 방탕으로 가득하게 하는도다"},{"n":26,"t":"소경된 바리새인아 너는 먼저 안을 깨끗이 하라 그리하면 겉도 깨끗하리라"},{"n":27,"t":"화 있을찐저 외식하는 서기관들과 바리새인들이여 회칠한 무덤 같으니 겉으로는 아름답게 보이나 그 안에는 죽은 사람의 뼈와 모든 더러운 것이 가득하도다"},{"n":28,"t":"이와 같이 너희도 겉으로는 사람에게 옳게 보이되 안으로는 외식과 불법이 가득하도다"},{"n":29,"t":"화 있을찐저 외식하는 서기관들과 바리새인들이여 너희는 선지자들의 무덤을 쌓고 의인들의 비석을 꾸미며 가로되"},{"n":30,"t":"만일 우리가 조상 때에 있었더면 우리는 저희가 선지자의 피를 흘리는데 참예하지 아니하였으리라 하니"},{"n":31,"t":"그러면 너희가 선지자를 죽인 자의 자손 됨을 스스로 증거함이로다"},{"n":32,"t":"너희가 너희 조상의 양을 채우라"},{"n":33,"t":"뱀들아 독사의 새끼들아 너희가 어떻게 지옥의 판결을 피하겠느냐"},{"n":34,"t":"그러므로 내가 너희에게 선지자들과 지혜 있는 자들과 서기관들을 보내매 너희가 그 중에서 더러는 죽이고 십자가에 못 박고 그 중에 더러는 너희 회당에서 채찍질하고 이 동네에서 저 동네로 구박하리라"},{"n":35,"t":"그러므로 의인 아벨의 피로부터 성전과 제단 사이에서 너희가 죽인 바라갸의 아들 사가랴의 피까지 땅 위에서 흘린 의로운 피가 다 너희에게 돌아 가리라"},{"n":36,"t":"내가 진실로 너희에게 이르노니 이것이 다 이 세대에게 돌아가리라"},{"n":37,"t":"예루살렘아 예루살렘아 선지자들을 죽이고 네게 파송된 자들을 돌로 치는 자여 암탉이 그 새끼를 날개 아래 모음 같이 내가 네 자녀를 모으려 한 일이 몇번이냐 그러나 너희가 원치 아니하였도다"},{"n":38,"t":"보라 너희 집이 황폐하여 버린바 되리라"},{"n":39,"t":"내가 너희에게 이르노니 이제부터 너희는 찬송하리로다 주의 이름으로 오시는 이여 할 때까지 나를 보지 못하리라 하시니라"}],"kids":[{"n":1,"t":"그때 예수님이 무리와 제자들에게 말씀하셨어요."},{"n":2,"t":"\\"율법 학자와 바리새인들이 모세의 자리에 앉았어.\\""},{"n":3,"t":"\\"그러니까 그들이 너희에게 말하는 것은 다 행하고 지켜라. 그러나 그들의 행위는 본받지 마. 그들은 말만 하고 행하지 않거든.\\""},{"n":4,"t":"\\"그들은 무거운 짐을 묶어 사람들 어깨에 지우면서도 자기 손가락 하나로도 옮기려 하지 않아.\\""},{"n":5,"t":"\\"그들이 하는 모든 일을 사람들에게 보이려고 해. 자기 경문을 넓게 하고 옷자락의 술을 길게 만들어.\\""},{"n":6,"t":"\\"잔치에서 윗자리, 회당에서 높은 자리를 좋아하고,\\""},{"n":7,"t":"\\"시장에서 인사받는 것과 사람들에게 \'랍비\'라 불리는 것을 좋아해.\\""},{"n":8,"t":"\\"그러나 너희는 랍비라 불리지 마. 너희 선생은 한 분이시고 너희는 다 형제야.\\""},{"n":9,"t":"\\"땅에서 어떤 사람을 너희 아버지라 부르지 마. 너희 아버지는 한 분이시니 하늘에 계신다.\\""},{"n":10,"t":"\\"지도자라 불리지도 마. 너희의 지도자는 한 분, 곧 그리스도시다.\\""},{"n":11,"t":"\\"너희 중에 큰 사람은 너희의 종이 될 거야.\\""},{"n":12,"t":"\\"누구든지 자기를 높이는 사람은 낮아지고 자기를 낮추는 사람은 높아질 거야.\\""},{"n":13,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 너희가 사람들 앞에서 천국 문을 닫고, 너희도 들어가지 않고 들어가려는 사람도 들어가지 못하게 해.\\""},{"n":14,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 너희가 과부의 집을 삼키고 보이기 위해 길게 기도해. 그래서 더 큰 심판을 받을 거야.\\""},{"n":15,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 너희가 한 사람을 개종시키려고 바다와 육지를 두루 다니고, 만들어지면 너희보다 두 배나 더 지옥의 자식으로 만들어.\\""},{"n":16,"t":"\\"화 있을 거야, 너희 맹인 인도자들아! \'성전을 두고 맹세하는 사람은 아무것도 아니지만 성전의 금으로 맹세하는 사람은 책임을 진다\' 하는구나.\\""},{"n":17,"t":"\\"어리석은 맹인들아, 금이 더 크니, 금을 거룩하게 하는 성전이 더 크니?\\""},{"n":18,"t":"\\"또 \'제단을 두고 맹세한 것은 아무것도 아니지만 제단 위의 예물을 두고 맹세하면 책임을 진다\' 하는구나.\\""},{"n":19,"t":"\\"맹인들아, 예물이 더 크니, 예물을 거룩하게 하는 제단이 더 크니?\\""},{"n":20,"t":"\\"그러므로 제단을 두고 맹세하는 사람은 그것과 그 위의 모든 것을 두고 맹세하는 거야.\\""},{"n":21,"t":"\\"성전을 두고 맹세하는 사람은 성전과 그 안에 계시는 분을 두고 맹세하는 거야.\\""},{"n":22,"t":"\\"하늘을 두고 맹세하는 사람은 하나님의 보좌와 그 위에 앉으신 분을 두고 맹세하는 거야.\\""},{"n":23,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 박하와 회향과 근채의 십일조는 드리면서 율법의 더 중요한 것인 정의와 자비와 신실은 버렸어. 이것은 행하고 저것도 빼먹지 말아야 해.\\""},{"n":24,"t":"\\"맹인 인도자들아, 너희는 모기는 걸러 내고 낙타는 삼키는구나.\\""},{"n":25,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 너희가 잔과 그릇의 겉은 깨끗이 하면서 안은 탐욕과 방종으로 가득해.\\""},{"n":26,"t":"\\"눈먼 바리새인이여, 먼저 잔과 그릇의 안을 깨끗이 해라. 그래야 겉도 깨끗해질 거야.\\""},{"n":27,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 너희가 겉만 하얗게 칠한 무덤 같아. 겉으로는 아름답게 보이지만 안에는 죽은 사람의 뼈와 모든 더러운 것이 가득해.\\""},{"n":28,"t":"\\"이처럼 너희도 겉으로는 사람들 앞에서 의로워 보이지만 안은 위선과 불법으로 가득해.\\""},{"n":29,"t":"\\"화 있을 거야, 위선자 율법 학자와 바리새인들아! 너희가 예언자의 무덤을 짓고 의인의 비석을 꾸미고,\\""},{"n":30,"t":"\\"\'우리가 조상의 때에 있었더라면 예언자들의 피 흘리는 일에 가담하지 않았을 것이다\' 하는구나.\\""},{"n":31,"t":"\\"그러므로 너희가 예언자를 죽인 사람의 자손인 것을 스스로 증명하는 거야.\\""},{"n":32,"t":"\\"너희가 너희 조상의 분량을 다 채워라.\\""},{"n":33,"t":"\\"뱀들아, 독사의 자식들아! 어떻게 너희가 지옥의 형벌을 피하겠니?\\""},{"n":34,"t":"\\"그래서 보라, 내가 너희에게 예언자와 지혜자와 율법 학자들을 보내. 너희가 그중 몇은 죽이고 십자가에 못 박고, 몇은 회당에서 채찍질하고 동네에서 동네로 박해할 거야.\\""},{"n":35,"t":"\\"그래서 의인 아벨의 피로부터 너희가 성전과 제단 사이에서 죽인 베레갸의 아들 사가랴의 피까지 땅에 흘린 모든 의로운 피가 너희에게 돌아갈 거야.\\""},{"n":36,"t":"\\"진정으로 말한다. 이 모든 일이 이 세대에 돌아올 거야.\\""},{"n":37,"t":"\\"예루살렘아, 예루살렘아! 예언자들을 죽이고 너에게 보낸 사람을 돌로 치는 자야! 암탉이 새끼들을 자기 날개 아래 모음 같이 내가 네 자녀를 모으려 한 적이 몇 번이었나! 그런데 너희가 원하지 않았다.\\""},{"n":38,"t":"\\"보라, 너희 집이 황폐하게 너희에게 남겨질 거야.\\""},{"n":39,"t":"\\"내가 너희에게 말한다. 너희가 \'주의 이름으로 오시는 분에게 복이 있다\'고 말할 때까지 너희는 다시 나를 보지 못할 거야.\\""}]}},{"chapter":24,"title":"마지막 때에 관한 말씀","verses":{"krv":[{"n":1,"t":"예수께서 성전에서 나와서 가실 때에 제자들이 성전 건물들을 가리켜 보이려고 나아오니"},{"n":2,"t":"대답하여 가라사대 너희가 이 모든 것을 보지 못하느냐 내가 진실로 너희에게 이르노니 돌 하나도 돌 위에 남지 않고 다 무너뜨리우리라"},{"n":3,"t":"예수께서 감람산 위에 앉으셨을 때에 제자들이 종용히 와서 가로되 우리에게 이르소서 어느 때에 이런 일이 있겠사 오며 또 주의 임하심과 세상 끝에는 무슨 징조가 있사오리이까"},{"n":4,"t":"예수께서 대답하여 가라사대 너희가 사람의 미혹을 받지 않도록 주의하라"},{"n":5,"t":"많은 사람이 내 이름으로 와서 이르되 나는 그리스도라 하여 많은 사람을 미혹케 하리라"},{"n":6,"t":"난리와 난리 소문을 듣겠으나 너희는 삼가 두려워 말라 이런 일이 있어야 하되 끝은 아직 아니니라"},{"n":7,"t":"민족이 민족을, 나라가 나라를 대적하여 일어나겠고 처처에 기근과 지진이 있으리니"},{"n":8,"t":"이 모든 것이 재난의 시작이니라"},{"n":9,"t":"그 때에 사람들이 너희를 환난에 넘겨주겠으며 너희를 죽이리니 너희가 내 이름을 위하여 모든 민족에게 미움을 받으리라"},{"n":10,"t":"그 때에 많은 사람이 시험에 빠져 서로 잡아 주고 서로 미워하겠으며"},{"n":11,"t":"거짓 선지자가 많이 일어나 많은 사람을 미혹하게 하겠으며"},{"n":12,"t":"불법이 성하므로 많은 사람의 사랑이 식어지리라"},{"n":13,"t":"그러나 끝까지 견디는 자는 구원을 얻으리라"},{"n":14,"t":"이 천국 복음이 모든 민족에게 증거되기 위하여 온 세상에 전파되리니 그제야 끝이 오리라"},{"n":15,"t":"그러므로 너희가 선지자 다니엘의 말한바 멸망의 가증한 것이 거룩한 곳에 선 것을 보거든(읽는 자는 깨달을찐저)"},{"n":16,"t":"그 때에 유대에 있는 자들은 산으로 도망할찌어다"},{"n":17,"t":"지붕 위에 있는 자는 집안에 있는 물건을 가질러 내려 가지 말며"},{"n":18,"t":"밭에 있는 자는 겉옷을 가질러 뒤로 돌이키지 말찌어다"},{"n":19,"t":"그 날에는 아이 밴 자들과 젖먹이는 자들에게 화가 있으리로다"},{"n":20,"t":"너희의 도망하는 일이 겨울에나 안식일에 되지 않도록 기도하라"},{"n":21,"t":"이는 그 때에 큰 환난이 있겠음이라 창세로부터 지금까지 이런 환난이 없었고 후에도 없으리라"},{"n":22,"t":"그 날들을 감하지 아니할 것이면 모든 육체가 구원을 얻지 못할 것이나 그러나 택하신 자들을 위하여 그 날들을 감하시리라"},{"n":23,"t":"그 때에 사람이 너희에게 말하되 보라 그리스도가 여기 있다 혹 저기 있다 하여도 믿지 말라"},{"n":24,"t":"거짓 그리스도들과 거짓 선지자들이 일어나 큰 표적과 기사를 보이어 할 수만 있으면 택하신 자들도 미혹하게 하리라"},{"n":25,"t":"보라 내가 너희에게 미리 말하였노라"},{"n":26,"t":"그러면 사람들이 너희에게 말하되 보라 그리스도가 광야에 있다 하여도 나가지 말고 보라 골방에 있다 하여도 믿지 말라"},{"n":27,"t":"번개가 동편에서 나서 서편까지 번쩍임 같이 인자의 임함도 그러하리라"},{"n":28,"t":"주검이 있는 곳에는 독수리들이 모일찌니라"},{"n":29,"t":"그 날 환난 후에 즉시 해가 어두워지며 달이 빛을 내지 아니하며 별들이 하늘에서 떨어지며 하늘의 권능들이 흔들리리라"},{"n":30,"t":"그 때에 인자의 징조가 하늘에서 보이겠고 그 때에 땅의 모든 족속들이 통곡하며 그들이 인자가 구름을 타고 능력과 큰 영광으로 오는 것을 보리라"},{"n":31,"t":"저가 큰 나팔 소리와 함께 천사들을 보내리니 저희가 그 택하신 자들을 하늘 이 끝에서 저 끝까지 사방에서 모으리라"},{"n":32,"t":"무화과나무의 비유를 배우라 그 가지가 연하여지고 잎사귀를 내면 여름이 가까운 줄을 아나니"},{"n":33,"t":"이와 같이 너희도 이 모든 일을 보거든 인자가 가까이 곧 문앞에 이른줄 알라"},{"n":34,"t":"내가 진실로 너희에게 말하노니 이 세대가 지나가기 전에 이 일이 다 이루리라"},{"n":35,"t":"천지는 없어지겠으나 내 말은 없어지지 아니하리라"},{"n":36,"t":"그러나 그 날과 그 때는 아무도 모르나니 하늘의 천사들도, 아들도 모르고 오직 아버지만 아시느니라"},{"n":37,"t":"노아의 때와 같이 인자의 임함도 그러하리라"},{"n":38,"t":"홍수 전에 노아가 방주에 들어가던 날까지 사람들이 먹고 마시고 장가 들고 시집 가고 있으면서"},{"n":39,"t":"홍수가 나서 저희를 다 멸하기까지 깨닫지 못하였으니 인자의 임함도 이와 같으리라"},{"n":40,"t":"그 때에 두 사람이 밭에 있으매 하나는 데려감을 당하고 하나는 버려둠을 당할 것이요"},{"n":41,"t":"두 여자가 매를 갈고 있으매 하나는 데려감을 당하고 하나는 버려둠을 당할 것이니라"},{"n":42,"t":"그러므로 깨어 있으라 어느 날에 너희 주가 임할는지"},{"n":43,"t":"너희가 알지 못함이니라 너희도 아는바니 만일 집 주인이 도적이 어느 경점에 올 줄을 알았더면 깨어 있어 그 집을 뚫지 못하게 하였으리라"},{"n":44,"t":"이러므로 너희도 예비하고 있으라 생각지 않은 때에 인자가 오리라"},{"n":45,"t":"충성되고 지혜 있는 종이 되어 주인에게 그 집 사람들을 맡아 때를 따라 양식을 나눠 줄 자가 누구뇨"},{"n":46,"t":"주인이 올 때에 그 종의 이렇게 하는 것을 보면 그 종이 복이 있으리로다"},{"n":47,"t":"내가 진실로 너희에게 이르노니 주인이 그 모든 소유를 저에게 맡기리라"},{"n":48,"t":"만일 그 악한 종이 마음에 생각하기를 주인이 더디 오리라 하여"},{"n":49,"t":"동무들을 때리며 술친구들로 더불어 먹고 마시게 되면"},{"n":50,"t":"생각지 않은 날 알지 못하는 시간에 그 종의 주인이 이르러"},{"n":51,"t":"엄히 때리고 외식하는 자의 받는 율에 처하리니 거기서 슬피 울며 이를 갊이 있으리라"}],"kids":[{"n":1,"t":"예수님이 성전에서 나가실 때 제자들이 성전 건물을 보여 주려고 가까이 왔어요."},{"n":2,"t":"예수님이 \\"이 모든 것을 보지 않니? 진정으로 말한다. 여기 돌 하나도 다른 돌 위에 남지 않고 다 무너질 거야\\" 하고 말씀하셨어요."},{"n":3,"t":"예수님이 감람산에 앉아 계실 때 제자들이 따로 와서 물었어요. \\"이런 일이 언제 일어날까요? 주님이 오시고 세상 끝이 가까이 온 표적은 무엇이에요?\\""},{"n":4,"t":"예수님이 대답하셨어요. \\"누가 너희를 속이지 못하도록 조심해.\\""},{"n":5,"t":"\\"많은 사람이 내 이름으로 와서 \'내가 그리스도다\' 하면서 많은 사람을 미혹할 거야.\\""},{"n":6,"t":"\\"전쟁과 전쟁의 소문을 듣겠지만 두려워하지 마. 그런 일이 일어나야 해. 그러나 끝은 아직 아니야.\\""},{"n":7,"t":"\\"민족이 민족을, 나라가 나라를 거슬러 일어나고 여러 곳에서 기근과 지진이 있을 거야.\\""},{"n":8,"t":"\\"이 모든 것은 재난의 시작이야.\\""},{"n":9,"t":"\\"그때에 사람들이 너희를 환난에 넘기고 죽일 거야. 내 이름 때문에 너희가 모든 민족에게 미움을 받게 될 거야.\\""},{"n":10,"t":"\\"그때 많은 사람이 걸려 넘어지고 서로 배신하고 서로 미워할 거야.\\""},{"n":11,"t":"\\"많은 거짓 예언자가 일어나 많은 사람을 미혹할 거야.\\""},{"n":12,"t":"\\"불법이 많아져서 많은 사람의 사랑이 식어질 거야.\\""},{"n":13,"t":"\\"그러나 끝까지 견디는 사람은 구원을 받을 거야.\\""},{"n":14,"t":"\\"이 천국 복음이 온 세상에 전파되어 모든 민족에게 증언이 될 거야. 그러면 끝이 올 거야.\\""},{"n":15,"t":"\\"그러므로 예언자 다니엘이 말한 멸망의 가증한 것이 거룩한 곳에 서 있는 것을 보거든(읽는 사람은 깨달아야 해),\\""},{"n":16,"t":"\\"그때 유대에 있는 사람들은 산으로 도망쳐.\\""},{"n":17,"t":"\\"지붕 위에 있는 사람은 집 안에 있는 물건을 가지러 내려오지 말고,\\""},{"n":18,"t":"\\"밭에 있는 사람도 자기 옷을 가지러 돌아가지 마.\\""},{"n":19,"t":"\\"그날에 아이 밴 사람들과 젖 먹이는 사람들에게 화가 있을 거야!\\""},{"n":20,"t":"\\"너희의 도망이 겨울이나 안식일에 일어나지 않도록 기도해.\\""},{"n":21,"t":"\\"그때 세상 시작부터 지금까지 없었고 앞으로도 없을 큰 환난이 있을 거야.\\""},{"n":22,"t":"\\"만약 그날들이 줄어들지 않으면 어떤 사람도 구원받지 못할 거야. 그러나 택한 사람을 위해 그날들이 줄어들 거야.\\""},{"n":23,"t":"\\"그때 누가 너희에게 \'여기 그리스도가 있다, 저기 있다\' 해도 믿지 마.\\""},{"n":24,"t":"\\"거짓 그리스도와 거짓 예언자가 일어나 큰 표적과 기사를 보여 가능하면 택한 사람도 미혹할 거야.\\""},{"n":25,"t":"\\"보라, 내가 너희에게 미리 말했다.\\""},{"n":26,"t":"\\"그러므로 누가 너희에게 \'보라, 그가 광야에 있다\' 해도 가지 말고, \'보라, 그가 골방에 있다\' 해도 믿지 마.\\""},{"n":27,"t":"\\"번개가 동에서 서로 비치는 것처럼 사람의 아들의 임함도 그러할 거야.\\""},{"n":28,"t":"\\"주검이 있는 곳에는 독수리가 모일 거야.\\""},{"n":29,"t":"\\"그날의 환난 뒤에 곧 해가 어두워지고 달이 빛을 내지 않고 별들이 하늘에서 떨어지며 하늘의 능력들이 흔들릴 거야.\\""},{"n":30,"t":"\\"그때 사람의 아들의 표적이 하늘에 나타나고 땅의 모든 족속이 통곡할 거야. 사람의 아들이 큰 권능과 영광으로 하늘 구름을 타고 오는 것을 볼 거야.\\""},{"n":31,"t":"\\"그가 큰 나팔 소리와 함께 자기 천사들을 보내 사방에서 자기 택한 사람들을 모을 거야. 하늘 이 끝부터 저 끝까지.\\""},{"n":32,"t":"\\"무화과나무로부터 비유를 배워라. 그 가지가 부드러워지고 잎이 나면 여름이 가까운 줄 알지.\\""},{"n":33,"t":"\\"이처럼 너희도 이 모든 일을 볼 때 사람의 아들이 가까이, 곧 문 앞에 있는 줄 알아라.\\""},{"n":34,"t":"\\"진정으로 말한다. 이 세대가 지나기 전에 이 모든 일이 일어날 거야.\\""},{"n":35,"t":"\\"하늘과 땅은 사라지겠지만 내 말은 결코 사라지지 않을 거야.\\""},{"n":36,"t":"\\"그날과 그때는 아무도 모르고 하늘의 천사들도 아들도 모르고 오직 아버지만 아셔.\\""},{"n":37,"t":"\\"노아의 때와 같이 사람의 아들의 임함도 그러할 거야.\\""},{"n":38,"t":"\\"홍수 전에 노아가 방주에 들어가던 날까지 사람들이 먹고 마시고 결혼하고 결혼시키며 지냈어.\\""},{"n":39,"t":"\\"홍수가 와서 다 휩쓸어 가기까지 깨닫지 못했어. 사람의 아들의 임함도 그러할 거야.\\""},{"n":40,"t":"\\"그때 두 사람이 밭에 있다가 한 사람은 데려가고 한 사람은 남겨질 거야.\\""},{"n":41,"t":"\\"두 여자가 맷돌로 곡식을 갈다가 한 사람은 데려가고 한 사람은 남겨질 거야.\\""},{"n":42,"t":"\\"그러므로 깨어 있어라. 너희 주님이 오시는 날을 모르기 때문이야.\\""},{"n":43,"t":"\\"이것을 너희가 알아라. 집주인이 도둑이 어느 시각에 올지 안다면 깨어 있어 자기 집을 뚫리게 두지 않았을 거야.\\""},{"n":44,"t":"\\"그러므로 너희도 준비해라. 너희가 생각하지 않은 시각에 사람의 아들이 올 거야.\\""},{"n":45,"t":"\\"누가 충성되고 슬기로운 종이 되어, 주인이 자기 집의 종들을 맡겨 제때에 식량을 나누어 주게 할까?\\""},{"n":46,"t":"\\"주인이 와서 보고 그렇게 하는 종은 복이 있다.\\""},{"n":47,"t":"\\"진정으로 말한다. 그 주인이 자기 모든 재산을 그에게 맡길 거야.\\""},{"n":48,"t":"\\"그러나 그 악한 종이 마음에 \'내 주인이 더디 온다\' 하면서,\\""},{"n":49,"t":"\\"동료들을 때리고 술꾼들과 함께 먹고 마시면,\\""},{"n":50,"t":"\\"그 종의 주인이 그가 생각하지 않은 날, 모르는 시각에 와서,\\""},{"n":51,"t":"\\"그를 엄히 처분하고 위선자들과 함께 두니, 거기서 울며 이를 갈게 될 거야.\\""}]}},{"chapter":25,"title":"열 처녀와 달란트 비유","verses":{"krv":[{"n":1,"t":"그 때에 천국은 마치 등을 들고 신랑을 맞으러 나간 열 처녀와 같다 하리니"},{"n":2,"t":"그 중에 다섯은 미련하고 다섯은 슬기 있는지라"},{"n":3,"t":"미련한 자들은 등을 가지되 기름을 가지지 아니하고"},{"n":4,"t":"슬기 있는 자들은 그릇에 기름을 담아 등과 함께 가져갔더니"},{"n":5,"t":"신랑이 더디 오므로 다 졸며 잘새"},{"n":6,"t":"밤중에 소리가 나되 보라 신랑이로다 맞으러 나오라 하매"},{"n":7,"t":"이에 그 처녀들이 다 일어나 등을 준비할새"},{"n":8,"t":"미련한 자들이 슬기 있는 자들에게 이르되 우리 등불이 꺼져가니 너희 기름을 좀 나눠 달라 하거늘"},{"n":9,"t":"슬기 있는 자들이 대답하여 가로되 우리와 너희의 쓰기에 다 부족할까 하노니 차라리 파는 자들에게 가서 너희 쓸 것을 사라 하니"},{"n":10,"t":"저희가 사러 간 동안에 신랑이 오므로 예비하였던 자들은 함께 혼인 잔치에 들어가고 문은 닫힌지라"},{"n":11,"t":"그 후에 남은 처녀들이 와서 가로되 주여 주여 우리에게 열어 주소서"},{"n":12,"t":"대답하여 가로되 진실로 너희에게 이르노니 내가 너희를 알지 못하노라 하였느니라"},{"n":13,"t":"그런즉 깨어 있으라 너희는 그 날과 그 시를 알지 못하느니라"},{"n":14,"t":"또 어떤 사람이 타국에 갈제 그 종들을 불러 자기 소유를 맡김과 같으니"},{"n":15,"t":"각각 그 재능대로 하나에게는 금 다섯 달란트를, 하나에게는 두 달란트를, 하나에게는 한 달란트를 주고 떠났더니"},{"n":16,"t":"다섯 달란트 받은자는 바로 가서 그것으로 장사하여 또 다섯 달란트를 남기고"},{"n":17,"t":"두 달란트를 받은 자도 그같이 하여 또 두 달란트를 남겼으되"},{"n":18,"t":"한 달란트 받은 자는 가서 땅을 파고 그 주인의 돈을 감추어 두었더니"},{"n":19,"t":"오랜 후에 그 종들의 주인이 돌아와 저희와 회계할새"},{"n":20,"t":"다섯 달란트 받았던 자는 다섯 달란트를 더 가지고 와서 가로되 주여 내게 다섯 달란트를 주셨는데 보소서 내가 또 다섯 달란트를 남겼나이다"},{"n":21,"t":"그 주인이 이르되 잘 하였도다 착하고 충성된 종아 네가 작은 일에 충성하였으매 내가 많은 것으로 네게 맡기리니 네 주인의 즐거움에 참예할지어다 하고"},{"n":22,"t":"두 달란트 받았던 자도 와서 가로되 주여 내게 두 달란트를 주셨는데 보소서 내가 또 두 달란트를 남겼나이다"},{"n":23,"t":"그 주인이 이르되 잘 하였도다 착하고 충성된 종아 네가 작은 일에 충성하였으매 내가 많은 것으로 네게 맡기리니 네 주인의 즐거움에 참예할지어다 하고"},{"n":24,"t":"한 달란트 받았던 자도 와서 가로되 주여 당신은 굳은 사람이라 심지 않은데서 거두고 헤치지 않은데서 모으는 줄을 내가 알았으므로"},{"n":25,"t":"두려워하여 나가서 당신의 달란트를 땅에 감추어 두었었나이다 보소서 당신의 것을 받으셨나이다"},{"n":26,"t":"그 주인이 대답하여 가로되 악하고 게으른 종아 나는 심지 않은 데서 거두고 헤치지 않은 데서 모으는 줄로 네가 알았느냐"},{"n":27,"t":"그러면 네가 마땅히 내 돈을 취리하는 자들에게나 두었다가 나로 돌아 와서 내 본전과 변리를 받게 할 것이니라 하고"},{"n":28,"t":"그에게서 그 한 달란트를 빼앗아 열 달란트 가진 자에게 주어라"},{"n":29,"t":"무릇 있는 자는 받아 풍족하게 되고 없는 자는 그 있는 것까지 빼앗기리라"},{"n":30,"t":"이 무익한 종을 바깥 어두운데로 내어 쫓으라 거기서 슬피 울며이를 갊이 있으리라 하니라"},{"n":31,"t":"인자가 자기 영광으로 모든 천사와 함께 올때에 자기 영광의 보좌에 앉으리니"},{"n":32,"t":"모든 민족을 그 앞에 모으고 각각 분별하기를 목자가 양과 염소를 분별하는것 같이 하여"},{"n":33,"t":"양은 그 오른편에, 염소는 왼편에 두리라"},{"n":34,"t":"그 때에 임금이 그 오른편에 있는 자들에게 이르시되 내 아버지께 복 받을 자들이여 나아와 창세로부터 너희를 위하여 예비된 나라를 상속하라"},{"n":35,"t":"내가 주릴 때에 너희가 먹을 것을 주었고 목마를 때에 마시게 하였고 나그네 되었을 때에 영접하였고"},{"n":36,"t":"벗었을 때에 옷을 입혔고 병들었을 때에 돌아보았고 옥에 갇혔을 때에 와서 보았느니라"},{"n":37,"t":"이에 의인들이 대답하여 가로되 주여 우리가 어느 때에 주의 주리신 것을 보고 공궤하였으며 목마르신 것을 보고 마시게 하였나이까"},{"n":38,"t":"어느 때에 나그네 되신 것을 보고 영접하였으며 벗으신 것을 보고 옷 입혔나이까"},{"n":39,"t":"어느 때에 병드신 것이나 옥에 갇히신 것을 보고 가서 뵈었나이까 하리니"},{"n":40,"t":"임금이 대답하여 가라사대 내가 진실로 너희에게 이르노니 너희가 여기 내 형제 중에 지극히 작은 자 하나에게 한 것이 곧 내게한 것이니라 하시고"},{"n":41,"t":"또 왼편에 있는 자들에게 이르시되 저주를 받은 자들아 나를 떠나 마귀와 그 사자들을 위하여 예비된 영영한 불에 들어가라"},{"n":42,"t":"내가 주릴 때에 너희가 먹을 것을 주지 아니하였고 목마를 때에 마시게 하지 아니하였고"},{"n":43,"t":"나그네 되었을 때에 영접하지 아니하였고 벗었을 때에 옷 입히지 아니하였고 병들었을 때와 옥에 갇혔을 때에 돌아보지 아니하였느니라 하시니"},{"n":44,"t":"저희도 대답하여 가로되 주여 우리가 어느 때에 주의 주리신 것이나 목마르신 것이나 나그네 되신 것이나 벗으신 것이나 병드신 것이나 옥에 갇히신 것을 보고 공양치 아니하더이까"},{"n":45,"t":"이에 임금이 대답하여 가라사대 내가 진실로 너희에게 이르노니 이 지극히 작은 자 하나에게 하지 아니한것이 곧 내게 하지 아니한 것이니라 하시리니"},{"n":46,"t":"저희는 영벌에, 의인들은 영생에 들어가리라 하시니라"}],"kids":[{"n":1,"t":"\\"그때 천국은 등을 들고 신랑을 맞으러 나간 열 처녀와 같아.\\""},{"n":2,"t":"\\"그중 다섯은 어리석고 다섯은 슬기로웠어.\\""},{"n":3,"t":"\\"어리석은 사람들은 등을 가지면서 기름을 함께 가지지 않았고,\\""},{"n":4,"t":"\\"슬기로운 사람들은 자기 등과 함께 그릇에 기름을 가지고 갔어.\\""},{"n":5,"t":"\\"신랑이 더디 오니 다 졸음이 와서 잤어.\\""},{"n":6,"t":"\\"한밤중에 \'보라, 신랑이다! 그를 맞으러 나가라\' 하고 외치는 소리가 났어.\\""},{"n":7,"t":"\\"그때 모든 처녀들이 일어나서 자기 등을 챙겼어.\\""},{"n":8,"t":"\\"어리석은 사람들이 슬기로운 사람들에게 \'우리 기름을 좀 나눠 줘. 우리 등이 꺼져 가\' 하고 말했어.\\""},{"n":9,"t":"\\"슬기로운 사람들이 \'우리에게도 너희에게도 모자랄 거야. 가게에 가서 자기 것을 사라\' 하고 답했어.\\""},{"n":10,"t":"\\"그들이 사러 간 사이에 신랑이 왔고 준비된 사람들은 함께 혼인 잔치에 들어가고 문이 닫혔어.\\""},{"n":11,"t":"\\"나중에 다른 처녀들이 와서 \'주여, 주여, 문을 열어 주세요\' 하고 청했어.\\""},{"n":12,"t":"\\"신랑이 \'진정으로 말한다. 나는 너희를 알지 못한다\' 하고 답했어.\\""},{"n":13,"t":"\\"그러므로 깨어 있어라. 그날과 그때를 너희가 모르기 때문이야.\\""},{"n":14,"t":"\\"또 천국은 어떤 사람이 멀리 떠나면서 자기 종들을 불러 재산을 맡기는 것과 같아.\\""},{"n":15,"t":"\\"각 종의 능력에 따라 한 사람에게는 다섯 달란트, 한 사람에게는 두 달란트, 한 사람에게는 한 달란트를 주고 떠났어.\\""},{"n":16,"t":"\\"다섯 달란트 받은 사람은 곧 가서 그것으로 장사하여 또 다섯을 벌었어.\\""},{"n":17,"t":"\\"두 달란트 받은 사람도 두 달란트를 벌었어.\\""},{"n":18,"t":"\\"그러나 한 달란트 받은 사람은 가서 땅을 파고 자기 주인의 돈을 감추었어.\\""},{"n":19,"t":"\\"오랜 시간이 지난 후에 그 종들의 주인이 와서 그들과 셈을 가렸어.\\""},{"n":20,"t":"\\"다섯 달란트 받은 사람이 와서 다섯 달란트를 더 가져와 \'주인님, 제게 다섯 달란트를 주셨는데 보세요, 다섯 달란트를 더 벌었어요\' 하고 말했어.\\""},{"n":21,"t":"\\"주인이 \'잘했다, 착하고 충성된 종아. 네가 작은 일에 충성했으니 내가 많은 일을 너에게 맡길게. 네 주인의 즐거움에 들어와라\' 하고 말했어.\\""},{"n":22,"t":"\\"두 달란트 받은 사람도 와서 \'주인님, 제게 두 달란트를 주셨는데 보세요, 두 달란트를 더 벌었어요\' 하고 말했어.\\""},{"n":23,"t":"\\"주인이 \'잘했다, 착하고 충성된 종아. 네가 작은 일에 충성했으니 내가 많은 일을 너에게 맡길게. 네 주인의 즐거움에 들어와라\' 하고 말했어.\\""},{"n":24,"t":"\\"한 달란트 받은 사람도 와서 \'주인님, 저는 주인이 굳은 사람이라 심지 않은 데서 거두고 헤치지 않은 데서 모으는 분인 줄 알았어요.\\""},{"n":25,"t":"\\"그래서 두려워서 가서 주인의 달란트를 땅에 감추었어요. 보세요, 주인의 것이에요\' 하고 말했어.\\""},{"n":26,"t":"\\"주인이 답했어. \'악하고 게으른 종아! 내가 심지 않은 데서 거두고 헤치지 않은 데서 모으는 줄 알았느냐?\\""},{"n":27,"t":"\\"그렇다면 내 돈을 돈놀이꾼에게 맡겼다가 내가 와서 이자와 함께 받았어야 하지 않니?\\""},{"n":28,"t":"\\"그 달란트를 그에게서 빼앗아 열 달란트 가진 사람에게 줘.\\""},{"n":29,"t":"\\"있는 사람마다 더 받아 풍성하게 되고, 없는 사람에게서는 그 있는 것까지도 빼앗길 거야.\\""},{"n":30,"t":"\\"무익한 그 종을 바깥 어둠에 내쳐라. 거기서 울며 이를 갈게 될 거야.\'\\""},{"n":31,"t":"\\"사람의 아들이 영광으로 모든 천사와 함께 올 때, 그때 그의 영광의 보좌에 앉을 거야.\\""},{"n":32,"t":"\\"모든 민족이 그 앞에 모이고, 그가 그들을 목자가 양과 염소를 가르듯이 갈라,\\""},{"n":33,"t":"\\"양은 자기 오른쪽에 두고 염소는 왼쪽에 둘 거야.\\""},{"n":34,"t":"\\"그때 임금이 오른쪽 사람들에게 말할 거야. \'내 아버지께 복 받은 사람들아, 세상 창조 때부터 너희를 위해 예비된 나라를 물려받아라.\\""},{"n":35,"t":"\\"내가 굶주렸을 때 너희가 먹을 것을 주었고, 목마를 때 마실 것을 주었고, 나그네 됐을 때 영접했고,\\""},{"n":36,"t":"\\"헐벗었을 때 입혔고, 병들었을 때 돌보았고, 감옥에 있을 때 찾아왔다.\'\\""},{"n":37,"t":"\\"의인들이 답해. \'주여, 우리가 언제 주께서 굶주린 것을 보고 음식을 드렸고, 목마른 것을 보고 마시게 했나요?\\""},{"n":38,"t":"\\"언제 나그네 되신 것을 보고 영접했고 헐벗으신 것을 보고 입혔나요?\\""},{"n":39,"t":"\\"언제 병드시거나 감옥에 계신 것을 보고 갔나요?\'\\""},{"n":40,"t":"\\"임금이 답해. \'진정으로 말한다. 너희가 여기 내 형제 중에 가장 작은 사람 하나에게 한 것이 곧 내게 한 것이다.\'\\""},{"n":41,"t":"\\"그때 또 왼쪽 사람들에게 말해. \'저주받은 사람들아, 내게서 떠나 마귀와 그 사자들을 위해 예비된 영원한 불에 들어가라.\\""},{"n":42,"t":"\\"내가 굶주릴 때 너희가 먹을 것을 주지 않았고, 목마를 때 마실 것을 주지 않았고,\\""},{"n":43,"t":"\\"나그네 됐을 때 영접하지 않았고, 헐벗었을 때 입히지 않았고, 병들고 감옥에 있을 때 돌보지 않았다.\'\\""},{"n":44,"t":"\\"그들이 답해. \'주여, 우리가 언제 주께서 굶주린 것이나 목마른 것이나 나그네이거나 헐벗거나 병들거나 감옥에 계신 것을 보고 섬기지 않았나요?\'\\""},{"n":45,"t":"\\"그가 답해. \'진정으로 말한다. 너희가 여기 가장 작은 사람 하나에게 하지 않은 것이 곧 내게 하지 않은 것이다.\'\\""},{"n":46,"t":"\\"그들은 영원한 형벌로, 의인은 영원한 생명으로 들어갈 거야.\\""}]}},{"chapter":26,"title":"마지막 만찬과 잡히심","verses":{"krv":[{"n":1,"t":"예수께서 이 말씀을 다 마치시고 제자들에게 이르시되"},{"n":2,"t":"너희의 아는 바와 같이 이틀을 지나면 유월절이라 인자가 십자가에 못 박히기 위하여 팔리우리라 하시더라"},{"n":3,"t":"그 때에 대제사장들과 백성의 장로들이 가야바라 하는 대제사장의 아문에 모여"},{"n":4,"t":"예수를 궤계로 잡아 죽이려고 의논하되"},{"n":5,"t":"말하기를 민요가 날까 하노니 명절에는 말자 하더라"},{"n":6,"t":"예수께서 베다니 문둥이 시몬의 집에 계실 때에"},{"n":7,"t":"한 여자가 매우 귀한 향유 한 옥합을 가지고 나아와서 식사하시는 예수의 머리에 부으니"},{"n":8,"t":"제자들이 보고 분하여 가로되 무슨 의사로 이것을 허비하느뇨"},{"n":9,"t":"이것을 많은 값에 팔아 가난한 자들에게 줄 수 있었겠도다 하거늘"},{"n":10,"t":"예수께서 아시고 저희에게 이르시되 너희가 어찌하여 이 여자를 괴롭게 하느냐 저가 내게 좋은 일을 하였느니라"},{"n":11,"t":"가난한 자들은 항상 너희와 함께 있거니와 나는 항상 함께 있지 아니하리라"},{"n":12,"t":"이 여자가 내 몸에 이 향유를 부은 것은 내 장사를 위하여 함이니라"},{"n":13,"t":"내가 진실로 너희에게 이르노니 온 천하에 어디서든지 이 복음이 전파되는 곳에는 이 여자의 행한 일도 말하여 저를 기념하리라 하시니라"},{"n":14,"t":"그 때에 열 둘 중에 하나인 가룟 유다라 하는 자가 대제사장들에게 가서 말하되"},{"n":15,"t":"내가 예수를 너희에게 넘겨주리니 얼마나 주려느냐 하니 그들이 은 삼십을 달아 주거늘"},{"n":16,"t":"저가 그 때부터 예수를 넘겨줄 기회를 찾더라"},{"n":17,"t":"무교절의 첫날에 제자들이 예수께 나아와서 가로되 유월절 잡수실 것을 우리가 어디서 예비하기를 원하시나이까"},{"n":18,"t":"가라사대 성안 아무에게 가서 이르되 선생님 말씀이 내 때가 가까왔으니 내 제자들과 함께 유월절을 네 집에서 지키겠다 하시더라 하라 하신대"},{"n":19,"t":"제자들이 예수의 시키신대로 하여 유월절을 예비하였더라"},{"n":20,"t":"저물 때에 예수께서 열 두 제자와 함께 앉으셨더니"},{"n":21,"t":"저희가 먹을 때에 이르시되 내가 진실로 너희에게 이르노니 너희중에 한 사람이 나를 팔리라 하시니"},{"n":22,"t":"저희가 심히 근심하여 각각 여짜오되 주여 내니이까"},{"n":23,"t":"대답하여 가라사대 나와 함께 그릇에 손을 넣는 그가 나를 팔리라"},{"n":24,"t":"인자는 자기에게 대하여 기록된대로 가거니와 인자를 파는 그 사람에게는 화가 있으리로다 그 사람은 차라리 나지 아니 하였더면 제게 좋을뻔 하였느니라"},{"n":25,"t":"예수를 파는 유다가 대답하여 가로되 랍비여 내니이까 대답하시되 네가 말하였도다 하시니라"},{"n":26,"t":"저희가 먹을 때에 예수께서 떡을 가지사 축복하시고 떼어 제자들을 주시며 가라사대 받아 먹으라 이것이 내 몸이니라 하시고"},{"n":27,"t":"또 잔을 가지사 사례하시고 저희에게 주시며 가라사대 너희가 다 이것을 마시라"},{"n":28,"t":"이것은 죄 사함을 얻게 하려고 많은 사람을 위하여 흘리는바 나의 피 곧 언약의 피니라"},{"n":29,"t":"그러나 너희에게 이르노니 내가 포도나무에서 난 것을 이제부터 내 아버지의 나라에서 새것으로 너희와 함께 마시는 날까지 마시지 아니하리라 하시니라"},{"n":30,"t":"이에 저희가 찬미하고 감람산으로 나아가니라"},{"n":31,"t":"때에 예수께서 제자들에게 이르시되 오늘 밤에 너희가 다 나를 버리리라 기록된바 내가 목자를 치리니 양의 떼가 흩어지리라 하였느니라"},{"n":32,"t":"그러나 내가 살아난 후에 너희보다 먼저 갈릴리로 가리라"},{"n":33,"t":"베드로가 대답하여 가로되 다 주를 버릴지라도 나는 언제든지 버리지 않겠나이다"},{"n":34,"t":"예수께서 가라사대 내가 진실로 네게 이르노니 오늘 밤 닭 울기 전에 네가 세번 나를 부인하리라"},{"n":35,"t":"베드로가 가로되 내가 주와 함께 죽을지언정 주를 부인하지 않겠나이다 하고 모든 제자도 이와 같이 말하니라"},{"n":36,"t":"이에 예수께서 제자들과 함께 겟세마네라 하는 곳에 이르러 제자들에게 이르시되 내가 저기 가서 기도할 동안에 너희는 여기 앉아 있으라 하시고"},{"n":37,"t":"베드로와 세베대의 두 아들을 데리고 가실쌔 고민하고 슬퍼하사"},{"n":38,"t":"이에 말씀하시되 내 마음이 심히 고민하여 죽게 되었으니 너희는 여기 머물러 나와 함께 깨어 있으라 하시고"},{"n":39,"t":"조금 나아가사 얼굴을 땅에 대시고 엎드려 기도하여 가라사대 내 아버지여 만일 할만하시거든 이 잔을 내게서 지나가게 하옵소서 그러나 나의 원대로 마옵시고 아버지의 원대로 하옵소서 하시고"},{"n":40,"t":"제자들에게 오사 그 자는 것을 보시고 베드로에게 말씀하시되 너희가 나와 함께 한 시 동안도 이렇게 깨어 있을 수 없더냐"},{"n":41,"t":"시험에 들지 않게 깨어 있어 기도하라 마음에는 원이로되 육신이 약하도다 하시고"},{"n":42,"t":"다시 두번째 나아가 기도하여 가라사대 내 아버지여 만일 내가 마시지 않고는 이 잔이 내게서 지나갈 수 없거든 아버지의 원대로 되기를 원하나이다 하시고"},{"n":43,"t":"다시 오사 보신즉 저희가 자니 이는 저희 눈이 피곤함일러라"},{"n":44,"t":"또 저희를 두시고 나아가 세번째 동일한 말씀으로 기도하신 후"},{"n":45,"t":"이에 제자들에게 오사 이르시되 이제는 자고 쉬라 보라 때가 가까왔으니 인자가 죄인의 손에 팔리우느니라"},{"n":46,"t":"일어나라 함께 가자 보라 나를 파는 자가 가까이 왔느니라"},{"n":47,"t":"말씀하실 때에 열 둘 중에 하나인 유다가 왔는데 대제사장들과 백성의 장로들에게서 파송된 큰 무리가 검과 몽치를 가지고 그와 함께 하였더라"},{"n":48,"t":"예수를 파는 자가 그들에게 군호를 짜 가로되 내가 입맞추는 자가 그이니 그를 잡으라 하였는지라"},{"n":49,"t":"곧 예수께 나아와 랍비여 안녕하시옵니까 하고 입을 맞추니"},{"n":50,"t":"예수께서 가라사대 친구여 네가 무엇을 하려고 왔는지 행하라 하신대 이에 저희가 나아와 예수께 손을 대어 잡는지라"},{"n":51,"t":"예수와 함께 있던 자 중에 하나가 손을 펴 검을 빼어 대제사장의 종을 쳐 그 귀를 떨어뜨리니"},{"n":52,"t":"이에 예수께서 이르시되 네 검을 도로 집에 꽂으라 검을 가지는 자는 다 검으로 망하느니라"},{"n":53,"t":"너는 내가 내 아버지께 구하여 지금 열 두 영 더되는 천사를 보내시게 할 수 없는 줄로 아느냐"},{"n":54,"t":"내가 만일 그렇게 하면 이런 일이 있으리라 한 성경이 어떻게 이루어지리요 하시더라"},{"n":55,"t":"그 때에 예수께서 무리에게 말씀하시되 너희가 강도를 잡는 것 같이 검과 몽치를 가지고 나를 잡으러 나왔느냐 내가 날마다 성전에 앉아 가르쳤으되 너희가 나를 잡지 아니하였도다"},{"n":56,"t":"그러나 이렇게 된 것은 다 선지자들의 글을 이루려 함이니라 하시더라 이에 제자들이 다 예수를 버리고 도망하니라"},{"n":57,"t":"예수를 잡은 자들이 끌고 대제사장 가야바에게로 가니 거기 서기관과 장로들이 모여 있더라"},{"n":58,"t":"베드로가 멀찍이 예수를 좇아 대제사장의 집 뜰에까지 가서 그 결국을 보려고 안에 들어가 하속들과 함께 앉았더라"},{"n":59,"t":"대제사장들과 온 공회가 예수를 죽이려고 그를 칠 거짓증거를 찾으매"},{"n":60,"t":"거짓 증인이 많이 왔으나 얻지 못하더니 후에 두 사람이 와서"},{"n":61,"t":"가로되 이 사람의 말이 내가 하나님의 성전을 헐고 사흘에 지을 수 있다 하더라 하니"},{"n":62,"t":"대제사장이 일어서서 예수께 묻되 아무 대답도 없느냐 이 사람들의 너를 치는 증거가 어떠하뇨 하되"},{"n":63,"t":"예수께서 잠잠하시거늘 대제사장이 가로되 내가 너로 살아계신 하나님께 맹세하게 하노니 네가 하나님의 아들 그리스도인지 우리에게 말하라"},{"n":64,"t":"예수께서 가라사대 네가 말하였느니라 그러나 내가 너희에게 이르노니 이 후에 인자가 권능의 우편에 앉은 것과 하늘 구름을 타고 오는 것을 너희가 보리라 하시니"},{"n":65,"t":"이에 대제사장이 자기 옷을 찢으며 가로되 저가 참람한 말을 하였으니 어찌 더 증인을 요구하리요 보라 너희가 지금 이 참람한 말을 들었도다"},{"n":66,"t":"생각이 어떠하뇨 대답하여 가로되 저는 사형에 해당하니라 하고"},{"n":67,"t":"이에 예수의 얼굴에 침 뱉으며 주먹으로 치고 혹은 손바닥으로 때리며"},{"n":68,"t":"가로되 그리스도야 우리에게 선지자 노릇을 하라 너를 친 자가 누구냐 하더라"},{"n":69,"t":"베드로가 바깥 뜰에 앉았더니 한 비자가 나아와 가로되 너도 갈릴리 사람 예수와 함께 있었도다 하거늘"},{"n":70,"t":"베드로가 모든 사람 앞에서 부인하여 가로되 나는 네 말하는 것이 무엇인지 알지 못하겠노라 하며"},{"n":71,"t":"앞문까지 나아가니 다른 비자가 저를 보고 거기 있는 사람들에게 말하되 이 사람은 나사렛 예수와 함께 있었도다 하매"},{"n":72,"t":"베드로가 맹세하고 또 부인하여 가로되 내가 그 사람을 알지 못 하노라 하더라"},{"n":73,"t":"조금 후에 곁에 섰던 사람들이 나아와 베드로에게 이르되 너도 진실로 그 당이라 네 말소리가 너를 표명한다 하거늘"},{"n":74,"t":"저가 저주하며 맹세하여 가로되 내가 그 사람을 알지 못하노라 하니 닭이 곧 울더라"},{"n":75,"t":"이에 베드로가 예수의 말씀에 닭 울기 전에 네가 세번 나를 부인하리라 하심이 생각나서 밖에 나가서 심히 통곡하니라"}],"kids":[{"n":1,"t":"예수님이 이 모든 말씀을 마치시고 제자들에게 말씀하셨어요."},{"n":2,"t":"\\"이틀 후면 유월절인 줄 너희가 알지. 사람의 아들이 십자가에 못 박히려고 넘겨질 거야.\\""},{"n":3,"t":"그때 대제사장들과 백성의 장로들이 가야바라는 대제사장의 뜰에 모여,"},{"n":4,"t":"예수님을 속임수로 잡아 죽이려고 의논했어요."},{"n":5,"t":"그러나 \\"명절에는 안 돼. 백성 사이에 소동이 일어날 거야\\" 하고 말했어요."},{"n":6,"t":"예수님이 베다니의 나병 환자 시몬의 집에 계실 때,"},{"n":7,"t":"한 여자가 매우 값진 향유 한 옥합을 가지고 와서 식사하시는 예수님 머리에 부었어요."},{"n":8,"t":"제자들이 보고 화를 내며 \\"왜 이렇게 낭비해요?\\""},{"n":9,"t":"\\"이것을 많은 값에 팔아 가난한 사람에게 줄 수 있었는데\\" 하고 말했어요."},{"n":10,"t":"예수님이 그것을 아시고 \\"왜 이 여자를 괴롭히니? 그녀가 내게 좋은 일을 했다.\\""},{"n":11,"t":"\\"가난한 사람은 늘 너희와 함께 있지만 나는 늘 함께 있지 않아.\\""},{"n":12,"t":"\\"이 여자가 내 몸에 향유를 부은 것은 내 장례를 준비한 거야.\\""},{"n":13,"t":"\\"진정으로 말한다. 온 세상에 이 복음이 전해지는 곳마다 이 여자가 한 일도 기억되어 말해질 거야.\\""},{"n":14,"t":"그때 열둘 중의 하나, 가룟 유다라 하는 사람이 대제사장들에게 가서,"},{"n":15,"t":"\\"제가 그분을 너희에게 넘기면 무엇을 주시겠어요?\\" 하고 말했어요. 그들이 은 삼십 닢을 그에게 주었어요."},{"n":16,"t":"그때부터 유다가 예수님을 넘길 기회를 찾았어요."},{"n":17,"t":"무교절 첫째 날에 제자들이 예수님께 와서 \\"유월절 음식을 어디서 준비해 드릴까요?\\" 하고 물었어요."},{"n":18,"t":"예수님이 \\"도시 안 어떤 사람에게 가서 \'선생님이 「내 때가 가까웠다. 내가 너희 집에서 제자들과 함께 유월절을 지키겠다」고 하셨어요\' 하고 말해라\\" 하셨어요."},{"n":19,"t":"제자들이 예수님이 말씀하신 대로 하여 유월절을 준비했어요."},{"n":20,"t":"저녁이 되자 예수님이 열두 제자와 함께 식탁에 앉으셨어요."},{"n":21,"t":"그들이 먹을 때 예수님이 \\"진정으로 말한다. 너희 중 하나가 나를 넘길 거다\\" 하고 말씀하셨어요."},{"n":22,"t":"그들이 몹시 슬퍼하며 각각 \\"주님, 저는 아니지요?\\" 하고 묻기 시작했어요."},{"n":23,"t":"예수님이 \\"나와 함께 손을 그릇에 넣은 사람이 나를 넘길 거야.\\""},{"n":24,"t":"\\"사람의 아들은 자기에 대해 기록된 대로 가지만 사람의 아들을 넘기는 그 사람에게는 화가 있다. 그 사람은 태어나지 않은 것이 더 좋을 거야.\\""},{"n":25,"t":"넘기려는 유다가 \\"랍비여, 저는 아니지요?\\" 하고 물었어요. 예수님이 \\"네 말과 같다\\" 하셨어요."},{"n":26,"t":"그들이 먹을 때 예수님이 빵을 가져다 축복하시고 떼어 제자들에게 주며 말씀하셨어요. \\"받아 먹어라. 이것은 내 몸이다.\\""},{"n":27,"t":"그리고 잔을 가져다 감사하시고 그들에게 주며 \\"다 이것을 마셔라.\\""},{"n":28,"t":"\\"이것은 죄 사함을 위해 많은 사람을 위해 흘리는 내 언약의 피야.\\""},{"n":29,"t":"\\"내가 너희에게 말한다. 내 아버지의 나라에서 너희와 새것으로 마시는 그날까지 내가 이 포도나무의 열매로 만든 것을 마시지 않을 거다\\" 하셨어요."},{"n":30,"t":"그들이 찬송을 부르고 감람산으로 나갔어요."},{"n":31,"t":"그때 예수님이 \\"오늘 밤 너희가 다 나 때문에 걸려 넘어질 거야. 기록된 바, \'내가 목자를 칠 것이며 양 떼가 흩어질 거다\'야.\\""},{"n":32,"t":"\\"그러나 내가 살아난 후에 너희보다 먼저 갈릴리로 갈 거야\\" 하셨어요."},{"n":33,"t":"베드로가 \\"다 주님 때문에 걸려 넘어져도 저는 결코 넘어지지 않을 거예요\\" 하고 답했어요."},{"n":34,"t":"예수님이 \\"진정으로 말한다. 오늘 밤 닭이 울기 전에 네가 나를 세 번 부인할 거야\\" 하셨어요."},{"n":35,"t":"베드로가 \\"제가 주님과 함께 죽을지언정 결코 부인하지 않겠어요\\" 하고 말했고 다른 제자들도 다 그렇게 말했어요."},{"n":36,"t":"예수님이 제자들과 함께 겟세마네라는 곳에 가서 \\"여기 앉아 있어. 내가 저기 가서 기도할 거야\\" 하셨어요."},{"n":37,"t":"베드로와 세베대의 두 아들을 데리고 가시며 슬퍼하고 답답해하시며,"},{"n":38,"t":"\\"내 영혼이 죽을 듯이 슬프다. 여기 머물러 나와 함께 깨어 있어라\\" 하셨어요."},{"n":39,"t":"조금 더 나아가 얼굴을 땅에 대고 기도하셨어요. \\"내 아버지, 가능하다면 이 잔을 내게서 지나가게 해 주세요. 그러나 내 원대로 하지 마시고 아버지 원대로 하세요.\\""},{"n":40,"t":"제자들에게 와서 자는 것을 보시고 베드로에게 \\"이렇게 너희가 나와 함께 한 시간도 깨어 있을 수 없니?\\""},{"n":41,"t":"\\"깨어 기도해. 시험에 들지 않게 하기 위해. 마음은 원하지만 육체가 약해\\" 하셨어요."},{"n":42,"t":"또 다시 가서 \\"아버지, 만약 이 잔이 지나갈 수 없으면 내가 마시지 않고는 안 된다면 아버지의 뜻대로 이루소서\\" 하고 기도하셨어요."},{"n":43,"t":"오셔서 또 그들이 자고 있는 것을 보셨어요. 눈이 무거웠거든요."},{"n":44,"t":"그들을 두고 다시 가서 세 번째로 같은 말씀으로 기도하셨어요."},{"n":45,"t":"제자들에게 오셔서 \\"이제 자고 쉬어라. 보라, 때가 가까웠다. 사람의 아들이 죄인의 손에 넘겨진다.\\""},{"n":46,"t":"\\"일어나라, 가자. 보라, 나를 넘기는 사람이 가까이 왔다\\" 하셨어요."},{"n":47,"t":"말씀하고 계실 때 열둘 중 하나인 유다가 칼과 몽둥이를 가진 큰 무리와 함께 왔어요. 대제사장들과 백성의 장로들이 보낸 사람들이에요."},{"n":48,"t":"예수님을 넘기는 사람이 그들에게 표를 주며 \\"내가 입맞추는 사람이 그분이니 잡으라\\" 했어요."},{"n":49,"t":"곧 예수님께 와서 \\"랍비여, 안녕하세요?\\" 하며 입을 맞췄어요."},{"n":50,"t":"예수님이 \\"친구야, 네가 온 일을 하라\\" 하셨어요. 그러자 사람들이 와서 예수님을 잡았어요."},{"n":51,"t":"예수님과 함께 있던 사람 중 하나가 손을 뻗어 칼을 빼서 대제사장의 종을 쳐서 그의 귀를 잘랐어요."},{"n":52,"t":"예수님이 \\"네 칼을 다시 그 자리에 넣어라. 칼을 가지는 사람은 다 칼로 망할 거야.\\""},{"n":53,"t":"\\"내가 내 아버지께 청하면 그분이 지금 천사 열두 군단도 더 보내실 수 있는 줄 너희가 모르니?\\""},{"n":54,"t":"\\"그러면 이렇게 되어야 한다는 성경이 어떻게 이루어지겠니?\\" 하셨어요."},{"n":55,"t":"그때 예수님이 무리에게 \\"너희가 강도를 잡듯이 칼과 몽둥이를 들고 나를 잡으러 나왔니? 내가 날마다 성전에 앉아 가르쳤을 때 너희가 나를 잡지 않았어.\\""},{"n":56,"t":"\\"이 모든 일이 일어난 것은 예언자들의 성경이 이루어지려 함이다\\" 하셨어요. 그때 모든 제자들이 예수님을 버리고 도망쳤어요."},{"n":57,"t":"예수님을 잡은 사람들이 대제사장 가야바에게로 끌고 갔는데, 거기에 율법 학자와 장로들이 모여 있었어요."},{"n":58,"t":"베드로는 멀찍이서 대제사장의 뜰까지 따라가 안에 들어가 결말을 보려고 종들과 함께 앉아 있었어요."},{"n":59,"t":"대제사장들과 온 공회가 예수님을 죽이려고 거짓 증거를 찾았지만 못 찾았어요."},{"n":60,"t":"많은 거짓 증인이 와도 못 찾았는데, 마지막에 두 사람이 와서,"},{"n":61,"t":"\\"이 사람이 「내가 하나님의 성전을 무너뜨리고 사흘 만에 짓겠다」고 했다\\" 하고 말했어요."},{"n":62,"t":"대제사장이 일어나 \\"아무 대답도 하지 않니? 이 사람들이 너에게 무엇을 증언하는지 들어 봐라\\" 하고 말했어요."},{"n":63,"t":"예수님은 잠잠하셨어요. 대제사장이 \\"살아 계신 하나님께 맹세하고 말해 봐. 네가 그리스도 하나님의 아들이니?\\" 하고 물었어요."},{"n":64,"t":"예수님이 \\"네 말과 같다. 또 너희에게 말한다. 이후로 사람의 아들이 권능의 오른편에 앉아 있는 것과 하늘 구름을 타고 오는 것을 너희가 볼 거야\\" 하셨어요."},{"n":65,"t":"대제사장이 자기 옷을 찢으며 \\"그가 하나님을 모독했어. 무슨 증인이 더 필요해? 너희가 지금 그 모독을 들었어.\\""},{"n":66,"t":"\\"너희 생각은 어떠니?\\" 하니, 그들이 \\"사형에 해당해요\\" 하고 답했어요."},{"n":67,"t":"그때 예수님의 얼굴에 침을 뱉고 주먹으로 치고, 어떤 사람은 손바닥으로 때리며,"},{"n":68,"t":"\\"그리스도야, 너를 친 사람이 누구인지 예언해 봐라\\" 하고 말했어요."},{"n":69,"t":"베드로는 밖에 뜰에 앉아 있었어요. 한 종 여자가 그에게 와서 \\"너도 갈릴리 사람 예수와 함께 있었어\\" 하고 말했어요."},{"n":70,"t":"베드로가 모든 사람 앞에서 \\"무슨 말인지 모르겠다\\" 하고 부인했어요."},{"n":71,"t":"그가 문 앞으로 나가니 다른 종 여자가 보고 거기 있는 사람들에게 \\"이 사람도 나사렛 예수와 함께 있었어\\" 하고 말했어요."},{"n":72,"t":"베드로가 또 맹세하며 \\"나는 그 사람을 알지 못한다\\" 하고 부인했어요."},{"n":73,"t":"조금 후에 서 있던 사람들이 와서 \\"너도 분명히 그들 중 한 명이야. 네 말투가 너를 드러내거든\\" 하고 말했어요."},{"n":74,"t":"베드로가 저주하며 맹세하기 시작했어요. \\"나는 그 사람을 알지 못한다.\\" 곧 닭이 울었어요."},{"n":75,"t":"베드로는 예수님이 \\"닭이 울기 전에 네가 나를 세 번 부인할 거다\\" 하신 말씀이 생각나서 밖에 나가 몹시 울었어요."}]}},{"chapter":27,"title":"십자가에 못 박히심","verses":{"krv":[{"n":1,"t":"새벽에 모든 대제사장과 백성의 장로들이 예수를 죽이려고 함께 의논하고"},{"n":2,"t":"결박하여 끌고 가서 총독 빌라도에게 넘겨주니라"},{"n":3,"t":"때에 예수를 판 유다가 그의 정죄됨을 보고 스스로 뉘우쳐 그 은 삼십을 대제사장들과 장로들에게 도로 갖다 주며"},{"n":4,"t":"가로되 내가 무죄한 피를 팔고 죄를 범하였도다 하니 저희가 가로되 그것이 우리에게 무슨 상관이 있느냐 네가 당하라 하거늘"},{"n":5,"t":"유다가 은을 성소에 던져 넣고 물러가서 스스로 목매어 죽은지라"},{"n":6,"t":"대제사장들이 그 은을 거두며 가로되 이것은 피 값이라 성전고에 넣어 둠이 옳지 않다 하고"},{"n":7,"t":"의논한 후 이것으로 토기장이의 밭을 사서 나그네의 묘지를 삼았으니"},{"n":8,"t":"그러므로 오늘날까지 그 밭을 피밭이라 일컫느니라"},{"n":9,"t":"이에 선지자 예레미야로 하신 말씀이 이루었나니 일렀으되 저희가 그 정가된 자 곧 이스라엘 자손 중에서 정가한 자의 가격 곧 은 삼십을 가지고"},{"n":10,"t":"토기장이의 밭 값으로 주었으니 이는 주께서 내게 명하신 바와 같으니라 하였더라"},{"n":11,"t":"예수께서 총독앞에 섰으매 총독이 물어 가로되 네가 유대인의 왕이냐 예수께서 대답하시되 네 말이 옳도다 하시고"},{"n":12,"t":"대제사장들과 장로들에게 고소를 당하되 아무 대답도 아니하시는지라"},{"n":13,"t":"이에 빌라도가 이르되 저희가 너를 쳐서 얼마나 많은 것으로 증거하는지 듣지 못하느냐 하되"},{"n":14,"t":"한마디도 대답지 아니하시니 총독이 심히 기이히 여기더라"},{"n":15,"t":"명절을 당하면 총독이 무리의 소원대로 죄수 하나를 놓아 주는 전례가 있더니"},{"n":16,"t":"그 때에 바라바라 하는 유명한 죄수가 있는데"},{"n":17,"t":"저희가 모였을 때에 빌라도가 물어 가로되 너희는 내가 누구를 너희에게 놓아 주기를 원하느냐 바라바냐 그리스도라 하는 예수냐 하니"},{"n":18,"t":"이는 저가 그들의 시기로 예수를 넘겨준줄 앎이러라"},{"n":19,"t":"총독이 재판 자리에 앉았을 때에 그 아내가 사람을 보내어 가로되 저 옳은 사람에게 아무 상관도 하지 마옵소서 오늘 꿈에 내가 그 사람을 인하여 애를 많이 썼나이다 하더라"},{"n":20,"t":"대제사장들과 장로들이 무리를 권하여 바라바를 달라 하게 하고 예수를 멸하자 하게 하였더니"},{"n":21,"t":"총독이 대답하여 가로되 둘 중에 누구를 너희에게 놓아 주기를 원하느냐 가로되 바라바로소이다"},{"n":22,"t":"빌라도가 가로되 그러면 그리스도라 하는 예수를 내가 어떻게 하랴 저희가 다 가로되 십자가에 못 박혀야 하겠나이다"},{"n":23,"t":"빌라도가 가로되 어찜이뇨 무슨 악한 일을 하였느냐 저희가 더욱 소리질러 가로되 십자가에 못 박혀야 하겠나이다 하는지라"},{"n":24,"t":"빌라도가 아무 효험도 없이 도리어 민란이 나려는 것을 보고 물을 가져다가 무리 앞에서 손을 씻으며 가로되 이 사람의 피에 대하여 나는 무죄하니 너희가 당하라"},{"n":25,"t":"백성이 다 대답하여 가로되 그 피를 우리와 우리 자손에게 돌릴지어다 하거늘"},{"n":26,"t":"이에 바라바는 저희에게 놓아주고 예수는 채찍질하고 십자가에 못박히게 넘겨주니라"},{"n":27,"t":"이에 총독의 군병들이 예수를 데리고 관정 안으로 들어가서 온 군대를 그에게로 모으고"},{"n":28,"t":"그의 옷을 벗기고 홍포를 입히며"},{"n":29,"t":"가시 면류관을 엮어 그 머리에 씌우고 갈대를 그 오른손에 들리 고 그 앞에서 무릎을 꿇고 희롱하여 가로되 유대인의 왕이여 평안할지어다 하며"},{"n":30,"t":"그에게 침 뱉고 갈대를 빼앗아 그의 머리를 치더라"},{"n":31,"t":"희롱을 다한 후 홍포를 벗기고 도로 그의 옷을 입혀 십자가에 못 박으려고 끌고 나가니라"},{"n":32,"t":"나가다가 시몬이란 구레네 사람을 만나매 그를 억지로 같이 가게 하여 예수의 십자가를 지웠더라"},{"n":33,"t":"골고다 즉 해골의 곳이라는 곳에 이르러"},{"n":34,"t":"쓸개탄 포도주를 예수께 주어 마시게 하려 하였더니 예수께서 맛보시고 마시고자 아니하시더라"},{"n":35,"t":"저희가 예수를 십자가에 못 박은 후에 그 옷을 제비 뽑아 나누고"},{"n":36,"t":"거기 앉아 지키더라"},{"n":37,"t":"그 머리 위에 이는 유대인의 왕 예수라 쓴 죄패를 붙였더라"},{"n":38,"t":"이 때에 예수와 함께 강도 둘이 십자가에 못 박히니 하나는 우편에, 하나는 좌편에 있더라"},{"n":39,"t":"지나가는 자들은 자기 머리를 흔들며 예수를 모욕하여"},{"n":40,"t":"가로되 성전을 헐고 사흘에 짓는 자여 네가 만일 하나님의 아들이어든 자기를 구원하고 십자가에서 내려오라 하며"},{"n":41,"t":"그와 같이 대제사장들과 서기관들과 장로들도 함께 희롱하여 가로되"},{"n":42,"t":"저가 남은 구원하였으되 자기는 구원할 수 없도다 저가 이스라엘의 왕이로다 지금 십자가에서 내려올지어다 그러면 우리가 믿겠노라"},{"n":43,"t":"저가 하나님을 신뢰하니 하나님이 저를 기뻐하시면 이제 구원하실지라 제 말이 나는 하나님의 아들이라 하였도다 하며"},{"n":44,"t":"함께 십자가에 못 박힌 강도들도 이와 같이 욕하더라"},{"n":45,"t":"제 육시로부터 온 땅에 어두움이 임하여 제 구시까지 계속하더니"},{"n":46,"t":"제 구시 즈음에 예수께서 크게 소리질러 가라사대 엘리 엘리 라마 사박다니 하시니 이는 곧 나의 하나님, 나의 하나님, 어찌하여 나를 버리셨나이까 하는 뜻이라"},{"n":47,"t":"거기 섰던 자 중 어떤이들이 듣고 가로되 이 사람이 엘리야를 부른다 하고"},{"n":48,"t":"그 중에 한 사람이 곧 달려가서 해융을 가지고 신 포도주를 머금게 하여 갈대에 꿰어 마시우거늘"},{"n":49,"t":"그 남은 사람들이 가로되 가만 두어라 엘리야가 와서 저를 구원하나 보자 하더라"},{"n":50,"t":"예수께서 다시 크게 소리 지르시고 영혼이 떠나시다"},{"n":51,"t":"이에 성소 휘장이 위로부터 아래까지 찢어져 둘이 되고 땅이 진동하며 바위가 터지고"},{"n":52,"t":"무덤들이 열리며 자던 성도의 몸이 많이 일어나되"},{"n":53,"t":"예수의 부활 후에 저희가 무덤에서 나와서 거룩한 성에 들어가 많은 사람에게 보이니라"},{"n":54,"t":"백부장과 및 함께 예수를 지키던 자들이 지진과 그 되는 일들을 보고 심히 두려워하여 가로되 이는 진실로 하나님의 아들이었도다 하더라"},{"n":55,"t":"예수를 섬기며 갈릴리에서부터 좇아 온 많은 여자가 거기 있어 멀리서 바라보고 있으니"},{"n":56,"t":"그 중에 막달라 마리아와 또 야고보와 요셉의 어머니 마리아와 또 세베대의 아들들의 어머니도 있더라"},{"n":57,"t":"저물었을 때에 아리마대 부자 요셉이라 하는 사람이 왔으니 그도 예수의 제자라"},{"n":58,"t":"빌라도에게 가서 예수의 시체를 달라 하니 이에 빌라도가 내어주라 분부하거늘"},{"n":59,"t":"요셉이 시체를 가져다가 정한 세마포로 싸서"},{"n":60,"t":"바위 속에 판 자기 새무덤에 넣어두고 큰 돌을 굴려 무덤 문에 놓고 가니"},{"n":61,"t":"거기 막달라 마리아와 다른 마리아가 무덤을 향하여 앉았더라"},{"n":62,"t":"그 이튿날은 예비일 다음 날이라 대제사장들과 바리새인들이 함께 빌라도에게 모여 가로되"},{"n":63,"t":"주여 저 유혹하던 자가 살았을 때에 말하되 내가 사흘 후에 다시 살아나리라 한 것을 우리가 기억하노니"},{"n":64,"t":"그러므로 분부하여 그 무덤을 사흘까지 굳게 지키게 하소서 그의 제자들이 와서 시체를 도적질하여 가고 백성에게 말하되 그가 죽은 자 가운데서 살아났다 하면 후의 유혹이 전보다 더 될까 하나이다 하니"},{"n":65,"t":"빌라도가 가로되 너희에게 파숫군이 있으니 가서 힘대로 굳게 하라 하거늘"},{"n":66,"t":"저희가 파숫군과 함께 가서 돌을 인봉하고 무덤을 굳게 하니라"}],"kids":[{"n":1,"t":"아침이 되자 모든 대제사장과 백성의 장로들이 예수님을 죽이려고 의논했어요."},{"n":2,"t":"그들이 예수님을 묶어 끌고 가서 총독 빌라도에게 넘겼어요."},{"n":3,"t":"그때 예수님을 넘긴 유다가 예수님이 사형 선고를 받은 것을 보고 후회하며 그 은 삼십 닢을 대제사장과 장로들에게 돌려주며,"},{"n":4,"t":"\\"내가 죄 없는 피를 넘겨 죄를 지었어\\" 하고 말했어요. 그들이 \\"그게 우리와 무슨 상관이야? 네가 알아서 해\\" 하고 답했어요."},{"n":5,"t":"유다가 그 돈을 성전에 던지고 나가서 목매어 죽었어요."},{"n":6,"t":"대제사장들이 그 돈을 가지고 \\"이것은 핏값이라 성전 금고에 넣는 게 옳지 않다\\" 하고 말했어요."},{"n":7,"t":"의논 끝에 그 돈으로 토기장이의 밭을 사 나그네의 묘지로 삼았어요."},{"n":8,"t":"그래서 그 밭이 오늘날까지 \'피의 밭\'이라 불려요."},{"n":9,"t":"그때 예언자 예레미야가 말한 것이 이루어졌어요. \\"그들이 은 삼십 닢, 곧 그분의 값을 지정한 사람의 값을 가지고,\\""},{"n":10,"t":"\\"토기장이의 밭값으로 주었으니 이는 주께서 내게 명하신 대로다.\\""},{"n":11,"t":"예수님이 총독 앞에 서셨어요. 총독이 \\"네가 유대인의 왕이니?\\" 하고 물으니, 예수님이 \\"네 말과 같다\\" 하셨어요."},{"n":12,"t":"대제사장과 장로들이 예수님을 고소할 때 아무 대답도 하지 않으셨어요."},{"n":13,"t":"빌라도가 \\"그들이 너에게 얼마나 많은 일을 증언하는지 듣지 못하니?\\" 하고 물었어요."},{"n":14,"t":"예수님이 한 말도 답하지 않으시니 총독이 매우 이상하게 여겼어요."},{"n":15,"t":"명절에는 총독이 무리의 청에 따라 죄수 한 사람을 풀어 주는 관례가 있었어요."},{"n":16,"t":"그때 바라바라 하는 유명한 죄수가 있었어요."},{"n":17,"t":"그들이 모였을 때 빌라도가 \\"너희에게 누구를 풀어 주기를 원하니? 바라바냐, 그리스도라 하는 예수냐?\\" 하고 물었어요."},{"n":18,"t":"그들이 예수님을 넘긴 것은 시기 때문인 줄 알았기 때문이에요."},{"n":19,"t":"빌라도가 재판석에 앉아 있을 때 그의 아내가 사람을 보내 \\"저 의로운 사람과 아무 상관도 마세요. 오늘 꿈에 그 때문에 많이 괴로워했어요\\" 하고 알렸어요."},{"n":20,"t":"대제사장과 장로들이 무리를 부추겨 바라바를 풀어 주고 예수님을 죽이라고 청하게 했어요."},{"n":21,"t":"총독이 \\"두 사람 중 누구를 풀어 줄까?\\" 하니 그들이 \\"바라바요\\" 하고 답했어요."},{"n":22,"t":"빌라도가 \\"그러면 그리스도라 하는 예수는 어떻게 할까?\\" 하니 다 \\"십자가에 못 박으세요\\" 하고 답했어요."},{"n":23,"t":"그가 \\"왜? 그가 무슨 악을 행했니?\\" 하니 그들이 더 크게 \\"십자가에 못 박으세요!\\" 하고 외쳤어요."},{"n":24,"t":"빌라도가 아무 소용 없고 도리어 소요가 일어나는 것을 보고 물을 가져다가 무리 앞에서 손을 씻으며 \\"이 의로운 사람의 피에 나는 무죄해. 너희가 책임져라\\" 하고 말했어요."},{"n":25,"t":"온 백성이 \\"그의 피가 우리와 우리 자손에게 돌아가게 하세요\\" 하고 대답했어요."},{"n":26,"t":"이에 바라바는 풀어 주고 예수님을 채찍질한 후 십자가에 못 박도록 넘겼어요."},{"n":27,"t":"총독의 군병들이 예수님을 관저로 데리고 가서 그 둘레에 군대를 다 모으고,"},{"n":28,"t":"그분의 옷을 벗기고 자주색 옷을 입혔어요."},{"n":29,"t":"그들이 가시관을 엮어 그분의 머리에 씌우고 오른손에 갈대를 들리고 그 앞에 무릎 꿇어 \\"유대인의 왕이여, 만세!\\" 하며 조롱했어요."},{"n":30,"t":"또 예수님께 침 뱉고 갈대를 빼앗아 그분의 머리를 쳤어요."},{"n":31,"t":"조롱을 마치고 자주색 옷을 벗기고 다시 그분의 옷을 입혀 십자가에 못 박으러 끌고 갔어요."},{"n":32,"t":"나가다가 시몬이라는 구레네 사람을 만나 강제로 예수님의 십자가를 지게 했어요."},{"n":33,"t":"\'해골의 곳\'이라는 골고다에 이르러,"},{"n":34,"t":"쓸개 탄 포도주를 예수님께 드렸으나 예수님이 맛만 보시고 마시려 하지 않으셨어요."},{"n":35,"t":"그들이 예수님을 십자가에 못 박은 후 제비를 뽑아 그분의 옷을 나누고,"},{"n":36,"t":"거기 앉아 그분을 지켰어요."},{"n":37,"t":"머리 위에 그분의 죄목을 써 붙였는데 \'이는 유대인의 왕 예수다\'였어요."},{"n":38,"t":"그때 예수님과 함께 두 강도도 십자가에 못 박혔어요. 하나는 오른쪽에, 하나는 왼쪽에요."},{"n":39,"t":"지나가는 사람들이 머리를 흔들며 예수님을 모욕했어요."},{"n":40,"t":"\\"성전을 무너뜨리고 사흘에 짓는 사람아, 자기를 구원해 봐. 하나님의 아들이거든 십자가에서 내려와 봐.\\""},{"n":41,"t":"대제사장들도 율법 학자와 장로들과 함께 마찬가지로 조롱하며,"},{"n":42,"t":"\\"다른 사람은 구원했는데 자기는 구원하지 못해. 이스라엘의 왕이라면 지금 십자가에서 내려와라. 그러면 우리가 그를 믿을 거야.\\""},{"n":43,"t":"\\"그가 하나님을 의지했으니 자기를 사랑하시면 지금 구해 주시라지. \'나는 하나님의 아들이다\'라고 했잖아\\" 하고 말했어요."},{"n":44,"t":"함께 못 박힌 강도들도 그렇게 욕했어요."},{"n":45,"t":"낮 열두 시부터 오후 세 시까지 온 땅에 어둠이 덮였어요."},{"n":46,"t":"세 시쯤 예수님이 큰 소리로 \\"엘리 엘리 라마 사박다니!\\" 하고 외치셨어요. 이는 \\"내 하나님, 내 하나님, 어찌하여 나를 버리셨나요?\\"라는 뜻이에요."},{"n":47,"t":"거기 서 있던 사람 중 어떤 사람이 듣고 \\"이 사람이 엘리야를 부르네\\" 하고 말했어요."},{"n":48,"t":"그중 한 사람이 곧 달려가 해면을 가져다 신 포도주에 적셔 갈대에 매서 예수님께 마시게 했어요."},{"n":49,"t":"다른 사람들은 \\"가만 둬. 엘리야가 와서 그를 구해 주는지 보자\\" 하고 말했어요."},{"n":50,"t":"예수님이 다시 큰 소리로 외치시고 영혼이 떠나갔어요."},{"n":51,"t":"그때 성전 휘장이 위에서 아래까지 두 갈래로 찢어지고 땅이 흔들리고 바위가 갈라지고,"},{"n":52,"t":"무덤들이 열리고 잠자던 많은 성도의 몸이 일어났어요."},{"n":53,"t":"예수님이 살아나신 후에 그들이 무덤에서 나와 거룩한 성에 들어가 많은 사람에게 보였어요."},{"n":54,"t":"백부장과 예수님을 지키던 사람들이 지진과 일어난 일들을 보고 매우 두려워하며 \\"이분은 진실로 하나님의 아들이셨다\\" 하고 말했어요."},{"n":55,"t":"또 거기에 많은 여자들이 멀리서 보고 있었는데, 갈릴리부터 예수님을 따라다니며 섬기던 사람들이에요."},{"n":56,"t":"그중에 막달라 마리아와 야고보와 요셉의 어머니 마리아와 세베대의 아들들의 어머니가 있었어요."},{"n":57,"t":"저녁이 되자 아리마대에서 온 부자 요셉이라는 사람이 왔어요. 그도 예수님의 제자였어요."},{"n":58,"t":"이 사람이 빌라도에게 가서 예수님의 시신을 달라고 청하니, 빌라도가 내주라고 명령했어요."},{"n":59,"t":"요셉이 시신을 가져다 깨끗한 세마포로 싸서,"},{"n":60,"t":"바위에 판 자기 새 무덤에 넣고 큰 돌을 굴려 무덤 입구에 놓고 갔어요."},{"n":61,"t":"막달라 마리아와 다른 마리아는 무덤 맞은편에 앉아 있었어요."},{"n":62,"t":"이튿날, 곧 예비일 다음 날에 대제사장과 바리새인들이 함께 빌라도에게 모여,"},{"n":63,"t":"\\"각하, 우리가 기억하니 저 미혹하던 사람이 살아 있을 때 「내가 사흘 후에 살아난다」고 했어요.\\""},{"n":64,"t":"\\"그러니 사흘째 되는 날까지 무덤을 단단히 지키게 명령해 주세요. 그의 제자들이 와서 시신을 훔치고 「죽은 자 가운데서 살아났다」고 백성에게 말할까 합니다. 그러면 나중 미혹이 처음보다 더 나쁠 거예요.\\""},{"n":65,"t":"빌라도가 \\"파수꾼이 있다. 너희가 가서 너희가 아는 대로 단단히 지켜라\\" 하고 말했어요."},{"n":66,"t":"그들이 가서 돌을 인 봉인하고 파수꾼과 함께 무덤을 단단히 지켰어요."}]}},{"chapter":28,"title":"부활하신 예수님","verses":{"krv":[{"n":1,"t":"안식일이 다하여가고 안식 후 첫날이 되려는 미명에 막달라 마리아와 다른 마리아가 무덤을 보려고 왔더니"},{"n":2,"t":"큰 지진이 나며 주의 천사가 하늘로서 내려와 돌을 굴려 내고 그위에 앉았는데"},{"n":3,"t":"그 형상이 번개 같고 그 옷은 눈 같이 희거늘"},{"n":4,"t":"수직하던 자들이 저를 무서워하여 떨며 죽은 사람과 같이 되었더라"},{"n":5,"t":"천사가 여자들에게 일러 가로되 너희는 무서워 말라 십자가에 못 박히신 예수를 너희가 찾는 줄을 내가 아노라"},{"n":6,"t":"그가 여기 계시지 않고 그의 말씀하시던대로 살아나셨느니라 와서 그의 누우셨던 곳을 보라"},{"n":7,"t":"또 빨리 가서 그의 제자들에게 이르되 그가 죽은 자 가운데서 살아나셨고 너희보다 먼저 갈릴리로 가시나니 거기서 너희가 뵈오리라 하라 보라 내가 너희에게 일렀느니라 하거늘"},{"n":8,"t":"그 여자들이 무서움과 큰 기쁨으로 무덤을 빨리 떠나 제자들에게 알게 하려고 달음질할쌔"},{"n":9,"t":"예수께서 저희를 만나 가라사대 평안하뇨 하시거늘 여자들이 나아가 그 발을 붙잡고 경배하니"},{"n":10,"t":"이에 예수께서 가라사대 무서워 말라 가서 내 형제들에게 갈릴리로 가라 하라 거기서 나를 보리라 하시니라"},{"n":11,"t":"여자들이 갈제 파숫군 중 몇이 성에 들어가 모든 된 일을 대제사장들에게 고하니"},{"n":12,"t":"그들이 장로들과 함께 모여 의논하고 군병들에게 돈을 많이 주며"},{"n":13,"t":"가로되 너희는 말하기를 그의 제자들이 밤에 와서 우리가 잘 때에 그를 도적질하여 갔다 하라"},{"n":14,"t":"만일 이 말이 총독에게 들리면 우리가 권하여 너희로 근심되지 않게 하리라 하니"},{"n":15,"t":"군병들이 돈을 받고 가르친대로 하였으니 이 말이 오늘날까지 유대인 가운데 두루 퍼지니라"},{"n":16,"t":"열 한 제자가 갈릴리에 가서 예수의 명하시던 산에 이르러"},{"n":17,"t":"예수를 뵈옵고 경배하나 오히려 의심하는 자도 있더라"},{"n":18,"t":"예수께서 나아와 일러 가라사대 하늘과 땅의 모든 권세를 내게 주셨으니"},{"n":19,"t":"그러므로 너희는 가서 모든 족속으로 제자를 삼아 아버지와 아들과 성령의 이름으로 세례를 주고"},{"n":20,"t":"내가 너희에게 분부한 모든 것을 가르쳐 지키게 하라 볼찌어다 내가 세상 끝날까지 너희와 항상 함께 있으리라 하시니라"}],"kids":[{"n":1,"t":"안식일이 다 지나고 주의 첫날이 새벽이 될 때, 막달라 마리아와 다른 마리아가 무덤을 보러 갔어요."},{"n":2,"t":"갑자기 큰 지진이 났어요. 주의 천사가 하늘에서 내려와 돌을 굴려 놓고 그 위에 앉았어요."},{"n":3,"t":"그의 모습은 번개 같고 옷은 눈처럼 희었어요."},{"n":4,"t":"파수꾼들이 두려워서 떨다가 죽은 사람처럼 됐어요."},{"n":5,"t":"천사가 여자들에게 말했어요. \\"두려워하지 마. 너희가 십자가에 못 박히신 예수를 찾는 줄 안다.\\""},{"n":6,"t":"\\"여기 계시지 않아. 그분이 말씀하신 대로 살아나셨다. 와서 그분이 누우셨던 곳을 봐라.\\""},{"n":7,"t":"\\"빨리 가서 그분의 제자들에게 \'그분이 죽은 자 가운데서 살아나셨다. 보라, 너희보다 먼저 갈릴리로 가시니 거기서 그분을 볼 거다\'라고 알려라. 보라, 내가 너희에게 말했다.\\""},{"n":8,"t":"여자들이 두려움과 큰 기쁨으로 빨리 무덤을 떠나 제자들에게 알리려고 달려갔어요."},{"n":9,"t":"그때 예수님이 그들을 만나 \\"안녕!\\" 하고 인사하셨어요. 그들이 가까이 와서 그분의 발을 잡고 절했어요."},{"n":10,"t":"예수님이 \\"두려워하지 마. 가서 내 형제들에게 갈릴리로 가라고 말해라. 거기서 나를 볼 거야\\" 하셨어요."},{"n":11,"t":"그들이 가는 동안 파수꾼 몇이 도시에 들어가 모든 일을 대제사장들에게 알렸어요."},{"n":12,"t":"그들이 장로들과 함께 모여 의논한 후 군병들에게 많은 돈을 주며,"},{"n":13,"t":"\\"너희가 \'밤에 우리가 자는 동안 그의 제자들이 와서 시신을 훔쳐 갔다\' 하고 말해라.\\""},{"n":14,"t":"\\"이 말이 총독의 귀에 들어가면 우리가 권하여 너희에게 근심이 없게 해 줄게\\" 하고 말했어요."},{"n":15,"t":"군병들이 돈을 받고 시키는 대로 했어요. 이 말이 오늘날까지 유대인들 사이에 퍼져 있어요."},{"n":16,"t":"열한 제자가 갈릴리로 가서 예수님이 정해 주신 산에 이르러,"},{"n":17,"t":"예수님을 보고 절했지만, 어떤 사람들은 의심했어요."},{"n":18,"t":"예수님이 다가오셔서 말씀하셨어요. \\"하늘과 땅의 모든 권세를 내게 주셨어.\\""},{"n":19,"t":"\\"그러므로 너희는 가서 모든 민족을 제자로 삼아 아버지와 아들과 성령의 이름으로 세례를 베풀고,\\""},{"n":20,"t":"\\"내가 너희에게 명령한 모든 것을 가르쳐 지키게 해라. 보라, 내가 세상 끝날까지 너희와 항상 함께 있을 거야.\\""}]}}]}');

